function initials(name) {
  if (!name) return "?";
  const parts = name.trim().split(/\s+/);
  const first = parts[0]?.[0] ?? "";
  const last = parts.length > 1 ? parts[parts.length - 1][0] : "";
  return (first + last).toUpperCase();
}

// Deterministic dummy face from a seed (name/id). Uses randomuser.me color
// portraits (men/women 0-99). Pass gender "men"/"women" to force it.
function faceUrl(seed, gender) {
  const s = String(seed == null ? "" : seed);
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0;
  const g = gender === "men" || gender === "women" ? gender : (h % 2 === 0 ? "women" : "men");
  const idx = Math.floor(h / 2) % 100;
  return `https://randomuser.me/api/portraits/${g}/${idx}.jpg`;
}

// Per-name face overrides — real photos (drop files in public/avatars/) and/or
// a forced gender. Applies anywhere a person with this name is shown. Missing
// image files fall back gracefully to the person's initials.
const FACE_OVERRIDES = {
  "Amira Hassan": { src: "/avatars/amira-hassan.jpg", gender: "women" },
  "Sarah Chen": { src: "/avatars/sarah-chen.jpg", gender: "women" },
  "Nurul Aisyah": { src: "/avatars/nurul-aisyah.jpg", gender: "women" },
  "Tan Wei Ming": { src: "/avatars/tan-wei-ming.jpg", gender: "men" },
  "Siti Rahman": { gender: "women" },
  "Priya Nair": { gender: "women" },
  "Daniel Teoh": { gender: "men" },
  "Tom Beckett": { gender: "men" },
  "Nurdiana Rashid": { gender: "women" },
  "Kevin Tan": { gender: "men" },
  "Aisyah Zainal": { gender: "women" },
  "Priya Kumar": { gender: "women" },
  "Daniel Lee": { gender: "men" },
  "Faridah Omar": { gender: "women" },
  "Marcus Wong": { gender: "men" },
  "Hannah Lim": { gender: "women" },
  "Siti Aminah": { gender: "women" },
  "Joel D'Cruz": { gender: "men" },
  "Wong Mei Ling": { gender: "women" },
  "Amir Hakim": { gender: "men" },
};

// A person photo with graceful fallback to initials-in-a-circle if the
// image can't load (offline / blocked). Seed is the name unless overridden.
function FaceAvatar({ src, name, seed, gender, size = 40, className = "", style = {}, fontScale = 0.36, fallbackBg = "var(--brand-soft)", fallbackColor = "var(--brand)" }) {
  const [failed, setFailed] = useState(false);
  const ov = name ? FACE_OVERRIDES[name] : null;
  const photo = src || (ov && ov.src) || null;
  const g = gender || (ov && ov.gender) || undefined;
  const key = seed != null ? seed : name;
  if (failed || (!photo && (key == null || key === ""))) {
    return (
      <div
        className={`rounded-full flex items-center justify-center font-semibold font-display shrink-0 ${className}`}
        style={{ width: size, height: size, background: fallbackBg, color: fallbackColor, fontSize: size * fontScale, ...style }}
      >
        {initials(name)}
      </div>
    );
  }
  return (
    <img
      src={photo || faceUrl(key, g)}
      alt={name || "Profile"}
      loading="lazy"
      onError={() => setFailed(true)}
      className={`rounded-full object-cover shrink-0 ${className}`}
      style={{ width: size, height: size, ...style }}
    />
  );
}

// Candidate avatars use the real photo extracted from the resume when we have
// one, and fall back to the person's initials — never a generated stock face.
function CandidateAvatar({ name, hasPhoto, src = null, size = 40, showPhotoDot = true }) {
  const [failed, setFailed] = useState(false);
  if (src && !failed) {
    return (
      <img
        src={src}
        alt={name || "Applicant"}
        loading="lazy"
        onError={() => setFailed(true)}
        className="rounded-full object-cover shrink-0"
        style={{ width: size, height: size, border: "1px solid var(--line)" }}
      />
    );
  }
  return (
    <div
      className="rounded-full flex items-center justify-center font-semibold font-display shrink-0"
      style={{ width: size, height: size, background: "var(--brand-soft)", color: "var(--brand)", fontSize: size * 0.36, border: "1px solid var(--line)" }}
    >
      {initials(name)}
    </div>
  );
}

// Shared activity feed used by both the header bell and the dashboard card.
// `target` describes where a click should navigate.
// Activity feed derived from the app's own data (applicants, matches, jobs),
// so names and roles always match what's really in the workspace. The two
// newest items start unread; opening the bell marks everything read.
function buildActivities() {
  const cand = (id) => MOCK_CANDIDATES.find((c) => c.id === id)?.parsed?.name || "A candidate";
  const jobTitle = (id) => MOCK_JOBS.find((j) => j.id === id)?.title || "a role";
  const ini = (name) => name.split(" ").filter(Boolean).map((w) => w[0]).slice(0, 2).join("").toUpperCase();

  const apps = Object.entries(APPLICANTS_BY_JOB).flatMap(([jobId, arr]) => arr.map((a) => ({ ...a, jobId })));
  const list = [];

  // Newest application
  if (apps[0]) {
    const n = cand(apps[0].candidateId);
    list.push({ icon: "doc", accent: "#5A78F8", title: "New application received", desc: `${n} applied for ${jobTitle(apps[0].jobId)}`, time: apps[0].appliedAt, dotColor: "bg-neutral-800", target: { screen: "candidates", filter: { source: "public_application" } } });
  }
  // An applicant currently in the interview stage
  const interviewing = apps.find((a) => a.baseStage === "interviewing");
  if (interviewing) {
    const n = cand(interviewing.candidateId);
    list.push({ icon: "calendar", accent: "#16A34A", title: "Interview scheduled", desc: `${n} · ${jobTitle(interviewing.jobId)}`, time: "1h ago", dotColor: "bg-emerald-500", target: { screen: "candidates", filter: { interview: true } } });
  }
  // Top AI match
  const [matchJobId, matches] = Object.entries(MOCK_MATCHES)[0] || [];
  if (matches && matches[0]) {
    const n = cand(matches[0].candidateId);
    list.push({ icon: "matching", accent: "#973BF7", title: "New match generated", desc: `${n} · ${jobTitle(matchJobId)} (${Math.round(matches[0].score * 100)}%)`, time: "3h ago", dotColor: "bg-neutral-800", target: { screen: "jobs", jobStatus: null } });
  }
  // A recently published open role (pick one not already surfaced above)
  const openJobs = MOCK_JOBS.filter((j) => j.status === "open");
  const publishedJob = openJobs[openJobs.length - 1] || openJobs[0];
  if (publishedJob) {
    list.push({ icon: "briefcase", accent: "#F59E0B", title: "Position published", desc: publishedJob.title, time: "5h ago", dotColor: "bg-neutral-300", target: { screen: "jobs", jobStatus: "open" } });
  }

  return list.map((it, i) => ({ id: `a${i + 1}`, read: i >= 2, ...it }));
}

