// --- Taxonomy resolution (aliases + fuzzy) --------------------------------
// No fixed list ever covers every skill/industry, so we normalise free input
// against the stored taxonomy in three layers: 1) an alias table for synonyms
// and shorthand, 2) exact (case-insensitive) match, 3) edit-distance fuzzy for
// typos. In production this deterministic resolver is where you'd plug an
// embedding/LLM service that maps free text to the nearest canonical entry with
// a confidence score (and routes low-confidence entries to a review queue).
const norm = (s) => (s || "").trim().toLowerCase().replace(/\s+/g, " ");

// Common shorthand and synonyms -> canonical value in the taxonomy.
const SKILL_ALIASES = {
  js: "JavaScript", ecmascript: "JavaScript", ts: "TypeScript", "react.js": "React", reactjs: "React",
  "next.js": "Next.js", nextjs: "Next.js", "vue.js": "Vue", vuejs: "Vue", "node.js": "Node.js", nodejs: "Node.js", node: "Node.js",
  py: "Python", golang: "Go", csharp: "C#", "c sharp": "C#", cpp: "C++", "c plus plus": "C++", dotnet: ".NET", "dot net": ".NET",
  k8s: "Kubernetes", gcp: "Google Cloud", "google cloud platform": "Google Cloud", postgres: "PostgreSQL", postgre: "PostgreSQL",
  mongo: "MongoDB", "rest api": "REST APIs", "rest apis": "REST APIs", rest: "REST APIs", gql: "GraphQL", "ci/cd": "CI/CD", cicd: "CI/CD",
  ml: "Machine Learning", "ml engineering": "Machine Learning", dl: "Deep Learning", nlp: "Natural Language Processing",
  tf: "TensorFlow", "power bi": "Power BI", powerbi: "Power BI",
  ux: "UX Design", "ux design": "UX Design", ui: "UI Design", "user experience": "UX Research", "user interface": "UI Design",
  pm: "Product Management", "product owner": "Product Management", "product mgmt": "Product Management", gtm: "Go-to-Market",
  smm: "Social Media Marketing", "social media mgmt": "Social Media Marketing", ga: "Google Analytics", "google analytics 4": "Google Analytics",
  sfdc: "Salesforce", "salesforce.com": "Salesforce", bd: "Business Development", "biz dev": "Business Development",
  "fp&a": "FP&A", fpa: "FP&A", "ms excel": "Excel", "microsoft excel": "Excel", spreadsheets: "Excel",
  "l&d": "Learning & Development", "comp & ben": "Compensation & Benefits", "comp and ben": "Compensation & Benefits",
  "project mgmt": "Project Management", pmp: "Project Management", qa: "Quality Assurance", "quality assurance": "Quality Assurance",
  rn: "Nursing", "registered nurse": "Nursing", ehr: "EMR", "electronic medical records": "EMR", cpr: "CPR",
  "ip law": "Intellectual Property", comms: "Communication", "leadership skills": "Leadership",
};
// Loose industry terms funnel toward the industries actually present in the data
// so a match still returns candidates.
const INDUSTRY_ALIASES = {
  fintech: "Finance & Fintech", finance: "Finance & Fintech", financial: "Finance & Fintech", "financial services": "Finance & Fintech",
  banking: "Finance & Fintech", bank: "Finance & Fintech", tech: "Technology", software: "Technology", it: "Technology",
  "information technology": "Technology", saas: "Technology", startup: "Technology",
  ecommerce: "E-commerce & Retail", "e commerce": "E-commerce & Retail", "e-commerce": "E-commerce & Retail", retail: "E-commerce & Retail", shopping: "E-commerce & Retail",
  medical: "Healthcare", hospital: "Healthcare", clinical: "Healthcare", health: "Healthcare", healthcare: "Healthcare", pharma: "Healthcare",
  media: "Media & Creative", creative: "Media & Creative", advertising: "Media & Creative", "ad agency": "Media & Creative", marketing: "Media & Creative",
  logistics: "Logistics & Operations", "supply chain": "Logistics & Operations", operations: "Logistics & Operations", shipping: "Logistics & Operations",
  travel: "Travel & Aviation", aviation: "Travel & Aviation", airline: "Travel & Aviation", airlines: "Travel & Aviation",
  consulting: "Professional Services", "professional services": "Professional Services", advisory: "Professional Services", audit: "Professional Services",
};

function levenshtein(a, b) {
  const m = a.length, n = b.length;
  if (!m) return n; if (!n) return m;
  let prev = Array.from({ length: n + 1 }, (_, i) => i);
  for (let i = 1; i <= m; i++) {
    const cur = [i];
    for (let j = 1; j <= n; j++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      cur[j] = Math.min(prev[j] + 1, cur[j - 1] + 1, prev[j - 1] + cost);
    }
    prev = cur;
  }
  return prev[n];
}
// Typo tolerance scales with word length: shorter words allow fewer edits.
const fuzzyThreshold = (len) => (len <= 4 ? 1 : len <= 7 ? 2 : 3);
// Resolve free input to a canonical taxonomy value: alias -> exact -> fuzzy.
// Returns { value, how: 'alias'|'exact'|'fuzzy'|null }.
function resolveToken(input, options, aliases) {
  const q = norm(input);
  if (!q) return { value: null, how: null };
  if (aliases && aliases[q]) return { value: aliases[q], how: "alias" };
  const exact = options.find((o) => o.toLowerCase() === q);
  if (exact) return { value: exact, how: "exact" };
  let best = null, bd = Infinity;
  for (const o of options) {
    const d = levenshtein(q, o.toLowerCase());
    if (d < bd) { bd = d; best = o; }
  }
  if (best && bd <= fuzzyThreshold(q.length)) return { value: best, how: "fuzzy" };
  return { value: null, how: null };
}

// --- Shared capture normaliser --------------------------------------------
// The single contract that keeps search accurate: the same resolver runs on both
// sides of a match. Whatever the AI extracts at ingestion (Bulk Upload or a
// candidate applying) is snapped to the canonical taxonomy before it's stored,
// and the search query is snapped the same way, so a resume that says "JS", "k8s"
// or "fintech" still lines up with a search for "JavaScript", "Kubernetes" or
// "Finance & Fintech". Memoised so repeated values resolve once.
const _skillCanon = new Map();
function canonicalizeSkill(raw) {
  const key = norm(raw);
  if (!key) return (raw || "").trim();
  if (_skillCanon.has(key)) return _skillCanon.get(key);
  const { value } = resolveToken(raw, ALL_SKILLS, SKILL_ALIASES);
  const out = value || raw.trim();
  _skillCanon.set(key, out);
  return out;
}
function canonicalizeSkills(list) {
  const seen = new Set(), out = [];
  (list || []).forEach((s) => { const c = canonicalizeSkill(s); const k = c.toLowerCase(); if (c && !seen.has(k)) { seen.add(k); out.push(c); } });
  return out;
}
function canonicalizeIndustry(raw) {
  const { value } = resolveToken(raw, ALL_INDUSTRIES, INDUSTRY_ALIASES);
  return value || (raw || "").trim();
}

// A black info icon; hovering (or focusing) it reveals the given text as a
// tooltip. Reused next to field labels and panel titles.
function InfoHint({ hint, align = "left", dir = "up", tone = "dark" }) {
  const down = dir === "down";
  const pos = `${align === "right" ? "right-0" : "left-0"} ${down ? "top-full mt-2" : "bottom-full mb-2"}`;
  const enter = down
    ? "-translate-y-1 group-hover:translate-y-0 group-focus:translate-y-0"
    : "translate-y-1 group-hover:translate-y-0 group-focus:translate-y-0";
  return (
    <span tabIndex={0} className="relative group inline-flex items-center align-middle outline-none" style={{ color: tone === "light" ? "rgba(255,255,255,0.72)" : "var(--ink)" }}>
      <Icon name="info" className="w-3.5 h-3.5 cursor-help" />
      <span className={`pointer-events-none absolute ${pos} w-60 rounded-lg px-3 py-2 text-[11px] font-normal normal-case tracking-normal leading-snug opacity-0 ${enter} group-hover:opacity-100 group-focus:opacity-100 transition-all duration-150 z-30`}
        style={{ background: "var(--ink)", color: "#fff", border: "1px solid rgba(255,255,255,0.12)", boxShadow: "0 12px 30px -10px rgba(18,19,42,0.5)" }}>{hint}</span>
    </span>
  );
}

// A field label with a black info icon; hovering (or focusing) the icon reveals
// the usage instruction as a tooltip.
function FieldLabel({ children, hint }) {
  return (
    <div className="flex items-center gap-1.5 mb-1.5">
      <span className="text-[11px] font-semibold uppercase tracking-wide" style={{ color: "var(--ink-2)", letterSpacing: "0.05em" }}>{children}</span>
      <InfoHint hint={hint} />
    </div>
  );
}

// One standardized plan-usage meter, shared across every screen (AI match runs,
// resume parsing, AI insights) so they all look and behave identically.
function UsageMeter({ title, hint, hintAlign = "right", used, limit, unit = "used", note, danger, onManage, onUpgrade, upgradeLabel = "Upgrade for unlimited" }) {
  const out = limit !== Infinity && used >= limit;
  const pct = limit === Infinity ? 4 : Math.max(Math.min((used / limit) * 100, 100), 4);
  const isDanger = danger ?? out;
  return (
    <div className="rounded-2xl bg-white border p-5" style={{ borderColor: "var(--line)" }}>
      <div className="flex items-center justify-between mb-2.5">
        <div className="flex items-center gap-1.5">
          <h3 className="text-[11px] font-semibold uppercase tracking-wide" style={{ color: "var(--ink-2)", letterSpacing: "0.06em" }}>{title}</h3>
          {hint && <InfoHint dir="down" align={hintAlign} hint={hint} />}
        </div>
        {onManage && <button onClick={onManage} className="text-xs font-medium hover:opacity-70 transition-opacity" style={{ color: "var(--brand)" }}>Manage</button>}
      </div>
      <div className="flex items-baseline gap-1.5 mb-2.5">
        <span className="text-2xl font-bold font-display tnum leading-none" style={{ color: out ? "#DC2626" : "var(--ink)" }}>{used}</span>
        <span className="text-sm" style={{ color: "var(--ink-3)" }}>/ {limit === Infinity ? "Unlimited" : limit} {unit}</span>
      </div>
      <div className="h-2.5 rounded-full overflow-hidden" style={{ background: "var(--line)" }}>
        <div className="h-full rounded-full transition-all" style={{ width: `${pct}%`, background: out ? "#EF4444" : "linear-gradient(90deg, var(--brand-0), var(--brand-2))" }} />
      </div>
      {note && <p className="text-xs mt-2.5 leading-relaxed" style={{ color: isDanger ? "#DC2626" : "var(--ink-3)" }}>{note}</p>}
      {onUpgrade && <button onClick={onUpgrade} className="mt-3.5 w-full rounded-xl brand-gradient hover:opacity-90 text-white text-sm font-semibold py-2.5 transition-opacity">{out ? "Upgrade plan" : upgradeLabel}</button>}
    </div>
  );
}

// A custom, on-brand dropdown for picking an open role. Replaces the native
// <select> so options can show role meta and match the app's styling.
function JobSelect({ jobs, value, onChange, disabled, placeholder }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);
  const selected = jobs.find((j) => j.id === value);
  useEffect(() => {
    if (!open) return;
    const onDoc = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    const onKey = (e) => { if (e.key === "Escape") setOpen(false); };
    document.addEventListener("mousedown", onDoc);
    document.addEventListener("keydown", onKey);
    return () => { document.removeEventListener("mousedown", onDoc); document.removeEventListener("keydown", onKey); };
  }, [open]);
  const cap = (s) => (s ? s.charAt(0).toUpperCase() + s.slice(1) : s);
  const metaOf = (j) => [j.department, j.location, cap(j.seniority_level)].filter(Boolean).join(" · ");
  return (
    <div ref={ref} className="relative flex-1">
      <button type="button" disabled={disabled} onClick={() => setOpen((o) => !o)} aria-haspopup="listbox" aria-expanded={open}
        className="w-full rounded-xl bg-white border px-3.5 py-2.5 text-sm flex items-center gap-2 focus:outline-none focus:ring-2 focus:ring-violet-200 transition-shadow disabled:opacity-60"
        style={{ borderColor: open ? "var(--brand)" : "var(--line)" }}>
        <span className="flex-1 text-left truncate" style={{ color: selected ? "var(--ink)" : "var(--ink-3)" }}>{selected ? selected.title : placeholder}</span>
        <span className="shrink-0 transition-transform" style={{ color: "var(--ink-3)", transform: open ? "rotate(180deg)" : "none" }}><Icon name="chevronDown" className="w-4 h-4" /></span>
      </button>
      {open && (
        <div role="listbox" className="absolute z-30 left-0 right-0 mt-1.5 rounded-xl bg-white border p-1 max-h-72 overflow-y-auto" style={{ borderColor: "var(--line)", boxShadow: "0 18px 40px -18px rgba(18,19,42,0.28)" }}>
          {jobs.length === 0 ? (
            <div className="px-3 py-6 text-center text-sm" style={{ color: "var(--ink-3)" }}>No open positions yet.</div>
          ) : jobs.map((j) => {
            const sel = j.id === value;
            return (
              <button key={j.id} type="button" role="option" aria-selected={sel} onClick={() => { onChange(j.id); setOpen(false); }}
                className="w-full text-left rounded-lg px-2.5 py-2 flex items-center gap-2.5 transition-colors hover:bg-neutral-50"
                style={sel ? { background: "var(--brand-soft)" } : undefined}>
                <span className="w-8 h-8 rounded-lg flex items-center justify-center shrink-0" style={sel ? { background: "linear-gradient(135deg, var(--brand-0), var(--brand-2))", color: "#fff" } : { background: "var(--brand-soft)", color: "var(--brand)" }}><Icon name="briefcase" className="w-4 h-4" /></span>
                <span className="min-w-0 flex-1">
                  <span className="block text-sm font-medium truncate" style={{ color: "var(--ink)" }}>{j.title}</span>
                  {metaOf(j) && <span className="block text-[11px] truncate mt-0.5" style={{ color: "var(--ink-3)" }}>{metaOf(j)}</span>}
                </span>
                {sel && <span className="shrink-0" style={{ color: "var(--brand)" }}><Icon name="check" className="w-4 h-4" /></span>}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

// A tag field with type-ahead suggestions from a stored list. Free-solo lets the
// user add a value that isn't in the list (skills); restricted mode limits input
// to known values (industry). Aliases + fuzzy matching mean synonyms and typos
// still resolve to the right canonical entry. Used by the "Skills & industry" tab.
function TokenAutocomplete({ tags, setTags, options, placeholder, onChange, freeSolo = true, aliases = null }) {
  const [input, setInput] = useState("");
  const [open, setOpen] = useState(false);
  const [hint, setHint] = useState("");
  const q = norm(input);
  const suggestions = (() => {
    if (!q) return [];
    const taken = new Set(tags.map((t) => t.toLowerCase()));
    const starts = [], contains = [], fuzzy = [];
    for (const o of options) {
      const lo = o.toLowerCase();
      if (taken.has(lo)) continue;
      if (lo.startsWith(q)) starts.push(o);
      else if (lo.includes(q)) contains.push(o);
      else {
        const d = levenshtein(q, lo);
        if (d <= fuzzyThreshold(q.length)) fuzzy.push([o, d]);
      }
    }
    fuzzy.sort((a, b) => a[1] - b[1]);
    const aliasHit = aliases && aliases[q];
    const merged = [];
    if (aliasHit && !taken.has(aliasHit.toLowerCase())) merged.push(aliasHit);
    for (const o of [...starts, ...contains, ...fuzzy.map((f) => f[0])]) {
      if (!merged.some((m) => m.toLowerCase() === o.toLowerCase())) merged.push(o);
    }
    return merged.slice(0, 8);
  })();
  const add = (val) => {
    const raw = (val || "").trim();
    if (!raw) return;
    const { value: resolved } = resolveToken(raw, options, aliases);
    let value = resolved;
    if (!value) {
      if (!freeSolo) { setHint(`"${raw}" isn't in our list. Pick the closest match.`); return; }
      value = raw; // free-text custom skill
    }
    if (!tags.some((t) => t.toLowerCase() === value.toLowerCase())) { setTags([...tags, value]); onChange && onChange(); }
    setInput(""); setOpen(false); setHint("");
  };
  const isCustom = (tag) => !options.some((o) => o.toLowerCase() === tag.toLowerCase());
  return (
    <div className="relative">
      <div className="flex flex-wrap gap-1.5 rounded-xl bg-white border p-2 focus-within:ring-2 focus-within:ring-violet-200 transition-shadow" style={{ borderColor: "var(--line)" }}>
        {tags.map((tag) => {
          const custom = isCustom(tag);
          return (
            <span key={tag} title={custom ? "Custom skill — not in our library, so it may match fewer candidates" : undefined}
              className="inline-flex items-center gap-1 text-xs font-medium rounded-full pl-2.5 pr-1.5 py-1"
              style={custom ? { background: "#fff", color: "var(--ink-2)", border: "1px dashed var(--line-strong)" } : { background: "var(--brand-soft)", color: "var(--brand)" }}>
              {custom && <span className="text-[9px] font-semibold uppercase tracking-wide opacity-60">custom</span>}
              {tag}
              <button onClick={() => { setTags(tags.filter((x) => x !== tag)); onChange && onChange(); }} aria-label={`Remove ${tag}`} className="w-4 h-4 rounded-full flex items-center justify-center hover:bg-black/5"><Icon name="close" className="w-3 h-3" /></button>
            </span>
          );
        })}
        <input
          value={input}
          onChange={(e) => { setInput(e.target.value); setOpen(true); setHint(""); }}
          onFocus={() => setOpen(true)}
          onBlur={() => setTimeout(() => setOpen(false), 120)}
          onKeyDown={(e) => {
            if (e.key === "Enter" || e.key === ",") { e.preventDefault(); add(suggestions.length ? suggestions[0] : input); }
            else if (e.key === "Backspace" && !input && tags.length) { setTags(tags.slice(0, -1)); onChange && onChange(); }
            else if (e.key === "Escape") setOpen(false);
          }}
          placeholder={tags.length ? "" : placeholder}
          className="flex-1 min-w-[150px] bg-transparent px-1.5 py-1 text-sm focus:outline-none" style={{ color: "var(--ink)" }}
        />
      </div>
      {hint && <p className="text-[11px] mt-1.5 px-1" style={{ color: "#DC2626" }}>{hint}</p>}
      {open && suggestions.length > 0 && (
        <div className="absolute z-20 left-0 right-0 mt-1 rounded-xl bg-white border overflow-hidden max-h-56 overflow-y-auto" style={{ borderColor: "var(--line)", boxShadow: "0 18px 40px -18px rgba(18,19,42,0.28)" }}>
          {suggestions.map((s) => (
            <button key={s} onMouseDown={(e) => { e.preventDefault(); add(s); }} className="w-full text-left px-3 py-2 text-sm hover:bg-neutral-50 transition-colors flex items-center justify-between gap-2" style={{ color: "var(--ink)" }}>
              <span>{s}</span>
              {q && !s.toLowerCase().includes(q) && <span className="text-[10px] shrink-0" style={{ color: "var(--brand)" }}>did you mean?</span>}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

function SearchScreen({ navigate, candidates, jobs, onViewCandidate, onPreviewApply, plan = "free", matchRunsUsed = 0, setMatchRunsUsed, hiredIds = new Set(), profile, avatarUrl = null, activities = [], onOpenNotifications, persist }) {
  const limits = planLimits(plan);
  const runLimit = limits.aiRunsPerMonth;
  const runsLeft = Math.max(0, runLimit - matchRunsUsed);
  const outOfRuns = limits.aiRunsPerMonth !== Infinity && runsLeft <= 0;
  // Seed from the persisted view state so returning from a candidate profile
  // keeps the same tab, filters, page, results and scroll (no reset/refresh).
  const P = (persist && persist.current) || {};
  const [tab, setTab] = useState(P.tab ?? "browse"); // browse | skills | role

  // Browse tab
  const [query, setQuery] = useState(P.query ?? "");
  const [minYears, setMinYears] = useState(P.minYears ?? 0);
  const [sortBy, setSortBy] = useState(P.sortBy ?? "name"); // name | experience
  const [page, setPage] = useState(P.page ?? 1);
  const PER_PAGE = 20;

  // Match-by-skills-or-industry tab (two searchable token fields)
  const [skillTags, setSkillTags] = useState(P.skillTags ?? []);
  const [industryTags, setIndustryTags] = useState(P.industryTags ?? []);
  const [openTip, setOpenTip] = useState(null); // sidebar "how it works" accordion

  // Match-to-a-role tab
  const [matchJobId, setMatchJobId] = useState(P.matchJobId ?? "");

  // Shared ranking output (either skills or role match writes here)
  const [matching, setMatching] = useState(false);
  const [matchScores, setMatchScores] = useState(P.matchScores ?? null); // null | { [id]: 0..1 }
  const [rankedMeta, setRankedMeta] = useState(P.rankedMeta ?? null);    // { mode:'skills'|'role', label, skills?, jobId? }

  // Save the view state on every change so returning from a profile keeps the
  // same tab, filters, page and results (scroll is handled centrally by the app).
  useEffect(() => {
    if (persist) persist.current = { ...persist.current, tab, query, minYears, sortBy, page, skillTags, industryTags, matchJobId, matchScores, rankedMeta };
  }, [persist, tab, query, minYears, sortBy, page, skillTags, industryTags, matchJobId, matchScores, rankedMeta]);

  // Invites (role tab only)
  const [invited, setInvited] = useState({});
  const [inviteBanner, setInviteBanner] = useState(null);

  // Deduplicate by email — the same person can have more than one resume on file
  // (an old CV and a newer one). A real ATS shows them once, not twice.
  const seenEmails = new Set();
  const parsed = candidates.filter((c) => {
    if (!c.parsed) return false;
    const email = (c.parsed.email || "").trim().toLowerCase();
    if (email && seenEmails.has(email)) return false;
    if (email) seenEmails.add(email);
    return true;
  });
  // Everyone you can actually act on: unique people, not already hired.
  const available = parsed.filter((c) => !hiredIds.has(c.id));
  const availableCount = available.length;
  // Skill suggestions = the stored taxonomy + whatever's actually in the pool,
  // so every candidate skill is type-ahead-able and a picked one always matches.
  const skillSuggestions = [...new Set([...ALL_SKILLS, ...available.flatMap((c) => canonicalizeSkills(c.parsed.skills))])].sort((a, b) => a.localeCompare(b));
  const openJobs = (jobs || []).filter((j) => j.status === "open");
  const matchJob = jobs?.find((j) => j.id === matchJobId);
  const alreadyApplied = matchJobId
    ? new Set((APPLICANTS_BY_JOB[matchJobId] || []).map((a) => a.candidateId))
    : new Set();

  // Each tab is a clean, self-contained mode — switching clears any ranking.
  const switchTab = (t) => { if (t === tab) return; setTab(t); setMatchScores(null); setRankedMeta(null); setMatching(false); };
  const consumeRun = () => { if (limits.aiRunsPerMonth !== Infinity && setMatchRunsUsed) setMatchRunsUsed((n) => n + 1); };

  // ---- Scoring ----
  // Fit against an open role: skill/role keyword overlap with the posting.
  const scoreAgainstJob = (c, job) => {
    if (!job) return 0;
    const hay = `${job.title} ${job.requirements || ""} ${job.description || ""}`.toLowerCase();
    const skills = c.parsed.skills || [];
    const hits = skills.filter((s) => hay.includes(s.toLowerCase())).length;
    const roleHit = (c.parsed.experience || []).some((e) => hay.includes((e.title || "").toLowerCase().split(" ")[0]));
    return Math.min(1, (hits * 2 + (roleHit ? 2 : 0)) / Math.max(6, skills.length));
  };
  // Fit against a set of wanted skills: fraction of them the candidate has.
  // Both sides are canonicalised through the shared resolver so "JS" on a resume
  // matches a "JavaScript" search regardless of how the capture stored it.
  const scoreBySkills = (c, wanted) => {
    if (!wanted.length) return 0;
    const cand = new Set(canonicalizeSkills(c.parsed.skills).map((s) => s.toLowerCase()));
    return wanted.filter((w) => cand.has(canonicalizeSkill(w).toLowerCase())).length / wanted.length;
  };
  const matchedSkills = (c) => {
    const cand = new Set(canonicalizeSkills(c.parsed.skills).map((s) => s.toLowerCase()));
    return (rankedMeta?.skills || []).filter((w) => cand.has(canonicalizeSkill(w).toLowerCase()));
  };

  const runRoleMatch = () => {
    if (!matchJob) return;
    if (outOfRuns) { navigate("billing"); return; }
    setMatching(true);
    setTimeout(() => {
      const map = {}; parsed.forEach((c) => { map[c.id] = scoreAgainstJob(c, matchJob); });
      setMatchScores(map); setRankedMeta({ mode: "role", label: matchJob.title, jobId: matchJob.id });
      setMatching(false); consumeRun();
    }, 1200);
  };
  const runSkillMatch = () => {
    if (!skillTags.length && !industryTags.length) return; // need at least one criterion
    if (outOfRuns) { navigate("billing"); return; }
    setMatching(true);
    setTimeout(() => {
      const map = {};
      parsed.forEach((c) => {
        const inds = industriesOf(c);
        const indMatch = industryTags.length ? (industryTags.some((i) => inds.has(i)) ? 1 : 0) : 1;
        const skillS = skillTags.length ? scoreBySkills(c, skillTags) : 1;
        // Both set → must match an industry, ranked by skill fit. One set → that alone.
        map[c.id] = skillTags.length && industryTags.length ? skillS * indMatch : industryTags.length ? indMatch : skillS;
      });
      setMatchScores(map);
      setRankedMeta({ mode: "skills", skills: [...skillTags], industries: [...industryTags] });
      setMatching(false); consumeRun();
    }, 1000);
  };

  // Quick-add a skill chip — editing criteria invalidates any existing ranking.
  const addSkill = (raw) => {
    const v = (raw || "").trim();
    if (!v) return;
    setSkillTags((prev) => (prev.some((x) => x.toLowerCase() === v.toLowerCase()) ? prev : [...prev, v]));
    setMatchScores(null);
  };
  const addIndustry = (raw) => {
    const v = (raw || "").trim();
    if (!v) return;
    setIndustryTags((prev) => (prev.some((x) => x.toLowerCase() === v.toLowerCase()) ? prev : [...prev, v]));
    setMatchScores(null);
  };
  const invalidate = () => setMatchScores(null);

  // ---- Build the visible list for the active tab ----
  const q = query.trim().toLowerCase();
  let list = [];
  if (tab === "browse") {
    const terms = q.split(/[\s,]+/).filter((t) => t.length > 1);
    list = available.filter((c) => {
      if (minYears > 0 && (c.parsed.years_of_experience ?? 0) < minYears) return false;
      if (terms.length === 0) return true;
      const name = c.parsed.name.toLowerCase();
      const skills = c.parsed.skills.map((s) => s.toLowerCase());
      const roles = c.parsed.experience.map((e) => e.title.toLowerCase());
      return terms.some((t) => name.includes(t) || skills.some((s) => s.includes(t)) || roles.some((r) => r.includes(t)));
    }).sort((a, b) => (sortBy === "experience"
      ? (b.parsed.years_of_experience ?? 0) - (a.parsed.years_of_experience ?? 0)
      : a.parsed.name.localeCompare(b.parsed.name)));
  } else if (matchScores) {
    const pool = tab === "role" ? available.filter((c) => !alreadyApplied.has(c.id)) : available;
    list = [...pool];
    if (tab === "skills") list = list.filter((c) => (matchScores[c.id] ?? 0) > 0); // only real matches
    list.sort((a, b) => ((matchScores[b.id] ?? 0) - (matchScores[a.id] ?? 0)) || ((b.parsed.years_of_experience ?? 0) - (a.parsed.years_of_experience ?? 0)));
  }

  // Plan gating: show the top N, blur/lock the rest.
  const viewLimit = matchScores ? limits.aiMatches : limits.visibleCandidates;
  const shownList = list.slice(0, viewLimit);
  const lockedList = list.slice(viewLimit);

  // Browse pagination (20 per page). Match tabs are already top-N gated.
  const pageCount = Math.max(1, Math.ceil(shownList.length / PER_PAGE));
  const safePage = Math.min(Math.max(1, page), pageCount);
  const pageStart = (safePage - 1) * PER_PAGE;
  const browseItems = shownList.slice(pageStart, pageStart + PER_PAGE);
  const goToPage = (n) => { setPage(n); if (typeof window !== "undefined") window.scrollTo(0, 0); };

  // ---- Invites (role tab) ----
  const inviteLink = (jobId) => `https://yourapp.com/apply/${jobId}?source=database`;
  const sendInvite = async (candidateId) => {
    if (!matchJob) return;
    const url = inviteLink(matchJob.id);
    let ok = false;
    try { if (navigator.clipboard && window.isSecureContext) { await navigator.clipboard.writeText(url); ok = true; } } catch { ok = false; }
    if (!ok) {
      try {
        const ta = document.createElement("textarea");
        ta.value = url; ta.style.position = "fixed"; ta.style.opacity = "0";
        document.body.appendChild(ta); ta.focus(); ta.select();
        ok = document.execCommand("copy"); document.body.removeChild(ta);
      } catch { ok = false; }
    }
    setInvited((prev) => ({ ...prev, [candidateId]: true }));
    const c = parsed.find((x) => x.id === candidateId);
    setInviteBanner(`${ok ? "Invite link copied" : "Invite link ready"} for ${c?.parsed?.name ?? "candidate"} → ${matchJob.title} (source: database).`);
    setTimeout(() => setInviteBanner(null), 4000);
  };

  // ---- Shared render helpers ----
  const emptyState = (title, sub, icon = "search") => (
    <div className="rounded-2xl border bg-white py-12 px-6 text-center" style={{ borderColor: "var(--line)" }}>
      <div className="w-12 h-12 rounded-2xl mx-auto mb-3 flex items-center justify-center" style={{ background: "var(--brand-soft)", color: "var(--brand)" }}>
        <Icon name={icon} className="w-5 h-5" />
      </div>
      <p className="text-sm font-semibold" style={{ color: "var(--ink)" }}>{title}</p>
      {sub && <p className="text-xs mt-1 max-w-sm mx-auto leading-relaxed" style={{ color: "var(--ink-3)" }}>{sub}</p>}
    </div>
  );
  const browseCard = (c) => {
    const role = c.parsed.experience?.[0]?.title;
    return (
      <button key={c.id} onClick={() => onViewCandidate(c.id)} className="text-left rounded-2xl bg-white border p-4 flex items-start gap-3.5 group transition-all hover:-translate-y-0.5 shadow-[0_1px_2px_rgba(18,19,42,0.04)] hover:shadow-[0_14px_30px_-16px_rgba(18,19,42,0.22)]" style={{ borderColor: "var(--line)" }}>
        <CandidateAvatar name={c.parsed.name} hasPhoto={c.hasPhoto} src={c.avatarUrl} size={44} showPhotoDot={false} />
        <div className="min-w-0 flex-1">
          <p className="text-sm font-semibold truncate group-hover:underline" style={{ color: "var(--ink)" }}>{c.parsed.name}</p>
          {role && <p className="text-xs truncate mt-0.5" style={{ color: "var(--ink-3)" }}>{role}</p>}
          <div className="flex flex-wrap gap-1.5 mt-2">{c.parsed.skills.slice(0, 4).map((s) => <span key={s} className="text-[11px] rounded-full px-2 py-0.5 font-medium" style={{ background: "var(--brand-soft)", color: "var(--brand)" }}>{s}</span>)}</div>
        </div>
        <span className="shrink-0 w-7 h-7 rounded-full flex items-center justify-center transition-colors group-hover:text-neutral-700" style={{ border: "1px solid var(--line)", color: "var(--ink-3)" }}>
          <Icon name="arrowUpRight" className="w-3.5 h-3.5" />
        </span>
      </button>
    );
  };
  const matchSkeleton = (
    <div className="space-y-2.5">
      {[0, 1, 2].map((i) => (
        <div key={i} className="rounded-2xl bg-white border p-4 flex items-center gap-4" style={{ borderColor: "var(--line)" }}>
          <div className="rounded-full bg-neutral-200 animate-pulse shrink-0" style={{ width: 52, height: 52 }} />
          <div className="flex-1 space-y-2">
            <div className="h-3 rounded bg-neutral-200 animate-pulse" style={{ width: "45%" }} />
            <div className="h-2.5 rounded bg-neutral-200 animate-pulse" style={{ width: "30%" }} />
            <div className="h-2.5 rounded bg-neutral-200 animate-pulse" style={{ width: "60%" }} />
          </div>
        </div>
      ))}
    </div>
  );
  // A short AI recommendation for interviewers that explains the match beyond
  // the raw score: a fit verdict, the evidence behind it, and what to do next.
  // Deterministic in this preview; in production this is the model's rationale.
  const capFirst = (s) => (s ? s.charAt(0).toUpperCase() + s.slice(1) : s);
  const matchInsight = (c, { pct, mode, matched, industryLabel, yrs, role }) => {
    const verdict = pct >= 80 ? "Strong fit" : pct >= 55 ? "Good fit" : pct >= 30 ? "Moderate fit" : "Stretch fit";
    if (mode === "role") {
      const jt = rankedMeta?.label || "the role";
      const exp = yrs != null ? `${yrs} yrs${role ? ` as ${role}` : ""}` : (role || "relevant experience");
      const rec = pct >= 55
        ? `Interview early and probe the core ${jt} responsibilities.`
        : `Expect gaps against the ${jt} posting, so interview only if the shortlist is thin.`;
      return `${verdict} for ${jt}. ${capFirst(exp)}. ${rec}`;
    }
    const parts = [];
    const wanted = rankedMeta?.skills || [];
    if (wanted.length) {
      const list = matched.length ? ` (${matched.slice(0, 3).join(", ")})` : "";
      const full = wanted.length === 1 ? "covers the skill you searched" : wanted.length === 2 ? "covers both skills you searched" : `covers all ${wanted.length} skills you searched`;
      parts.push((matched.length === wanted.length ? full : `covers ${matched.length} of ${wanted.length} skills`) + list);
    }
    if (industryLabel) parts.push(`${yrs != null ? `${yrs} yrs` : "experience"} in ${industryLabel}`);
    else if (yrs != null) parts.push(`${yrs} yrs${role ? ` as ${role}` : ""}`);
    const rec = pct >= 80 ? "Worth an early interview." : pct >= 55 ? "A solid candidate to interview." : pct >= 30 ? "Interview if transferable experience works for you." : "Consider only if the shortlist is thin.";
    return `${verdict}. ${capFirst(parts.join(", "))}. ${rec}`;
  };
  const rankedList = (
    <div className="space-y-2.5">
      {shownList.map((c, idx) => {
        const pct = Math.round((matchScores?.[c.id] ?? 0) * 100);
        const isTop = idx === 0;
        const yrs = c.parsed.years_of_experience;
        const role = c.parsed.experience?.[0]?.title;
        const isSkills = rankedMeta?.mode === "skills";
        const hasSkillCriteria = isSkills && (rankedMeta.skills?.length > 0);
        const industryLabel = isSkills && rankedMeta.industries?.length ? [...industriesOf(c)].find((i) => rankedMeta.industries.includes(i)) : null;
        const matched = hasSkillCriteria ? matchedSkills(c) : [];
        const chips = hasSkillCriteria ? matched : (c.parsed.skills || []).slice(0, 4);
        const descriptor = isSkills
          ? [hasSkillCriteria ? `${matched.length}/${rankedMeta.skills.length} skills matched` : null, industryLabel, yrs != null ? `${yrs} yrs` : null, role].filter(Boolean).join(" · ")
          : [yrs != null ? `${yrs} yrs` : null, role].filter(Boolean).join(" · ");
        const insight = matchInsight(c, { pct, mode: rankedMeta?.mode, matched, industryLabel, yrs, role });
        return (
          <div key={c.id} className="rounded-2xl bg-white px-4 sm:px-5 py-4 border" style={{ borderColor: isTop ? "var(--brand)" : "var(--line)", boxShadow: isTop ? "0 18px 44px -22px rgba(151,59,247,0.45)" : "0 1px 2px rgba(18,19,42,0.04)" }}>
            <div className="flex items-center gap-4">
              <button onClick={() => onViewCandidate(c.id)} className="shrink-0" aria-label={`View ${c.parsed.name}`}>
                <ScoreRingLight value={pct} size={52} />
              </button>
              <div className="min-w-0 flex-1">
                <div className="flex items-center gap-2">
                  <CandidateAvatar name={c.parsed.name} hasPhoto={c.hasPhoto} src={c.avatarUrl} size={26} showPhotoDot={false} />
                  <button onClick={() => onViewCandidate(c.id)} className="min-w-0 flex-1 text-left">
                    <p className="text-sm font-semibold truncate hover:underline" style={{ color: "var(--ink)" }}>{c.parsed.name}</p>
                  </button>
                  {isTop && <span className="shrink-0 text-[10px] px-2 py-0.5 rounded-full brand-gradient text-white font-semibold">Top match</span>}
                </div>
                <p className="text-xs truncate mt-0.5" style={{ color: "var(--ink-3)" }}>{descriptor}</p>
                <div className="flex flex-wrap gap-1.5 mt-2">{chips.map((s) => <span key={s} className="text-[11px] rounded-full px-2 py-0.5 font-medium" style={{ background: "var(--brand-soft)", color: "var(--brand)" }}>{s}</span>)}</div>
              </div>
              <button onClick={() => onViewCandidate(c.id)} className="shrink-0 text-xs font-semibold rounded-xl px-3.5 py-2 transition-colors hover:bg-neutral-50" style={{ border: "1px solid var(--line-strong)", color: "var(--ink-2)" }}>View</button>
            </div>
            <div className="mt-3 flex items-start gap-2 rounded-xl px-3 py-2.5" style={{ background: "rgba(151,59,247,0.05)", border: "1px solid rgba(151,59,247,0.13)" }}>
              <span className="shrink-0 mt-px" style={{ color: "var(--brand)" }}><Icon name="matching" className="w-3.5 h-3.5" /></span>
              <p className="text-[11px] leading-relaxed" style={{ color: "var(--ink-2)" }}><span className="font-semibold" style={{ color: "var(--brand)" }}>AI insight: </span>{insight}</p>
            </div>
          </div>
        );
      })}
      {lockedList.length > 0 && (
        <div className="relative pt-1">
          <div className="space-y-2.5 blur-[3px] pointer-events-none select-none" aria-hidden="true">
            {lockedList.slice(0, 2).map((c, i) => (
              <div key={i} className="rounded-2xl bg-white border p-4 flex items-center gap-3.5" style={{ borderColor: "var(--line)" }}>
                <CandidateAvatar name={c.parsed.name} hasPhoto={c.hasPhoto} src={c.avatarUrl} size={44} showPhotoDot={false} />
                <div className="min-w-0 flex-1"><p className="text-sm font-semibold truncate" style={{ color: "var(--ink)" }}>{c.parsed.name}</p></div>
              </div>
            ))}
          </div>
          <div className="absolute inset-0 flex items-center justify-center px-4">
            <div className="rounded-2xl bg-white/90 backdrop-blur-sm border act-shadow" style={{ borderColor: "var(--line)" }}>
              <UpgradeLock navigate={navigate} compact title={`${lockedList.length} more ${lockedList.length === 1 ? "match" : "matches"} hidden`} sub={`Your plan shows the top ${limits.aiMatches}. Upgrade for the full ranking.`} />
            </div>
          </div>
        </div>
      )}
    </div>
  );
  // Runs-left note shown under both AI panels.
  // AI-match-runs usage — same meter method as the Upload screen's "Usage this month".
  const planNote = limits.aiRunsPerMonth !== Infinity ? (
    <UsageMeter
      title="AI match runs this month"
      hint="One run is a single AI ranking of your candidates. Each Run AI match uses one, and your plan includes a set number each month."
      used={matchRunsUsed} limit={limits.aiRunsPerMonth} unit="runs used"
      note={outOfRuns
        ? `You've used all ${limits.aiRunsPerMonth} runs. Resets on the 1st.`
        : `${runsLeft} run${runsLeft === 1 ? "" : "s"} left on your ${plan === "starter" ? "Pro" : plan === "professional" ? "Premium" : "current"} plan · showing the top ${limits.aiMatches} matches.`}
      onManage={() => navigate("billing")} onUpgrade={() => navigate("billing")}
    />
  ) : null;

  const TABS = [
    { key: "browse", short: "Browse", full: "Browse", icon: "users" },
    { key: "skills", short: "Skills", full: "Skills & industry", icon: "matching" },
    { key: "role", short: "Role", full: "Match to a role", icon: "briefcase" },
  ];
  // Popular skills across job families (not just engineering) — each exists in
  // the candidate pool so a quick-add always returns real matches.
  const POPULAR_SKILLS = ["React", "Salesforce", "SEO", "Financial Modeling", "Recruiting", "SQL", "Account Management", "Project Management", "Copywriting", "Patient Care"];
  // Industries present in the candidate pool, so a bubble always returns matches.
  const POPULAR_INDUSTRIES = ["Technology", "Finance & Fintech", "E-commerce & Retail", "Healthcare", "Media & Creative", "Travel & Aviation", "Logistics & Operations", "Professional Services"];
  const SEARCH_HELP = [
    { icon: "users", title: "Browse & filter", body: "Search your whole database by name, skill, or role, and narrow by years of experience." },
    { icon: "matching", title: "Match by skills or industry", body: "Add the skills you're hiring for, pick an industry, or both, and AI ranks everyone by fit." },
    { icon: "briefcase", title: "Match to a role", body: "Pick an open role and AI ranks candidates by fit, so you can invite the strongest to apply." },
    { icon: "link", title: "Invite to apply", body: "Found someone good? Send them a link to apply. Even an older profile might still be keen." },
  ];

  return (
    <div
      className="px-4 sm:px-6 lg:px-8 py-6 lg:py-8 md:min-h-[calc(100vh-2rem)] md:rounded-[26px]"
      style={{
        background:
          "radial-gradient(1100px 480px at 100% -8%, rgba(151,59,247,0.08), transparent 60%)," +
          "radial-gradient(900px 460px at -8% 4%, rgba(90,120,248,0.07), transparent 55%)," +
          "var(--bg)",
      }}
    >
      <div className="mx-auto w-full max-w-[1400px]">
        <BackLink onClick={() => navigate("dashboard")}>← Dashboard</BackLink>
        <div className="mt-2">
          <TopBar
            title="Candidate Search"
            subtitle={
              <span className="inline-flex flex-wrap items-center gap-2">
                <span className="inline-flex items-center gap-1.5 rounded-full px-2.5 py-0.5 text-xs font-medium" style={{ background: "#F1F1F4", color: "var(--ink-2)" }}>
                  <Icon name="users" className="w-3.5 h-3.5" style={{ color: "var(--brand)" }} /> {availableCount} candidates
                </span>
                <span className="inline-flex items-center gap-1.5 rounded-full px-2.5 py-0.5 text-xs font-medium" style={{ background: "#ECFDF3", color: "#15803D" }}>
                  <span className="w-1.5 h-1.5 rounded-full" style={{ background: "#22C55E" }} /> {openJobs.length} open {openJobs.length === 1 ? "role" : "roles"}
                </span>
              </span>
            }
            activities={activities}
            onOpenNotifications={onOpenNotifications}
            avatarUrl={avatarUrl}
            profile={profile}
            navigate={navigate}
          />
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-5 lg:gap-6 items-start">
          {/* Main workspace */}
          <div className="lg:col-span-2 min-w-0">

        {/* Tabs — three separate ways to find people */}
        <div className="flex gap-1 p-1 rounded-2xl mb-5 sm:inline-flex" style={{ background: "#fff", border: "1px solid var(--line)" }}>
          {TABS.map((t) => {
            const active = tab === t.key;
            return (
              <button key={t.key} onClick={() => switchTab(t.key)}
                className={`flex-1 sm:flex-none inline-flex items-center justify-center gap-2 px-3 sm:px-4 py-2 rounded-xl text-[13px] sm:text-sm font-semibold transition-all ${active ? "brand-gradient text-white shadow-[0_8px_20px_-10px_rgba(151,59,247,0.7)]" : "hover:bg-neutral-50"}`}
                style={active ? undefined : { color: "var(--ink-2)" }}>
                <Icon name={t.icon} className="w-4 h-4" />
                <span className="sm:hidden">{t.short}</span>
                <span className="hidden sm:inline">{t.full}</span>
              </button>
            );
          })}
        </div>

        {/* ---------- Tab 1: Browse ---------- */}
        {tab === "browse" && (
          <>
            <div className="relative">
              <span className="absolute left-4 top-1/2 -translate-y-1/2" style={{ color: "var(--ink-3)" }}><Icon name="search" className="w-5 h-5" /></span>
              <input value={query} onChange={(e) => { setQuery(e.target.value); setPage(1); }} placeholder="Search by name, skill, or role…"
                className="w-full rounded-2xl bg-white border pl-12 pr-10 py-3.5 text-sm focus:outline-none focus:ring-2 focus:ring-violet-200 focus:border-violet-300 transition-shadow"
                style={{ borderColor: "var(--line)", color: "var(--ink)", boxShadow: "0 1px 2px rgba(18,19,42,0.04)" }} />
              {query && <button onClick={() => { setQuery(""); setPage(1); }} aria-label="Clear search" className="absolute right-3 top-1/2 -translate-y-1/2 w-6 h-6 rounded-full flex items-center justify-center hover:bg-neutral-100 transition-colors" style={{ color: "var(--ink-3)" }}><Icon name="close" className="w-4 h-4" /></button>}
            </div>
            <div className="flex flex-wrap items-center gap-2 mt-3">
              <span className="text-xs" style={{ color: "var(--ink-3)" }}>Popular:</span>
              {["React", "Salesforce", "SEO", "Project Management", "Financial Modeling", "Adobe Photoshop"].map((chip) => {
                const active = query === chip;
                return <button key={chip} onClick={() => { setQuery(active ? "" : chip); setPage(1); }} className="text-xs rounded-full px-3 py-1 font-medium transition-colors" style={active ? { background: "var(--brand-soft)", border: "1px solid var(--brand)", color: "var(--brand)" } : { background: "#fff", border: "1px solid var(--line)", color: "var(--ink-2)" }}>{chip}</button>;
              })}
            </div>
            <div className="flex flex-wrap items-center justify-between gap-3 mt-5 mb-3">
              <p className="text-sm" style={{ color: "var(--ink-2)" }}>
                <span className="font-semibold" style={{ color: "var(--ink)" }}>{list.length}</span> {list.length === 1 ? "candidate" : "candidates"}{q ? ` · matching "${query}"` : " in your database"}
                {pageCount > 1 && <span style={{ color: "var(--ink-3)" }}> · {pageStart + 1}–{Math.min(pageStart + PER_PAGE, shownList.length)} shown</span>}
              </p>
              <div className="flex items-center gap-2">
                <select value={minYears} onChange={(e) => { setMinYears(Number(e.target.value)); setPage(1); }} className="rounded-lg bg-white border px-2.5 py-1.5 text-xs font-medium focus:outline-none focus:ring-2 focus:ring-violet-200 transition-shadow" style={{ borderColor: "var(--line)", color: "var(--ink-2)" }} aria-label="Filter by experience">
                  <option value={0}>Any experience</option><option value={3}>3+ years</option><option value={5}>5+ years</option><option value={8}>8+ years</option>
                </select>
                <select value={sortBy} onChange={(e) => { setSortBy(e.target.value); setPage(1); }} className="rounded-lg bg-white border px-2.5 py-1.5 text-xs font-medium focus:outline-none focus:ring-2 focus:ring-violet-200 transition-shadow" style={{ borderColor: "var(--line)", color: "var(--ink-2)" }} aria-label="Sort candidates">
                  <option value="name">Sort: Name (A–Z)</option><option value="experience">Sort: Most experience</option>
                </select>
                {(q || minYears > 0) && <button onClick={() => { setQuery(""); setMinYears(0); setPage(1); }} className="text-xs font-medium hover:opacity-70 transition-opacity" style={{ color: "var(--brand)" }}>Reset</button>}
              </div>
            </div>
            {list.length === 0 ? emptyState("No candidates found", q ? `Nothing matches "${query}". Try a different name, skill, or role.` : "Your database is empty.") : (<>
              <div className="grid sm:grid-cols-2 gap-3">
                {browseItems.map((c) => browseCard(c))}
                {lockedList.length > 0 && (
                  <div className="relative pt-1 sm:col-span-2">
                    <div className="grid sm:grid-cols-2 gap-3 blur-[3px] pointer-events-none select-none" aria-hidden="true">
                      {lockedList.slice(0, 3).map((c, i) => (
                        <div key={i} className="rounded-2xl bg-white border p-4 flex items-center gap-3.5" style={{ borderColor: "var(--line)" }}>
                          <CandidateAvatar name={c.parsed.name} hasPhoto={c.hasPhoto} src={c.avatarUrl} size={44} showPhotoDot={false} />
                          <div className="min-w-0 flex-1"><p className="text-sm font-semibold truncate" style={{ color: "var(--ink)" }}>{c.parsed.name}</p></div>
                        </div>
                      ))}
                    </div>
                    <div className="absolute inset-0 flex items-center justify-center px-4">
                      <div className="rounded-2xl bg-white/90 backdrop-blur-sm border act-shadow" style={{ borderColor: "var(--line)" }}>
                        <UpgradeLock navigate={navigate} compact title={`${lockedList.length} more candidate${lockedList.length === 1 ? "" : "s"} hidden`} sub={`Your plan shows the top ${limits.visibleCandidates}. Upgrade to browse everyone.`} />
                      </div>
                    </div>
                  </div>
                )}
              </div>
              {pageCount > 1 && (
                <div className="flex items-center justify-center gap-1.5 mt-6">
                  <button onClick={() => goToPage(safePage - 1)} disabled={safePage === 1} aria-label="Previous page"
                    className="rounded-lg border px-3 py-1.5 text-xs font-medium transition-colors disabled:opacity-40 disabled:cursor-not-allowed hover:bg-neutral-50 inline-flex items-center gap-1" style={{ borderColor: "var(--line-strong)", color: "var(--ink-2)" }}>
                    <Icon name="chevronLeft" className="w-3.5 h-3.5" /> Prev
                  </button>
                  {Array.from({ length: pageCount }, (_, i) => i + 1).map((n) => (
                    <button key={n} onClick={() => goToPage(n)} aria-label={`Page ${n}`} aria-current={n === safePage ? "page" : undefined}
                      className="w-8 h-8 rounded-lg text-xs font-semibold transition-colors"
                      style={n === safePage ? { background: "linear-gradient(135deg, var(--brand-0), var(--brand-2))", color: "#fff" } : { border: "1px solid var(--line)", color: "var(--ink-2)" }}>
                      {n}
                    </button>
                  ))}
                  <button onClick={() => goToPage(safePage + 1)} disabled={safePage === pageCount} aria-label="Next page"
                    className="rounded-lg border px-3 py-1.5 text-xs font-medium transition-colors disabled:opacity-40 disabled:cursor-not-allowed hover:bg-neutral-50 inline-flex items-center gap-1" style={{ borderColor: "var(--line-strong)", color: "var(--ink-2)" }}>
                    Next <Icon name="chevronRight" className="w-3.5 h-3.5" />
                  </button>
                </div>
              )}
            </>)}
          </>
        )}

        {/* ---------- Tab 2: Match by skills ---------- */}
        {tab === "skills" && (
          <>
            <div className="rounded-2xl p-4 sm:p-5 mb-5 relative" style={{ background: "linear-gradient(135deg, rgba(214,91,255,0.06), rgba(90,120,248,0.05))", border: "1px solid var(--line)" }}>
              <div className="flex items-start gap-3">
                <span className="w-9 h-9 rounded-xl brand-gradient flex items-center justify-center text-white shrink-0 shadow-[0_8px_20px_-8px_rgba(151,59,247,0.7)]"><Icon name="matching" className="w-4 h-4" /></span>
                <div className="min-w-0 flex-1">
                  <p className="text-sm font-semibold font-display" style={{ color: "var(--ink)" }}>Match by skills or industry</p>
                  <p className="text-xs mt-0.5" style={{ color: "var(--ink-3)" }}>Search skills, an industry, or both. AI ranks everyone by fit.</p>
                  <div className="mt-3 grid sm:grid-cols-2 gap-3">
                    <div>
                      <FieldLabel hint="Type any skill and pick a suggestion. If it is not in the list, press Enter to add it as your own custom skill.">Skills</FieldLabel>
                      <TokenAutocomplete tags={skillTags} setTags={setSkillTags} options={skillSuggestions} placeholder="Search skills…" onChange={invalidate} aliases={SKILL_ALIASES} freeSolo />
                      <div className="flex flex-wrap items-center gap-1.5 mt-2">
                        {POPULAR_SKILLS.filter((s) => !skillTags.some((x) => x.toLowerCase() === s.toLowerCase())).slice(0, 5).map((s) => (
                          <button key={s} onClick={() => addSkill(s)} className="text-[11px] rounded-full px-2.5 py-1 font-medium transition-colors hover:bg-neutral-50" style={{ background: "#fff", border: "1px solid var(--line)", color: "var(--ink-2)" }}>+ {s}</button>
                        ))}
                      </div>
                    </div>
                    <div>
                      <FieldLabel hint="Type to search our industry list and pick the closest match. Choosing from the list keeps the ranking accurate.">Industry</FieldLabel>
                      <TokenAutocomplete tags={industryTags} setTags={setIndustryTags} options={ALL_INDUSTRIES} placeholder="Search industries…" onChange={invalidate} aliases={INDUSTRY_ALIASES} freeSolo={false} />
                      <div className="flex flex-wrap items-center gap-1.5 mt-2">
                        {POPULAR_INDUSTRIES.filter((s) => !industryTags.some((x) => x.toLowerCase() === s.toLowerCase())).slice(0, 5).map((s) => (
                          <button key={s} onClick={() => addIndustry(s)} className="text-[11px] rounded-full px-2.5 py-1 font-medium transition-colors hover:bg-neutral-50" style={{ background: "#fff", border: "1px solid var(--line)", color: "var(--ink-2)" }}>+ {s}</button>
                        ))}
                      </div>
                    </div>
                  </div>
                  <div className="mt-4">
                    <button onClick={runSkillMatch} disabled={(!skillTags.length && !industryTags.length) || matching}
                      className="rounded-xl brand-gradient hover:opacity-95 disabled:opacity-40 disabled:cursor-not-allowed text-white text-sm font-semibold px-5 py-2.5 inline-flex items-center justify-center gap-2 transition-all enabled:hover:-translate-y-0.5 shadow-[0_12px_30px_-12px_rgba(151,59,247,0.8)]">
                      <Icon name={outOfRuns ? "lock" : "matching"} className="w-4 h-4" />
                      {matching ? "Matching…" : outOfRuns ? "Upgrade for more runs" : "Run AI match"}
                    </button>
                  </div>
                </div>
              </div>
            </div>
            {matchScores && !matching && (
              <div className="flex items-center justify-between gap-3 mb-3">
                <p className="text-sm" style={{ color: "var(--ink-2)" }}><span className="font-semibold" style={{ color: "var(--ink)" }}>{list.length}</span> {list.length === 1 ? "candidate" : "candidates"} · ranked by fit <InfoHint dir="down" hint="The ring is a fit score from 0 to 100 percent, showing how closely each person matches what you searched for." /></p>
                <button onClick={() => setMatchScores(null)} className="text-xs font-medium hover:opacity-70 transition-opacity" style={{ color: "var(--brand)" }}>Clear</button>
              </div>
            )}
            {matching ? matchSkeleton
              : !matchScores ? emptyState("Rank by skills or industry", (skillTags.length || industryTags.length) ? "Run the AI match to see the best fits." : "Search skills, an industry, or both, then run the AI match.", "matching")
              : list.length === 0 ? emptyState("No matches found", "No candidates fit those criteria. Try broadening the skills or industry.", "matching")
              : rankedList}
          </>
        )}

        {/* ---------- Tab 3: Match to a role ---------- */}
        {tab === "role" && (
          <>
            <div className="rounded-2xl p-4 sm:p-5 mb-5 relative" style={{ background: "linear-gradient(135deg, rgba(214,91,255,0.06), rgba(90,120,248,0.05))", border: "1px solid var(--line)" }}>
              <div className="flex items-start gap-3">
                <span className="w-9 h-9 rounded-xl brand-gradient flex items-center justify-center text-white shrink-0 shadow-[0_8px_20px_-8px_rgba(151,59,247,0.7)]"><Icon name="briefcase" className="w-4 h-4" /></span>
                <div className="min-w-0 flex-1">
                  <p className="text-sm font-semibold font-display flex items-center gap-1.5" style={{ color: "var(--ink)" }}>
                    Match to an open role
                    <InfoHint dir="down" hint="These are the live job postings in your workspace. AI ranks your whole candidate database against the role you pick, so you can invite the best fits to apply." />
                  </p>
                  <p className="text-xs mt-0.5" style={{ color: "var(--ink-3)" }}>Pick a role. AI ranks every candidate by fit. Open a profile to review them, then invite the strongest to apply.</p>
                  <div className="flex flex-col sm:flex-row gap-2 mt-3">
                    <JobSelect jobs={openJobs} value={matchJobId} onChange={(id) => { setMatchJobId(id); setMatchScores(null); }} disabled={openJobs.length === 0} placeholder="Select an open position…" />
                    <button onClick={runRoleMatch} disabled={!matchJobId || matching}
                      className="shrink-0 rounded-xl brand-gradient hover:opacity-95 disabled:opacity-40 disabled:cursor-not-allowed text-white text-sm font-semibold px-5 py-2.5 flex items-center justify-center gap-2 transition-all enabled:hover:-translate-y-0.5 shadow-[0_12px_30px_-12px_rgba(151,59,247,0.8)]">
                      <Icon name={outOfRuns ? "lock" : "matching"} className="w-4 h-4" />
                      {matching ? "Matching…" : outOfRuns ? "Upgrade for more runs" : "Run AI match"}
                    </button>
                  </div>
                  {openJobs.length === 0 && (
                    <p className="text-xs mt-2.5" style={{ color: "var(--ink-3)" }}>No open positions yet. Create one under Job Postings.</p>
                  )}
                </div>
              </div>
            </div>
            {inviteBanner && (
              <div className="mb-4 rounded-xl px-3.5 py-2.5 flex items-center gap-2" style={{ background: "rgba(16,185,129,0.08)", border: "1px solid rgba(16,185,129,0.25)" }}>
                <span className="shrink-0" style={{ color: "#059669" }}><Icon name="check" className="w-4 h-4" /></span>
                <p className="text-xs" style={{ color: "#047857" }}>{inviteBanner}</p>
              </div>
            )}
            {matchScores && !matching && (
              <div className="flex items-center justify-between gap-3 mb-3">
                <p className="text-sm" style={{ color: "var(--ink-2)" }}>
                  <span className="font-semibold" style={{ color: "var(--ink)" }}>{list.length}</span> {list.length === 1 ? "candidate" : "candidates"} · ranked for {matchJob?.title}
                  {alreadyApplied.size > 0 ? ` · ${alreadyApplied.size} already applied, hidden` : ""}
                </p>
                <button onClick={() => setMatchScores(null)} className="text-xs font-medium hover:opacity-70 transition-opacity" style={{ color: "var(--brand)" }}>Clear</button>
              </div>
            )}
            {matching ? matchSkeleton
              : !matchScores ? emptyState("Rank candidates for a role", openJobs.length === 0 ? "Create an open role under Job Postings to match against." : "Select an open role above, then run the AI match.", "briefcase")
              : list.length === 0 ? emptyState("No one left to invite", matchJob ? `Everyone in your database has already applied to ${matchJob.title}.` : "No candidates to rank.", "briefcase")
              : rankedList}
            {matchScores && matchJob && list.length > 0 && (
              <button onClick={() => onPreviewApply && onPreviewApply(matchJob)} className="text-sm font-medium mt-4 hover:opacity-70 transition-opacity" style={{ color: "var(--brand)" }}>
                Preview the {matchJob.title} application page →
              </button>
            )}
          </>
        )}

          </div>{/* main workspace */}

          {/* Sidebar — AI-run usage monitor + how search works (matches Bulk Upload) */}
          <aside className="space-y-5 lg:sticky lg:top-4 lg:self-start">
            {planNote}
            <div className="rounded-2xl bg-white border p-4" style={{ borderColor: "var(--line)" }}>
              <h2 className="text-[11px] font-semibold uppercase tracking-wide mb-1.5 px-1" style={{ color: "var(--ink-2)", letterSpacing: "0.06em" }}>How it works</h2>
              <div>
                {SEARCH_HELP.map((item, i) => {
                  const open = openTip === i;
                  return (
                    <div key={item.title} className={i > 0 ? "border-t" : ""} style={i > 0 ? { borderColor: "var(--line)" } : undefined}>
                      <button onClick={() => setOpenTip(open ? null : i)} aria-expanded={open} className="w-full flex items-center gap-2.5 py-2.5 px-1 text-left transition-colors hover:bg-neutral-50/60 rounded-lg">
                        <span className="flex w-6 h-6 shrink-0 items-center justify-center rounded-md" style={{ background: "var(--brand-soft)", color: "var(--brand)" }}><Icon name={item.icon} className="w-3.5 h-3.5" /></span>
                        <span className="flex-1 text-[13px] font-medium min-w-0" style={{ color: "var(--ink)" }}>{item.title}</span>
                        <span className="shrink-0 transition-transform" style={{ color: "var(--ink-3)", transform: open ? "rotate(180deg)" : "none" }}><Icon name="chevronDown" className="w-4 h-4" /></span>
                      </button>
                      {open && <p className="text-xs leading-relaxed pb-3 pl-[2.15rem] pr-1" style={{ color: "var(--ink-3)" }}>{item.body}</p>}
                    </div>
                  );
                })}
              </div>
            </div>
          </aside>
        </div>{/* grid */}
      </div>
    </div>
  );
}

function InterviewsScreen({ navigate, bookings, candidates, jobs, onViewCandidate }) {
  const interviews = scheduledInterviewsFrom(bookings, candidates);

  const jobForTitle = (title) => jobs.find((j) => j.title === title);

  return (
    <div className="px-4 sm:px-6 py-8 sm:py-10">
      <div className="max-w-3xl mx-auto">
        <BackLink onClick={() => navigate("dashboard")}>← Dashboard</BackLink>
        <div className="flex items-center justify-between mt-2 mb-1">
          <h1 className="text-xl sm:text-2xl font-bold font-display" style={{ color: "var(--ink)" }}>Scheduled Interviews</h1>
          <button
            onClick={() => navigate("interviewers")}
            className="text-sm font-medium hover:opacity-70 transition-opacity"
            style={{ color: "var(--brand)" }}
          >
            Manage interviewers →
          </button>
        </div>
        <p className="text-sm mb-6" style={{ color: "var(--ink-2)" }}>
          {interviews.length > 0
            ? `${interviews.length} interview${interviews.length > 1 ? "s" : ""} confirmed and on the calendar.`
            : "Interviews a candidate has confirmed will appear here."}
        </p>

        {interviews.length === 0 ? (
          <div className="rounded-2xl bg-white act-shadow border p-10 text-center" style={{ borderColor: "var(--line)" }}>
            <p className="text-sm" style={{ color: "var(--ink-2)" }}>No interviews scheduled yet.</p>
            <p className="text-xs mt-1" style={{ color: "var(--ink-3)" }}>
              Send a candidate an interview invite — once they pick a time, it shows up here with the position and their details.
            </p>
          </div>
        ) : (
          <div className="space-y-3">
            {interviews.map((iv) => {
              const cand = candidates.find((c) => c.id === iv.candidateId);
              const job = jobForTitle(iv.jobTitle);
              const dateLine = iv.start.toLocaleString("en-US", {
                weekday: "long",
                month: "long",
                day: "numeric",
              });
              return (
                <button
                  key={iv.candidateId}
                  onClick={() => onViewCandidate(iv.candidateId, job?.id ?? null)}
                  className="w-full text-left rounded-2xl bg-white act-shadow border p-4 sm:p-5 hover:border-[color:var(--line-strong)] transition-colors flex items-center gap-4"
                  style={{ borderColor: "var(--line)" }}
                >
                  {/* Date chip */}
                  <div className="w-14 shrink-0 text-center rounded-xl py-2" style={{ background: "var(--brand-soft)" }}>
                    <p className="text-[10px] uppercase tracking-wide" style={{ color: "var(--brand)" }}>{iv.month}</p>
                    <p className="text-lg font-bold leading-none" style={{ color: "var(--ink)" }}>{iv.day}</p>
                  </div>

                  {/* Candidate + position */}
                  <div className="min-w-0 flex-1">
                    <p className="text-sm font-semibold truncate" style={{ color: "var(--ink)" }}>{iv.candidateName}</p>
                    <p className="text-xs truncate" style={{ color: "var(--ink-2)" }}>{iv.jobTitle}</p>
                    <div className="flex flex-wrap items-center gap-x-3 gap-y-1 mt-1.5">
                      <span className="text-xs flex items-center gap-1" style={{ color: "var(--ink-3)" }}>
                        <Icon name="calendar" className="w-3 h-3" /> {dateLine}
                      </span>
                      <span className="text-xs flex items-center gap-1" style={{ color: "var(--ink-3)" }}>
                        <Icon name="clock" className="w-3 h-3" /> {iv.time}
                      </span>
                      {iv.interviewerName && (
                        <span className="text-xs flex items-center gap-1" style={{ color: "var(--ink-3)" }}>
                          <Icon name="users" className="w-3 h-3" /> {iv.interviewerName}
                        </span>
                      )}
                    </div>
                  </div>

                  {/* Provider + status */}
                  <div className="text-right shrink-0 hidden sm:block">
                    <span className="inline-flex items-center gap-1.5 text-xs font-medium rounded-full px-2.5 py-1" style={{ background: "#ECFDF3", color: "#067647" }}>
                      <span className="w-1.5 h-1.5 rounded-full" style={{ background: "#12B76A" }} /> Confirmed
                    </span>
                    <p className="text-xs mt-1.5" style={{ color: "var(--ink-3)" }}>{iv.provider}</p>
                  </div>
                </button>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

function InterviewersScreen({ navigate, interviewers, setInterviewers, defaultProvider, bookings = {}, calendarConnected = false, plan = "free", profile }) {
  const limits = planLimits(plan);
  const canAddInterviewers = limits.canAddInterviewers;
  // Seats include the owner, so invitable teammates = seats − 1.
  const seatCap = limits.seats === Infinity ? Infinity : Math.max(0, limits.seats - 1);
  const atSeatCap = interviewers.length >= seatCap;
  const [showForm, setShowForm] = useState(false);
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [banner, setBanner] = useState(null);
  const [removing, setRemoving] = useState(null); // interviewer pending removal (confirm modal)

  const ownerName = `${profile?.firstName || "You"} ${profile?.lastName || ""}`.trim();

  // The meeting-link type and calendar are a single workspace choice, connected
  // once in Settings — not something each interviewer sets up individually.
  const meetLabel = defaultProvider === "microsoft" ? "Microsoft Teams" : "Google Meet";
  const calSystem = defaultProvider === "microsoft" ? "Microsoft 365" : "Google Workspace";

  const inputClass = "w-full rounded-xl bg-neutral-100 border border-neutral-200 px-3 py-2 text-neutral-900 text-sm focus:outline-none focus:ring-2 focus:ring-neutral-400";
  const labelClass = "block text-sm text-neutral-700 mb-1";

  // How many confirmed interviews reference this interviewer (bookings link by name).
  const scheduledCountFor = (iv) =>
    Object.values(bookings).filter(
      (b) => b && b.status === "scheduled" && b.request?.interviewerName === iv.name
    ).length;

  const handleAdd = () => {
    if (!canAddInterviewers || !name || !email) return;
    if (atSeatCap) {
      setBanner(`Your plan includes ${limits.seats} seats. Upgrade to Premium for unlimited team members.`);
      return;
    }
    setInterviewers([
      ...interviewers,
      {
        id: `iv${interviewers.length + 1}`,
        name,
        email,
        timezone: "Asia/Kuala_Lumpur",
        status: "pending",
      },
    ]);
    setBanner(`Invite sent to ${email}. They'll get a link to join your workspace and run interviews.`);
    setName("");
    setEmail("");
    setShowForm(false);
  };

  const confirmRemove = () => {
    if (!removing) return;
    setInterviewers((prev) => prev.filter((x) => x.id !== removing.id));
    setBanner(`${removing.name} was removed.`);
    setRemoving(null);
  };

  return (
    <div className="px-4 sm:px-6 py-8 sm:py-10">
      <div className="max-w-2xl mx-auto">
        <BackLink onClick={() => navigate("dashboard")}>← Dashboard</BackLink>
        <div className="flex items-center justify-between mt-2 mb-1">
          <h1 className="text-xl sm:text-2xl font-bold font-display" style={{ color: "var(--ink)" }}>Interviewers</h1>
          {canAddInterviewers ? (
            <button
              onClick={() => (atSeatCap ? navigate("billing") : setShowForm((s) => !s))}
              className="text-sm rounded-xl bg-neutral-900 hover:bg-neutral-800 text-white px-3 py-1.5 transition-colors"
            >
              {atSeatCap ? "Seats full — upgrade" : showForm ? "Cancel" : "+ Invite teammate"}
            </button>
          ) : (
            <button
              onClick={() => navigate("billing")}
              className="text-sm rounded-xl border px-3 py-1.5 flex items-center gap-1.5 transition-colors hover:bg-neutral-50"
              style={{ borderColor: "var(--line-strong)", color: "var(--ink-2)" }}
            >
              <Icon name="lock" className="w-3.5 h-3.5" /> Invite teammate <LockBadge />
            </button>
          )}
        </div>
        {!canAddInterviewers && (
          <div className="rounded-xl border p-3 mb-4 mt-2 flex items-center justify-between gap-3" style={{ borderColor: "var(--line)", background: "var(--brand-soft)" }}>
            <p className="text-xs" style={{ color: "var(--ink-2)" }}>
              The Free plan includes <span className="font-semibold">1 seat — just you</span>. Upgrade to invite teammates, each with their own login.
            </p>
            <button onClick={() => navigate("billing")} className="text-xs brand-gradient text-white font-medium px-3 py-1.5 rounded-lg shrink-0 hover:opacity-90 transition-opacity">Upgrade</button>
          </div>
        )}
        {canAddInterviewers && limits.seats !== Infinity && (
          <div className="rounded-xl border p-3 mb-4 mt-2 flex items-center justify-between gap-3" style={{ borderColor: "var(--line)", background: atSeatCap ? "var(--brand-soft)" : "#fff" }}>
            <p className="text-xs" style={{ color: "var(--ink-2)" }}>
              Your plan includes <span className="font-semibold">{limits.seats} seats</span> — {interviewers.length + 1} of {limits.seats} in use{atSeatCap ? ". Upgrade to Premium for unlimited seats." : "."}
            </p>
            {atSeatCap && <button onClick={() => navigate("billing")} className="text-xs brand-gradient text-white font-medium px-3 py-1.5 rounded-lg shrink-0 hover:opacity-90 transition-opacity">Upgrade</button>}
          </div>
        )}
        <p className="text-sm mb-4" style={{ color: "var(--ink-2)" }}>
          Your team. Invite teammates to run interviews — each gets their own login and sees only the interviews assigned to them. Availability and {meetLabel} links come from your workspace calendar, so there's no per-person setup.
        </p>

        {/* Workspace calendar status — one connection covers everyone */}
        <div className="mb-6 rounded-xl border p-3 flex items-center justify-between gap-3" style={{ borderColor: "var(--line)", background: calendarConnected ? "#F0FDF4" : "#FFF7ED" }}>
          <div className="flex items-center gap-2 min-w-0">
            <Icon name="calendar" className="w-4 h-4 shrink-0" style={{ color: calendarConnected ? "#16A34A" : "#B45309" }} />
            <p className="text-sm min-w-0" style={{ color: calendarConnected ? "#166534" : "#92400E" }}>
              {calendarConnected
                ? `${calSystem} calendar connected — all interviewers are covered.`
                : `Connect your ${calSystem} calendar to enable scheduling for everyone.`}
            </p>
          </div>
          {!calendarConnected && (
            <button onClick={() => navigate("settings")} className="text-xs font-medium shrink-0 hover:opacity-70" style={{ color: "var(--brand)" }}>
              Connect in Settings →
            </button>
          )}
        </div>

        {banner && (
          <div className="mb-4 rounded-xl bg-white act-shadow px-4 py-2 border border-[color:var(--line)]">
            <p className="text-sm text-neutral-700">{banner}</p>
          </div>
        )}

        {showForm && (
          <div className="mb-6 rounded-2xl bg-white act-shadow p-5 border border-[color:var(--line)] space-y-3">
            <p className="text-sm font-medium text-neutral-900">Invite a teammate</p>
            <div>
              <label className={labelClass}>Name</label>
              <input value={name} onChange={(e) => setName(e.target.value)} placeholder="Jane Tan" className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Work email</label>
              <input value={email} onChange={(e) => setEmail(e.target.value)} placeholder="jane@company.com" className={inputClass} />
            </div>
            <button onClick={handleAdd} className="rounded-xl bg-neutral-900 hover:bg-neutral-800 text-white text-sm font-medium px-4 py-2 transition-colors">
              Send invite
            </button>
            <p className="text-xs text-neutral-400">They'll get an email to join your workspace. Teammates are included in your plan — they don't buy their own.</p>
          </div>
        )}

        <div className="space-y-2">
          {/* Account owner — always a member, can't be removed */}
          <div className="flex items-start justify-between gap-3 rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]">
            <div className="min-w-0">
              <div className="flex items-center gap-2">
                <p className="text-neutral-900 font-medium truncate">{ownerName || "You"}</p>
                <span className="text-[10px] px-1.5 py-0.5 rounded-full font-semibold" style={{ background: "var(--brand-soft)", color: "var(--brand)" }}>Owner · You</span>
              </div>
              <p className="text-xs text-neutral-500 truncate">{profile?.role || "Hiring Manager"} · {meetLabel}</p>
            </div>
          </div>

          {interviewers.map((iv) => {
            const upcoming = scheduledCountFor(iv);
            const pending = iv.status === "pending";
            return (
              <div key={iv.id} className="flex items-start justify-between gap-3 rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]">
                <div className="min-w-0">
                  <div className="flex items-center gap-2">
                    <p className="text-neutral-900 font-medium truncate">{iv.name}</p>
                    <span className="text-[10px] px-1.5 py-0.5 rounded-full font-semibold shrink-0" style={pending ? { background: "#FEF3C7", color: "#92400E" } : !canAddInterviewers ? { background: "#F1F1F4", color: "var(--ink-3)" } : { background: "#DCFCE7", color: "#166534" }}>
                      {pending ? "Invite pending" : !canAddInterviewers ? "Access suspended" : "Active"}
                    </span>
                  </div>
                  <p className="text-xs text-neutral-500 truncate">
                    {iv.email} · {iv.timezone} · {meetLabel}
                  </p>
                  {upcoming > 0 && (
                    <p className="text-[11px] mt-2 inline-flex items-center gap-1" style={{ color: "var(--brand)" }}>
                      <Icon name="calendar" className="w-3 h-3" /> {upcoming} upcoming interview{upcoming > 1 ? "s" : ""}
                    </p>
                  )}
                </div>
                <div className="flex flex-col items-end gap-2 shrink-0">
                  <button
                    onClick={() => setRemoving(iv)}
                    className="text-xs text-neutral-400 hover:text-red-600 transition-colors"
                  >
                    Remove
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Remove confirmation */}
      {removing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center px-4" style={{ background: "rgba(10,11,30,0.45)" }} onClick={() => setRemoving(null)}>
          <div className="w-full max-w-md rounded-2xl bg-white p-6 act-shadow" onClick={(e) => e.stopPropagation()}>
            <h3 className="text-base font-bold font-display mb-1" style={{ color: "var(--ink)" }}>Remove {removing.name}?</h3>
            {(() => {
              const sched = scheduledCountFor(removing);
              return (
                <>
                  <p className="text-sm mb-3" style={{ color: "var(--ink-2)" }}>
                    This removes the interviewer from your workspace. Your job postings aren't affected.
                  </p>
                  {sched > 0 && (
                    <div className="rounded-xl p-3 mb-4 text-sm" style={{ background: "#FFF7ED", border: "1px solid #FED7AA", color: "#9A3412" }}>
                      They have <span className="font-semibold">{sched}</span> scheduled interview{sched > 1 ? "s" : ""}. You'll need to reassign {sched > 1 ? "those" : "it"} to another interviewer.
                    </div>
                  )}
                  <div className="flex justify-end gap-2">
                    <button onClick={() => setRemoving(null)} className="text-sm rounded-xl px-4 py-2 border transition-colors hover:bg-neutral-50" style={{ borderColor: "var(--line)", color: "var(--ink-2)" }}>
                      Cancel
                    </button>
                    <button onClick={confirmRemove} className="text-sm rounded-xl px-4 py-2 bg-red-600 hover:bg-red-700 text-white font-medium transition-colors">
                      Remove interviewer
                    </button>
                  </div>
                </>
              );
            })()}
          </div>
        </div>
      )}
    </div>
  );
}

// Deterministic mock slots — five weekday afternoons/mornings spread across
// the next two weeks, standing in for what find-available-slots computes
// from real Google Calendar free/busy data + Claude's slot picks.
function generateMockSlots() {
  // Business-hours slots only: weekdays (Mon–Fri), start times between 9am
  // and 4:30pm so a 30-min slot always ends by 5pm.
  const slots = [];
  const now = new Date();
  const startHours = [9, 10, 11, 14, 15, 16]; // avoids lunch hour, all within 9–5
  let dayOffset = 1;

  while (slots.length < 5 && dayOffset < 21) {
    const d = new Date(now);
    d.setDate(d.getDate() + dayOffset);
    const weekday = d.getDay(); // 0 = Sun, 6 = Sat
    if (weekday !== 0 && weekday !== 6) {
      const hour = startHours[slots.length % startHours.length];
      d.setHours(hour, 0, 0, 0);
      const end = new Date(d.getTime() + 30 * 60000);
      slots.push({ start: d.toISOString(), end: end.toISOString() });
    }
    dayOffset++;
  }
  return slots;
}

function formatSlotDisplay(iso) {
  return new Date(iso).toLocaleString("en-US", {
    weekday: "short",
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  });
}

// Derive the list of real scheduled interviews from the shared bookings map.
// Only bookings the candidate has actually confirmed ('scheduled') count as
// upcoming interviews. Returned sorted by soonest start time.
function scheduledInterviewsFrom(bookings, candidates) {
  const rows = Object.entries(bookings || {})
    .filter(([, b]) => b && b.status === "scheduled" && b.confirmedSlot?.start)
    .map(([candidateId, b]) => {
      const cand = candidates.find((c) => c.id === candidateId);
      const start = new Date(b.confirmedSlot.start);
      return {
        candidateId,
        candidateName: cand?.parsed?.name || cand?.name || "Candidate",
        jobTitle: b.request?.jobTitle || "Interview",
        interviewerName: b.request?.interviewerName || null,
        start,
        month: start.toLocaleString("en-US", { month: "short" }),
        day: String(start.getDate()),
        time: start.toLocaleString("en-US", { hour: "numeric", minute: "2-digit" }),
        provider: (b.provider || "google") === "microsoft" ? "Teams" : "Google Meet",
      };
    })
    .sort((a, b) => a.start - b.start);
  return rows;
}

function buildQuestionPool(p, roleTitle) {
  const s0 = p.skills?.[0] ?? "your core stack";
  const s1 = p.skills?.[1] ?? "a key tool";
  const s2 = p.skills?.[2] ?? s0;
  const r0 = p.experience?.[0];
  const r1 = p.experience?.[1];
  const isFrontend = roleTitle.toLowerCase().includes("frontend") || roleTitle.toLowerCase().includes("engineer");

  const pool = [
    { category: "Technical", question: `Your resume lists ${s0} and ${s1}. For the ${roleTitle} role, walk me through a project where you combined them to ship something end-to-end.` },
    r0 && { category: "Experience", question: `At ${r0.company} you were ${r0.title}. What was the hardest technical trade-off you made there, and how would it apply to what we're building?` },
    { category: "Role fit", question: `This role leans on ${isFrontend ? "design systems and component architecture" : "the core responsibilities in the posting"}. Where's the biggest gap between your current experience and what this role needs?` },
    { category: "Behavioral", question: `Tell me about a time you disagreed with a teammate on an approach. How did you resolve it?` },
    { category: "Depth check", question: `You mention ${s0} — go deep on a limitation you've hit with it in production and how you worked around it.` },
    { category: "Technical", question: `How do you decide when to reach for ${s1} versus building something yourself? Give a recent example.` },
    r1 && { category: "Experience", question: `Before ${r0?.company ?? "your last role"}, you were at ${r1.company}. What made you move on, and what did you carry forward?` },
    { category: "Role fit", question: `What would your first 30 days in the ${roleTitle} role look like if you wanted to make an early impact?` },
    { category: "Behavioral", question: `Describe a project that slipped or failed. What did you learn, and what would you do differently?` },
    { category: "Technical", question: `Walk me through how you'd debug a performance regression that only shows up in production, using ${s2}.` },
    { category: "Collaboration", question: `How do you handle handoffs with design and backend? What does a smooth one look like to you?` },
    { category: "Depth check", question: `If I gave you a legacy ${s0} codebase with no tests, what's your first week look like?` },
    { category: "Motivation", question: `Why this role specifically, and why now? What are you hoping to grow into?` },
    { category: "Technical", question: `What's an opinion you hold about ${s1} that not everyone on your team shared?` },
    { category: "Role fit", question: `How do you keep up with changes in ${s0} and the wider ecosystem?` },
  ].filter(Boolean);

  // Group by category in a sensible order so questions read as coherent
  // sections (and stay grouped as more are revealed), not a jumbled mix.
  const CATEGORY_ORDER = ["Technical", "Depth check", "Experience", "Role fit", "Behavioral", "Collaboration", "Motivation"];
  pool.sort((a, b) => {
    const d = CATEGORY_ORDER.indexOf(a.category) - CATEGORY_ORDER.indexOf(b.category);
    return d !== 0 ? d : 0;
  });

  return pool;
}

function InterviewQuestionsPanel({ candidate, jobs, contextJobId, isScheduled }) {
  const openJobs = jobs.filter((j) => j.status === "open");
  const fixedJob = contextJobId ? jobs.find((j) => j.id === contextJobId) : null;
  const [jobId, setJobId] = useState(fixedJob?.id ?? openJobs[0]?.id ?? "");
  const [pool, setPool] = useState(null);
  const [visibleCount, setVisibleCount] = useState(5);
  const [generating, setGenerating] = useState(false);
  const [loadingMore, setLoadingMore] = useState(false);
  const [copiedIdx, setCopiedIdx] = useState(null);
  const [copiedAll, setCopiedAll] = useState(false);

  const inputClass = "w-full rounded-xl bg-neutral-100 border border-neutral-200 px-3 py-2 text-neutral-900 text-sm focus:outline-none focus:ring-2 focus:ring-neutral-400";
  const activeJob = fixedJob ?? openJobs.find((j) => j.id === jobId);
  const p = candidate.parsed;

  const generate = () => {
    setGenerating(true);
    setTimeout(() => {
      setPool(buildQuestionPool(p, activeJob?.title ?? "this role"));
      setVisibleCount(5);
      setGenerating(false);
    }, 1000);
  };

  const loadMore = () => {
    setLoadingMore(true);
    setTimeout(() => {
      setVisibleCount((n) => n + 5);
      setLoadingMore(false);
    }, 500);
  };

  const copyText = (text) => {
    // Clipboard API may be unavailable in the preview sandbox; fall back quietly.
    try {
      navigator.clipboard?.writeText(text);
    } catch (e) {}
  };

  const copyOne = (q, i) => {
    copyText(`[${q.category}] ${q.question}`);
    setCopiedIdx(i);
    setTimeout(() => setCopiedIdx(null), 1500);
  };

  const copyAll = () => {
    const visible = pool.slice(0, visibleCount);
    const notes = `Interview questions — ${p.name}${activeJob ? ` · ${activeJob.title}` : ""}\n\n` +
      visible.map((q, i) => `${i + 1}. [${q.category}] ${q.question}`).join("\n");
    copyText(notes);
    setCopiedAll(true);
    setTimeout(() => setCopiedAll(false), 1500);
  };

  // Questions only become available once the interview is actually scheduled.
  if (!isScheduled) {
    return (
      <div className="mb-6 rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]">
        <h2 className="text-sm font-medium text-neutral-600 uppercase tracking-wide mb-1">Interview Questions</h2>
        <div className="flex items-start gap-2 mt-2">
          <Icon name="clock" className="w-4 h-4 text-neutral-400 mt-0.5 shrink-0" />
          <p className="text-sm text-neutral-500">
            Available once the interview is scheduled. Book a time above and tailored questions for {p.name} will appear here.
          </p>
        </div>
      </div>
    );
  }

  const visible = pool ? pool.slice(0, visibleCount) : [];
  const hasMore = pool && visibleCount < pool.length;

  return (
    <div className="mb-6 rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]">
      <div className="flex items-center justify-between mb-1">
        <div className="flex items-center gap-1.5">
          <h2 className="text-sm font-medium text-neutral-600 uppercase tracking-wide">Interview Questions</h2>
          <InfoHint dir="down" hint="AI drafts these questions from this candidate's resume and the role, so you can tailor the interview before you meet." />
        </div>
        {pool && (
          <div className="flex items-center gap-3">
            <button onClick={copyAll} className="text-xs text-neutral-600 hover:text-neutral-900">
              {copiedAll ? "Copied ✓" : "Copy all to notes"}
            </button>
            <button onClick={generate} disabled={generating} className="text-xs text-indigo-600 hover:text-indigo-700">
              {generating ? "Regenerating…" : "Regenerate"}
            </button>
          </div>
        )}
      </div>
      <p className="text-sm text-neutral-500 mb-3">
        Tailored to {p.name}'s experience{activeJob ? ` and the ${activeJob.title} role` : ""}.
      </p>

      {!fixedJob && openJobs.length > 0 && !pool && (
        <div className="mb-3">
          <label className="block text-xs text-neutral-500 mb-1">Role</label>
          <select value={jobId} onChange={(e) => setJobId(e.target.value)} className={inputClass}>
            {openJobs.map((j) => (
              <option key={j.id} value={j.id}>{j.title}</option>
            ))}
          </select>
        </div>
      )}

      {!pool ? (
        <button
          onClick={generate}
          disabled={generating || !activeJob}
          className="rounded-xl brand-gradient hover:opacity-90 disabled:opacity-50 text-white text-sm font-medium shadow-[0_6px_16px_-8px_rgba(151,59,247,0.7)] px-4 py-2 transition-colors"
        >
          {generating ? "Generating…" : "Generate interview questions"}
        </button>
      ) : (
        <>
          <div className="space-y-4">
            {(() => {
              // Build contiguous category groups from the visible (category-sorted) slice.
              const groups = [];
              visible.forEach((q, i) => {
                const item = { ...q, flatIndex: i };
                const last = groups[groups.length - 1];
                if (last && last.category === q.category) last.items.push(item);
                else groups.push({ category: q.category, items: [item] });
              });
              return groups.map((g, gi) => (
                <div key={gi}>
                  <p className="text-xs font-semibold uppercase tracking-wide mb-2" style={{ color: "var(--brand)" }}>{g.category}</p>
                  <div className="space-y-2">
                    {g.items.map((q) => (
                      <div key={q.flatIndex} className="rounded-xl border border-neutral-200 bg-neutral-50 px-4 py-3">
                        <div className="flex items-start justify-between gap-3">
                          <p className="text-sm text-neutral-800 min-w-0">{q.question}</p>
                          <button
                            onClick={() => copyOne(q, q.flatIndex)}
                            className="text-xs text-neutral-400 hover:text-neutral-700 shrink-0 mt-0.5"
                            title="Copy question"
                          >
                            {copiedIdx === q.flatIndex ? "Copied ✓" : "Copy"}
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ));
            })()}
          </div>

          <div className="flex items-center gap-3 mt-4">
            {hasMore && (
              <button
                onClick={loadMore}
                disabled={loadingMore}
                className="text-sm rounded-xl border border-neutral-200 px-4 py-2 text-neutral-700 hover:border-neutral-300 disabled:opacity-50 transition-colors"
              >
                {loadingMore ? "Loading…" : "Load more questions"}
              </button>
            )}
            <span className="text-xs text-neutral-400">{visible.length} of {pool.length}</span>
          </div>
        </>
      )}
    </div>
  );
}

function ScheduleInterviewPanel({ candidate, jobs, interviewers, onPreviewBooking, contextJobId, booking, onInviteSent, provider = "google", calendarConnected = false }) {
  const openJobs = jobs.filter((j) => j.status === "open");
  // If opened from a specific job's applicant list, that job is fixed and
  // there's no need to pick one. Otherwise let HR choose the open role.
  const fixedJob = contextJobId ? jobs.find((j) => j.id === contextJobId) : null;
  const [jobId, setJobId] = useState(fixedJob?.id ?? openJobs[0]?.id ?? "");
  const [interviewerId, setInterviewerId] = useState(interviewers[0]?.id ?? "");
  const meetName = provider === "microsoft" ? "Teams" : "Google Meet";
  const [attendeePick, setAttendeePick] = useState("");
  const [additionalAttendees, setAdditionalAttendees] = useState([]); // array of interviewer ids
  const [finding, setFinding] = useState(false);
  const [sending, setSending] = useState(false);
  const [request, setRequest] = useState(null);
  const [selectedSlots, setSelectedSlots] = useState([]); // ISO start strings HR chose to send

  const inputClass = "w-full rounded-xl bg-neutral-100 border border-neutral-200 px-3 py-2 text-neutral-900 text-sm focus:outline-none focus:ring-2 focus:ring-neutral-400";
  const selectedInterviewer = interviewers.find((iv) => iv.id === interviewerId);
  const activeJobTitle = fixedJob?.title ?? openJobs.find((j) => j.id === jobId)?.title;

  // Shared booking (from the root) is the source of truth once an invite has
  // gone out — it survives navigating to the candidate's booking page and back,
  // and reflects the candidate confirming a time.
  const bookingStatus = booking?.status; // undefined | 'sent' | 'scheduled'
  const sentRequest = booking?.request;

  // Attendees can only be interviewers already set up in the system, and not
  // the primary interviewer already on the invite.
  const attendeeOptions = interviewers.filter(
    (iv) => iv.id !== interviewerId && !additionalAttendees.includes(iv.id)
  );
  const attendeeName = (id) => interviewers.find((iv) => iv.id === id)?.name ?? id;

  const addAttendee = () => {
    if (!attendeePick || additionalAttendees.includes(attendeePick)) return;
    setAdditionalAttendees((prev) => [...prev, attendeePick]);
    setAttendeePick("");
  };

  const removeAttendee = (id) => setAdditionalAttendees((prev) => prev.filter((a) => a !== id));

  const toggleSlot = (start) =>
    setSelectedSlots((prev) => (prev.includes(start) ? prev.filter((s) => s !== start) : [...prev, start]));

  const handleFindSlots = () => {
    setFinding(true);
    setTimeout(() => {
      const slots = generateMockSlots();
      setRequest({
        id: `req-${candidate.id}`,
        candidateId: candidate.id,
        status: "draft",
        slot_duration_minutes: 30,
        proposed_slots: slots,
        jobTitle: activeJobTitle,
        interviewerName: selectedInterviewer?.name,
      });
      // Pre-select all AI-suggested slots; HR can deselect the ones they don't want.
      setSelectedSlots(slots.map((s) => s.start));
      setFinding(false);
    }, 1500);
  };

  const handleSendInvite = () => {
    setSending(true);
    setTimeout(() => {
      // Only the slots HR kept selected are sent to the candidate.
      const chosen = request.proposed_slots.filter((s) => selectedSlots.includes(s.start));
      const sent = { ...request, status: "sent", proposed_slots: chosen };
      setRequest(sent);
      // Lift to shared booking so the profile + booking page stay in sync.
      if (onInviteSent) onInviteSent(candidate.id, sent);
      setSending(false);
    }, 1200);
  };

  return (
    <div className="mb-6 rounded-2xl border border-indigo-200 bg-indigo-50 px-5 py-4">
      <h2 className="text-sm font-medium text-indigo-700 mb-1">AI Auto Schedule</h2>
      <p className="text-sm text-neutral-600 mb-3">
        {fixedJob
          ? `Scheduling for the ${fixedJob.title} role. `
          : ""}
        Finds the interviewer's free calendar slots, sends the candidate a link to pick one, then
        creates the calendar event and Meet link automatically — no back-and-forth.
      </p>

      {bookingStatus === "scheduled" ? (
        <div className="rounded-xl bg-white border border-emerald-200 px-4 py-3">
          <p className="text-sm text-emerald-600 font-medium">Interview scheduled ✓</p>
          <p className="text-sm text-neutral-700 mt-0.5">
            {formatSlotDisplay(booking.confirmedSlot.start)}
            {sentRequest?.interviewerName ? ` with ${sentRequest.interviewerName}` : ""}
            {sentRequest?.jobTitle ? ` · ${sentRequest.jobTitle}` : ""}
          </p>
          <p className="text-xs text-neutral-400 mt-1">
            The candidate confirmed this time. Calendar invite and video link have been sent to everyone.
          </p>
        </div>
      ) : bookingStatus === "sent" ? (
        <div className="rounded-xl bg-white border border-neutral-200 px-4 py-3">
          <p className="text-xs text-neutral-500 mb-1">Sent these times ({sentRequest.proposed_slots.length}):</p>
          <div className="flex flex-wrap gap-2 mb-2">
            {sentRequest.proposed_slots.map((slot) => (
              <span key={slot.start} className="text-xs rounded-full bg-neutral-100 border border-neutral-200 px-3 py-1 text-neutral-700">
                {formatSlotDisplay(slot.start)}
              </span>
            ))}
          </div>
          <p className="text-sm text-amber-600">Invite sent — waiting for the candidate to pick a time.</p>
          <button
            onClick={() => onPreviewBooking(sentRequest)}
            className="text-sm text-indigo-600 hover:text-indigo-700 mt-1"
          >
            Preview the candidate's booking page →
          </button>
        </div>
      ) : !fixedJob && openJobs.length === 0 ? (
        <p className="text-sm text-neutral-500">No open jobs to schedule against.</p>
      ) : interviewers.length === 0 ? (
        <p className="text-sm text-neutral-500">No interviewers set up yet.</p>
      ) : (
        <>
          {!fixedJob && (
            <div className="mb-3">
              <label className="block text-xs text-neutral-500 mb-1">Role</label>
              <select value={jobId} onChange={(e) => setJobId(e.target.value)} className={inputClass}>
                {openJobs.map((j) => (
                  <option key={j.id} value={j.id}>{j.title}</option>
                ))}
              </select>
            </div>
          )}

          <div className="mb-3">
            <label className="block text-xs text-neutral-500 mb-1">Interviewer</label>
            <select value={interviewerId} onChange={(e) => setInterviewerId(e.target.value)} className={inputClass}>
              {interviewers.map((iv) => (
                <option key={iv.id} value={iv.id}>
                  {iv.name}
                </option>
              ))}
            </select>
          </div>

          <div className="mb-3">
            <label className="block text-xs text-neutral-500 mb-1">
              Additional interviewers <span className="text-neutral-400">(optional)</span>
            </label>
            {attendeeOptions.length > 0 ? (
              <div className="flex gap-2">
                <select
                  value={attendeePick}
                  onChange={(e) => setAttendeePick(e.target.value)}
                  className={inputClass}
                >
                  <option value="">Select an interviewer…</option>
                  {attendeeOptions.map((iv) => (
                    <option key={iv.id} value={iv.id}>
                      {iv.name} · {meetName}
                    </option>
                  ))}
                </select>
                <button
                  type="button"
                  onClick={addAttendee}
                  disabled={!attendeePick}
                  className="rounded-xl bg-neutral-100 hover:bg-neutral-200 disabled:opacity-50 text-neutral-700 text-sm px-3 py-2 shrink-0 transition-colors"
                >
                  Add
                </button>
              </div>
            ) : (
              <p className="text-xs text-neutral-400">
                No other interviewers available. Add more in the Interviewers section.
              </p>
            )}
            {additionalAttendees.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {additionalAttendees.map((id) => (
                  <span key={id} className="inline-flex items-center gap-1 text-xs rounded-full bg-neutral-100 border border-neutral-200 px-3 py-1 text-neutral-700">
                    {attendeeName(id)}
                    <button type="button" onClick={() => removeAttendee(id)} className="text-neutral-400 hover:text-neutral-700">✕</button>
                  </span>
                ))}
              </div>
            )}
            <p className="text-xs text-neutral-400 mt-1">
              Only interviewers already in the system can be added. They'll join the calendar invite and {meetName} link once the candidate picks a time.
            </p>
          </div>

          {!request ? (
            <div>
              {!calendarConnected && (
                <p className="text-xs mb-2" style={{ color: "#B45309" }}>
                  Connect your workspace calendar in Settings to find available times.
                </p>
              )}
              <button
                onClick={handleFindSlots}
                disabled={finding || !calendarConnected}
                className="rounded-xl brand-gradient hover:opacity-90 disabled:opacity-50 text-white text-sm font-medium shadow-[0_6px_16px_-8px_rgba(151,59,247,0.7)] px-4 py-2 transition-colors"
              >
                {finding ? "Finding slots…" : "Find available slots"}
              </button>
            </div>
          ) : (
            <div>
              <div className="flex items-center justify-between mb-2">
                <p className="text-xs text-neutral-500">
                  Tap to choose which times to offer the candidate ({selectedSlots.length} selected)
                </p>
                <button
                  onClick={() =>
                    setSelectedSlots(
                      selectedSlots.length === request.proposed_slots.length
                        ? []
                        : request.proposed_slots.map((s) => s.start)
                    )
                  }
                  className="text-xs text-indigo-600 hover:text-indigo-700 shrink-0"
                >
                  {selectedSlots.length === request.proposed_slots.length ? "Clear all" : "Select all"}
                </button>
              </div>
              {additionalAttendees.length > 0 && (
                <p className="text-xs text-neutral-500 mb-2">Also inviting: {additionalAttendees.map(attendeeName).join(", ")}</p>
              )}
              <div className="flex flex-wrap gap-2 mb-3">
                {request.proposed_slots.map((slot) => {
                  const on = selectedSlots.includes(slot.start);
                  return (
                    <button
                      key={slot.start}
                      onClick={() => toggleSlot(slot.start)}
                      className={`inline-flex items-center gap-1.5 text-xs rounded-full px-3 py-1.5 border transition-colors ${
                        on
                          ? "bg-indigo-600 border-indigo-600 text-white"
                          : "bg-white border-neutral-200 text-neutral-700 hover:border-neutral-300"
                      }`}
                    >
                      {on && <span>✓</span>}
                      {formatSlotDisplay(slot.start)}
                    </button>
                  );
                })}
              </div>

              <button
                onClick={handleSendInvite}
                disabled={sending || selectedSlots.length === 0}
                className="rounded-xl brand-gradient hover:opacity-90 disabled:opacity-50 text-white text-sm font-medium shadow-[0_6px_16px_-8px_rgba(151,59,247,0.7)] px-4 py-2 transition-colors"
              >
                {sending
                  ? "Sending…"
                  : `Send ${selectedSlots.length} time${selectedSlots.length === 1 ? "" : "s"} to candidate`}
              </button>
            </div>
          )}
        </>
      )}
    </div>
  );
}

function SchedulePickerScreen({ navigate, request, onConfirm }) {
  const [stage, setStage] = useState("picking"); // picking | confirming | confirmed
  const [confirmedSlot, setConfirmedSlot] = useState(null);
  const meetingLink = "https://meet.google.com/abc-defg-hij";

  if (!request) {
    return (
      <div className="px-4 sm:px-6 py-8 sm:py-10">
        <div className="max-w-2xl mx-auto">
          <BackLink onClick={() => navigate("dashboard")}>← Dashboard</BackLink>
          <p className="text-sm text-neutral-500 mt-4">No active booking link to preview.</p>
        </div>
      </div>
    );
  }

  const handlePick = (slot) => {
    setStage("confirming");
    setTimeout(() => {
      setConfirmedSlot(slot);
      setStage("confirmed");
      // Propagate the confirmation back so the profile locks scheduling and
      // unlocks interview questions.
      if (onConfirm) onConfirm(slot);
    }, 1200);
  };

  if (stage === "confirmed" && confirmedSlot) {
    return (
      <div className="px-4 sm:px-6 py-8 sm:py-10">
        <div className="max-w-2xl mx-auto">
          <BackLink onClick={() => navigate(-1)}>← Exit preview (admin only)</BackLink>
          <div className="text-center max-w-sm mx-auto mt-10">
            <div className="w-12 h-12 rounded-full bg-emerald-50 border border-emerald-200 flex items-center justify-center mx-auto mb-4">
              <span className="text-emerald-600 text-xl">✓</span>
            </div>
            <h1 className="text-lg font-bold font-display mb-2" style={{ color: "var(--ink)" }}>Interview confirmed</h1>
            <p className="text-sm text-neutral-600 mb-3">{formatSlotDisplay(confirmedSlot.start)}</p>
            <p className="text-sm text-neutral-600 mb-4">
              A calendar invite has been sent to your email with the video call link.
            </p>
            <a
              href={meetingLink}
              target="_blank"
              rel="noopener noreferrer"
              className="inline-block rounded-xl bg-neutral-900 hover:bg-neutral-800 text-white text-sm font-medium px-4 py-2 transition-colors"
            >
              Meeting link
            </a>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="px-4 sm:px-6 py-8 sm:py-10">
      <div className="max-w-xl mx-auto">
        <BackLink onClick={() => navigate(-1)}>← Exit preview (admin only)</BackLink>
        <div className="mt-6 rounded-xl border border-indigo-200 bg-indigo-50 px-4 py-2 mb-6">
          <p className="text-xs text-indigo-700">
            Below is what the candidate sees. A public page, no login, reached only through the job's link.
          </p>
        </div>
        <h1 className="text-xl sm:text-2xl font-bold font-display mb-1" style={{ color: "var(--ink)" }}>Interview: {request.jobTitle}</h1>
        <p className="text-sm text-neutral-600 mb-6">
          With {request.interviewerName} · {request.slot_duration_minutes} minutes. Choose whichever time works best for you.
        </p>

        <div className="space-y-2">
          {request.proposed_slots.map((slot) => (
            <button
              key={slot.start}
              onClick={() => handlePick(slot)}
              disabled={stage === "confirming"}
              className="block w-full text-left rounded-2xl bg-white act-shadow card-hover disabled:opacity-50 px-5 py-4 border border-[color:var(--line)]"
            >
              <p className="text-neutral-900 font-medium">{formatSlotDisplay(slot.start)}</p>
            </button>
          ))}
        </div>

        {stage === "confirming" && <p className="text-sm text-neutral-500 mt-4">Confirming your slot…</p>}
      </div>
    </div>
  );
}

// Shown one after another while the resume is being read, so a longer parse
// (the AI also looks companies up on the web) clearly reads as "working", not stuck.
const PROCESSING_STEPS = [
  "Reading your resume…",
  "Pulling out your skills and experience…",
  "Looking up the companies you've worked at…",
  "Setting up your profile…",
  "Almost there…",
];

function ApplyScreen({ navigate, job, paused = false, hiredEmails = new Set(), onApplied }) {
  // Public, no-login page a candidate reaches via the job's application link.
  // Flow: review job → upload a PDF resume → submit → AI parses → profile created.
  const [file, setFile] = useState(null);
  const [fileError, setFileError] = useState(null);
  const [confirmed, setConfirmed] = useState(false); // gates the upload
  const [stage, setStage] = useState("form"); // form | processing | done
  const [submitErr, setSubmitErr] = useState(null);
  const [procStep, setProcStep] = useState(0);

  // Advance the status line while processing (holds on the last one).
  useEffect(() => {
    if (stage !== "processing") { setProcStep(0); return; }
    const id = setInterval(() => setProcStep((i) => Math.min(i + 1, PROCESSING_STEPS.length - 1)), 4000);
    return () => clearInterval(id);
  }, [stage]);

  // Accept either an array of bullets or a legacy string; always return an array.
  const toList = (v) =>
    Array.isArray(v) ? v.filter(Boolean) : typeof v === "string" && v.trim() ? v.split("\n").map((s) => s.trim()).filter(Boolean) : [];

  if (!job) {
    return (
      <div className="px-4 sm:px-6 py-8 sm:py-10">
        <div className="max-w-2xl mx-auto">
          <BackLink onClick={() => navigate("dashboard")}>← Dashboard</BackLink>
          <p className="text-sm text-neutral-500 mt-4">No job selected to preview the application page.</p>
        </div>
      </div>
    );
  }

  const salary = formatSalary(job);
  const meta = [job.department, job.location, job.employment_type?.replace("_", "-"), job.remote_type, job.seniority_level, salary].filter(Boolean);

  // Paused job (over the owner's plan limit): the public link still resolves,
  // but it stops taking applications until the owner reactivates. Nothing breaks.
  if (paused) {
    return (
      <div className="px-4 sm:px-6 py-8 sm:py-10">
        <div className="max-w-xl mx-auto">
          <BackLink onClick={() => navigate(-1)}>← Exit preview (admin only)</BackLink>
          <div className="mt-6 rounded-xl border p-3 mb-6 flex items-center justify-between gap-3" style={{ borderColor: "#FCD34D", background: "#FFFBEB" }}>
            <p className="text-xs" style={{ color: "#92400E" }}>
              Admin view: this role is paused because you're over your plan's job limit. Candidates who open the link see the message below, and applications stay closed until you reactivate.
            </p>
            <button onClick={() => navigate("billing")} className="text-xs brand-gradient text-white font-medium px-3 py-1.5 rounded-lg shrink-0 hover:opacity-90 transition-opacity">Reactivate</button>
          </div>
          <div className="text-center max-w-sm mx-auto mt-8">
            <div className="w-12 h-12 rounded-full bg-neutral-100 border border-neutral-200 flex items-center justify-center mx-auto mb-4">
              <span className="text-neutral-400 text-xl">⏸</span>
            </div>
            <h1 className="text-lg font-bold font-display mb-2" style={{ color: "var(--ink)" }}>Applications paused</h1>
            <p className="text-sm mb-1" style={{ color: "var(--ink-2)" }}>
              <span className="font-medium" style={{ color: "var(--ink)" }}>{job.title}</span> isn't taking applications right now.
            </p>
            <p className="text-sm" style={{ color: "var(--ink-3)" }}>
              Check back soon, or take a look at our other open roles.
            </p>
          </div>
        </div>
      </div>
    );
  }

  // Closed jobs can't take new applications — the public link shows a notice.
  if (job.status !== "open") {
    return (
      <div className="px-4 sm:px-6 py-8 sm:py-10">
        <div className="max-w-xl mx-auto">
          <BackLink onClick={() => navigate(-1)}>← Exit preview (admin only)</BackLink>
          <div className="mt-6 rounded-xl border border-indigo-200 bg-indigo-50 px-4 py-2 mb-6">
            <p className="text-xs text-indigo-700">
This is what a candidate sees if they open the link after the role has closed.
            </p>
          </div>
          <div className="text-center max-w-sm mx-auto mt-8">
            <div className="w-12 h-12 rounded-full bg-neutral-100 border border-neutral-200 flex items-center justify-center mx-auto mb-4">
              <span className="text-neutral-400 text-xl">🔒</span>
            </div>
            <h1 className="text-lg font-bold font-display mb-2" style={{ color: "var(--ink)" }}>Position closed</h1>
            <p className="text-sm mb-1" style={{ color: "var(--ink-2)" }}>
              <span className="font-medium" style={{ color: "var(--ink)" }}>{job.title}</span> has closed and isn't taking applications.
            </p>
            <p className="text-sm" style={{ color: "var(--ink-3)" }}>
              Thanks for your interest. Keep an eye on our careers page for future openings.
            </p>
          </div>
        </div>
      </div>
    );
  }

  const isPdf = (f) => f && (f.type === "application/pdf" || /\.pdf$/i.test(f.name));

  const MAX_MB = 10; // resumes are tiny; anything bigger is usually not a CV
  const handleFile = (e) => {
    const f = e.target.files?.[0];
    if (!f) return;
    if (!isPdf(f)) {
      setFile(null);
      setFileError("That's not a PDF. Upload your resume as a PDF file.");
      return;
    }
    if (f.size > MAX_MB * 1024 * 1024) {
      setFile(null);
      setFileError(`That file is ${(f.size / 1048576).toFixed(0)} MB, which is large for a resume. Upload a PDF under ${MAX_MB} MB.`);
      return;
    }
    setFileError(null);
    setSubmitErr(null);
    setFile(f);
  };

  const canSubmit = file && isPdf(file) && confirmed && stage === "form";

  // A real job carries a uuid id; demo jobs use "j…" ids we never send to the DB.
  const isRealJob = (id) => typeof id === "string" && /^[0-9a-f]{8}-[0-9a-f]{4}-/i.test(id);
  // PDF file → base64 (without the data: prefix) for the parser function.
  const fileToBase64 = (f) => new Promise((resolve, reject) => {
    const r = new FileReader();
    r.onload = () => resolve(String(r.result).split(",")[1] || "");
    r.onerror = reject;
    r.readAsDataURL(f);
  });
  const handleSubmit = async () => {
    if (!canSubmit) return;
    setSubmitErr(null);
    setStage("processing");

    // Demo mode (no keys / preview of a demo job): simulate parsing.
    if (!hasSupabase || !isRealJob(job?.id)) {
      setTimeout(() => setStage("done"), 2200);
      return;
    }

    // The edge function reads the PDF with Claude, pulls out the applicant's
    // details, rejects anything that isn't a resume, and files the application.
    try {
      const resume_base64 = await fileToBase64(file);
      const { data, error } = await supabase.functions.invoke("parse-application", {
        body: { job_id: job.id, resume_base64, filename: file?.name || null, source: "Career Page" },
      });
      // On a non-2xx status, invoke returns `error` and the JSON body (with our
      // reason code) sits on error.context, not in `data`. Read both.
      let code = data?.error || "";
      if (!code && error?.context?.json) {
        try { const body = await error.context.json(); code = body?.error || ""; } catch { /* ignore */ }
      }
      if (error || code) {
        if (code === "not_a_resume") { setSubmitErr("That file doesn't look like a resume. Upload your CV as a PDF and try again."); setStage("form"); return; }
        if (code === "no_email") { setSubmitErr("We couldn't find an email on your resume. Add your email to the CV and upload again so the team can reach you."); setStage("form"); return; }
        if (/job not open/i.test(code)) { setSubmitErr("This role isn't taking applications anymore."); setStage("form"); return; }
        throw new Error(code || error?.message || "failed");
      }
      onApplied && onApplied();
      setStage("done");
    } catch (_e) {
      setSubmitErr("We couldn't read your resume just then. Give it another try.");
      setStage("form");
    }
  };

  const inputClass = "w-full rounded-xl bg-neutral-100 border border-neutral-200 px-3 py-2 text-neutral-900 text-sm focus:outline-none focus:ring-2 focus:ring-neutral-400";

  return (
    <div className="px-4 sm:px-6 py-8 sm:py-10">
      <div className="max-w-xl mx-auto">
        <BackLink onClick={() => navigate(-1)}>← Exit preview (admin only)</BackLink>
        <div className="mt-6 rounded-xl border border-indigo-200 bg-indigo-50 px-4 py-2 mb-6">
          <p className="text-xs text-indigo-700">
This is what a candidate sees. A public page, no login, reached only through the job's application link.
          </p>
        </div>

        {stage === "done" ? (
          <div className="text-center max-w-sm mx-auto mt-8">
            <div className="w-12 h-12 rounded-full bg-emerald-50 border border-emerald-200 flex items-center justify-center mx-auto mb-4">
              <span className="text-emerald-600 text-xl">✓</span>
            </div>
            <h1 className="text-lg font-bold font-display mb-2" style={{ color: "var(--ink)" }}>You're in</h1>
            <p className="text-sm mb-1" style={{ color: "var(--ink-2)" }}>
              Aster has read your resume and added you as an applicant for <span className="font-medium" style={{ color: "var(--ink)" }}>{job.title}</span>.
            </p>
            <p className="text-sm" style={{ color: "var(--ink-3)" }}>
              The team reviews every applicant and will be in touch if there's a fit. Look out for a confirmation in your inbox.
            </p>
          </div>
        ) : (
          <>
            {/* Job details */}
            <h1 className="text-xl sm:text-2xl font-bold font-display mb-1" style={{ color: "var(--ink)" }}>{job.title}</h1>
            {meta.length > 0 && <p className="text-sm mb-4" style={{ color: "var(--ink-3)" }}>{meta.join(" · ")}</p>}

            {/* Key facts */}
            <div className="rounded-2xl bg-white border border-[color:var(--line)] p-4 mb-5 grid grid-cols-2 sm:grid-cols-4 gap-3">
              {[
                ["Salary", salary || "Not disclosed"],
                ["Type", (job.employment_type || "").replace(/_/g, " ") || "—"],
                ["Location", job.location || "—"],
                ["Work style", job.remote_type || "—"],
              ].map(([k, v]) => (
                <div key={k}>
                  <p className="text-[11px] uppercase tracking-wide" style={{ color: "var(--ink-3)" }}>{k}</p>
                  <p className="text-sm font-medium capitalize" style={{ color: "var(--ink)" }}>{v}</p>
                </div>
              ))}
            </div>

            {job.description && <p className="text-sm mb-6 leading-relaxed" style={{ color: "var(--ink-2)" }}>{job.description}</p>}

            {[
              ["What you'll do", toList(job.responsibilities)],
              ["What we're looking for", toList(job.requirements)],
              ["What we offer", toList(job.benefits)],
            ].map(([heading, items]) =>
              items.length > 0 ? (
                <div key={heading} className="mb-6">
                  <h2 className="text-sm font-semibold font-display mb-2" style={{ color: "var(--ink)" }}>{heading}</h2>
                  <ul className="space-y-1.5">
                    {items.map((it, i) => (
                      <li key={i} className="text-sm flex gap-2 leading-relaxed" style={{ color: "var(--ink-2)" }}>
                        <span className="shrink-0" style={{ color: "var(--brand)" }}>•</span> {it}
                      </li>
                    ))}
                  </ul>
                </div>
              ) : null
            )}

            <div className="rounded-2xl bg-white border border-[color:var(--line)] p-5">
              <h2 className="text-sm font-semibold font-display mb-4" style={{ color: "var(--ink)" }}>Apply for this role</h2>

              <p className="text-sm mb-4" style={{ color: "var(--ink-2)" }}>
                No forms to fill in. Upload your resume and Aster reads your name, contact details and experience straight from it.
              </p>

              <div className="space-y-3">
                {/* Confirmation gate: the upload only unlocks once this is ticked. */}
                <label className="flex items-start gap-2.5 cursor-pointer select-none">
                  <input
                    type="checkbox"
                    checked={confirmed}
                    onChange={(e) => setConfirmed(e.target.checked)}
                    disabled={stage !== "form"}
                    className="mt-0.5 h-4 w-4 shrink-0 rounded accent-[color:var(--brand)]"
                  />
                  <span className="text-sm leading-snug" style={{ color: "var(--ink-2)" }}>
                    This is my resume, and it includes my current email so the team can reach me about this role.
                  </span>
                </label>

                <div className={confirmed ? "" : "opacity-50 pointer-events-none"}>
                  <label className="block text-xs mb-1" style={{ color: "var(--ink-2)" }}>Resume (PDF only)</label>
                  <label className={`block rounded-xl border border-dashed px-4 py-6 text-center cursor-pointer transition-colors ${stage !== "form" ? "opacity-60 pointer-events-none" : "hover:bg-neutral-50"}`} style={{ borderColor: "var(--line-strong)" }}>
                    <input type="file" accept="application/pdf,.pdf" onChange={handleFile} className="hidden" disabled={stage !== "form" || !confirmed} />
                    {file ? (
                      <span className="text-sm" style={{ color: "var(--ink)" }}>{file.name}</span>
                    ) : (
                      <span className="text-sm" style={{ color: "var(--ink-3)" }}>Tap to choose your resume. PDF only.</span>
                    )}
                  </label>
                  {!confirmed && <p className="text-xs mt-1.5" style={{ color: "var(--ink-3)" }}>Tick the box above to turn on the upload.</p>}
                  {fileError && <p className="text-xs text-rose-600 mt-1.5">{fileError}</p>}
                </div>
              </div>

              {submitErr && <p className="text-xs text-rose-600 mt-4 text-center">{submitErr}</p>}

              <button
                onClick={handleSubmit}
                disabled={!canSubmit}
                className="w-full mt-5 rounded-xl brand-gradient disabled:opacity-40 text-white text-sm font-semibold px-4 py-2.5 transition-opacity hover:opacity-90"
              >
                {stage === "processing" ? PROCESSING_STEPS[procStep] : "Submit application"}
              </button>

              {stage === "processing" && (
                <p className="text-xs text-center mt-3" style={{ color: "var(--ink-3)" }}>
                  This isn't stuck. Aster is reading your resume and looking up the companies you've worked at. It can take up to a minute, so please keep this page open.
                </p>
              )}
            </div>
          </>
        )}
      </div>
    </div>
  );
}


function BillingScreen({ navigate, plan, setPlan, planCycle = "monthly", setPlanCycle, company, jobs = [], interviewers = [], keptJobId, setKeptJobId, trialDaysLeft = 0, onEndTrial }) {
  const [msg, setMsg] = useState(null);
  // The cycle the user is *previewing* in the picker (defaults to their saved cycle).
  const [cycle, setCycle] = useState(planCycle);
  const [showDowngrade, setShowDowngrade] = useState(false);
  const [keepJob, setKeepJob] = useState(keptJobId || (jobs[0] && jobs[0].id) || null);

  // USD pricing. Yearly is 20% off the annualised monthly price. Prices are
  // charged in USD; applicable taxes are added at checkout by billing country.
  const PRICES = {
    starter: {
      monthly: { price: "$89", cadence: "per month", renewCopy: "$89/month", nextAmount: "$89.00", invAmount: "$89.00", invDesc: "Pro — monthly" },
      yearly: { price: "$71", cadence: "per month, billed yearly", renewCopy: "$852/year", nextAmount: "$852.00", invAmount: "$852.00", invDesc: "Pro — yearly" },
    },
    professional: {
      monthly: { price: "$199", cadence: "per month", renewCopy: "$199/month", nextAmount: "$199.00", invAmount: "$199.00", invDesc: "Premium — monthly" },
      yearly: { price: "$159", cadence: "per month, billed yearly", renewCopy: "$1,908/year", nextAmount: "$1,908.00", invAmount: "$1,908.00", invDesc: "Premium — yearly" },
    },
  };
  const rmHint = { starter: {}, professional: {} };
  // Saved plan's billing detail (undefined for free/enterprise).
  const saved = (PRICES[plan] && PRICES[plan][planCycle]) || null;

  // The four plans. Starter & Professional pricing is cycle-dependent.
  const PLANS = [
    {
      key: "free",
      name: "Free",
      price: "$0",
      cadence: "forever",
      blurb: "For trying things out on a single role.",
      features: ["1 active job", "1 seat (just you)", "10 resumes/month", "3 AI match runs/month", "Community support"],
    },
    {
      key: "starter",
      name: "Pro",
      price: (PRICES.starter[cycle] || PRICES.starter.monthly).price,
      cadence: (PRICES.starter[cycle] || PRICES.starter.monthly).cadence,
      rm: null,
      blurb: "For small teams making their first hires.",
      features: ["5 active jobs", "3 team seats", "100 resumes/month", "30 AI runs + reasoning", "Scorecards & stored CVs", "Email support"],
      popular: true,
    },
    {
      key: "professional",
      name: "Premium",
      price: (PRICES.professional[cycle] || PRICES.professional.monthly).price,
      cadence: (PRICES.professional[cycle] || PRICES.professional.monthly).cadence,
      rm: null,
      blurb: "For growing teams hiring across several roles.",
      features: ["Unlimited jobs", "Unlimited seats", "Unlimited resumes & AI", "WhatsApp reminders", "Interview scheduling", "Priority support"],
    },
    {
      key: "enterprise",
      name: "Enterprise",
      price: "Let's talk",
      cadence: "",
      blurb: "For larger organizations with security & volume needs.",
      features: ["Everything in Premium", "SSO & audit logs", "Dedicated success manager", "Custom SLAs", "Onboarding & training"],
    },
  ];

  const current = PLANS.find((p) => p.key === plan) || PLANS[0];
  const paidSub = plan === "starter" || plan === "professional"; // has a card + invoices
  const rank = { free: 0, starter: 1, professional: 2, enterprise: 3 };

  // Mock invoice history — "what they've paid". Reflects the saved billing cycle.
  const invoices = paidSub && saved
    ? planCycle === "yearly"
      ? [{ id: "INV-2025-01", date: "1 Jan 2025", desc: saved.invDesc, amount: saved.invAmount, status: "Paid" }]
      : [
          { id: "INV-2025-06", date: "1 Jun 2025", desc: saved.invDesc, amount: saved.invAmount, status: "Paid" },
          { id: "INV-2025-05", date: "1 May 2025", desc: saved.invDesc, amount: saved.invAmount, status: "Paid" },
          { id: "INV-2025-04", date: "1 Apr 2025", desc: saved.invDesc, amount: saved.invAmount, status: "Paid" },
        ]
    : [];

  const cardClass = "rounded-2xl bg-white act-shadow p-5 border border-[color:var(--line)]";

  const choosePlan = (p) => {
    if (p.key === "enterprise") {
      setMsg("Preview only — in the real app this opens a “Contact sales” form. No plan change made.");
      return;
    }
    const cycleMatters = p.key === "starter" || p.key === "professional";
    if (p.key === plan && (!cycleMatters || cycle === planCycle)) return;
    // Moving down to Free from a paid plan → confirm what gets paused/locked first.
    if (p.key === "free" && paidSub) {
      setKeepJob(keptJobId || (jobs[0] && jobs[0].id) || null);
      setShowDowngrade(true);
      return;
    }
    setPlan(p.key);
    if (cycleMatters) {
      setPlanCycle && setPlanCycle(cycle);
      const isUp = rank[p.key] > rank[plan];
      setMsg(
        cycle === "yearly"
          ? `Preview: switched to ${p.name} (yearly, 20% off). In production you'd be charged for the year today.`
          : `Preview: switched to ${p.name} (monthly). In production you'd be charged a ${isUp ? "prorated" : "prorated"} amount today.`
      );
    } else {
      setMsg("Preview: switched to Free.");
    }
  };

  const confirmDowngrade = () => {
    setKeptJobId && setKeptJobId(keepJob);
    setPlan("free");
    setShowDowngrade(false);
    setMsg("Preview: downgraded to Free. In production this takes effect at the end of your billing period — nothing is deleted, and re-upgrading restores everything.");
  };

  const otherJobs = jobs.filter((j) => j.id !== keepJob).length;
  const activeTeammates = interviewers.length;

  return (
    <div className="px-4 sm:px-6 py-8 sm:py-10">
      <div className="max-w-2xl mx-auto pb-8">
        <BackLink onClick={() => navigate("dashboard")}>← Dashboard</BackLink>
        <h1 className="text-xl font-bold text-neutral-900 font-display mt-3 mb-1">Billing &amp; plan</h1>
        <p className="text-sm text-neutral-500 mb-6">Manage the plan, payment method, and invoices for {company || "your workspace"}.</p>

        {msg && (
          <div className="rounded-xl border p-3 mb-4 text-xs" style={{ borderColor: "#BFDBFE", background: "#EFF6FF", color: "#1E40AF" }}>
            {msg}
          </div>
        )}

        {/* Current plan */}
        <div className={`${cardClass} mb-4`}>
          <div className="flex items-start justify-between gap-3">
            <div className="min-w-0">
              <div className="flex items-center gap-2 mb-1">
                <h2 className="text-sm font-medium text-neutral-600 uppercase tracking-wide">Current plan</h2>
                {trialDaysLeft > 0 ? (
                  <span className="text-[10px] px-2 py-0.5 rounded-full font-semibold" style={{ background: "var(--brand-soft)", color: "var(--brand)" }}>Trial</span>
                ) : (
                  <span className="text-[10px] px-2 py-0.5 rounded-full font-semibold" style={{ background: "#DCFCE7", color: "#166534" }}>Active</span>
                )}
              </div>
              <p className="text-2xl font-bold text-neutral-900 font-display">{trialDaysLeft > 0 ? "Free (trial)" : current.name}</p>
              <p className="text-sm text-neutral-500 mt-0.5">
                {trialDaysLeft > 0
                  ? `Full Premium access — ${trialDaysLeft} day${trialDaysLeft === 1 ? "" : "s"} left, then you'll move to Free.`
                  : paidSub && saved
                    ? `${saved.renewCopy} · renews 1 ${planCycle === "yearly" ? "Jan 2026" : "Jul 2025"} · plus tax`
                    : plan === "free"
                      ? "No charge — you're on the free tier."
                      : "Custom pricing — billed by agreement."}
              </p>
            </div>
            {paidSub && saved && (
              <div className="text-right shrink-0">
                <p className="text-xs text-neutral-500">Next payment</p>
                <p className="text-sm font-semibold text-neutral-900">{saved.nextAmount}</p>
                <p className="text-xs text-neutral-500">1 {planCycle === "yearly" ? "Jan 2026" : "Jul 2025"}</p>
              </div>
            )}
          </div>
          {paidSub && (
            <button
              onClick={() => setMsg("Preview: in production this cancels at period end — access continues until 1 Jul 2025.")}
              className="mt-4 text-xs text-neutral-500 hover:text-neutral-800 underline underline-offset-2"
            >
              Cancel subscription
            </button>
          )}
          {trialDaysLeft > 0 && (
            <button
              onClick={onEndTrial}
              className="mt-4 text-xs text-neutral-500 hover:text-neutral-800 underline underline-offset-2"
            >
              End trial now (preview)
            </button>
          )}
        </div>

        {/* Plan picker */}
        <div className={`${cardClass} mb-4`}>
          <div className="flex items-center justify-between gap-3 mb-3 flex-wrap">
            <h2 className="text-sm font-medium text-neutral-600 uppercase tracking-wide">Change plan</h2>
            <div className="inline-flex rounded-full border p-0.5" style={{ borderColor: "var(--line)" }}>
              {[
                { key: "monthly", label: "Monthly" },
                { key: "yearly", label: "Yearly" },
              ].map((c) => {
                const on = cycle === c.key;
                return (
                  <button
                    key={c.key}
                    onClick={() => setCycle(c.key)}
                    className={`text-xs px-3 py-1 rounded-full font-medium transition-colors flex items-center gap-1 ${on ? "text-white" : "text-neutral-500 hover:text-neutral-800"}`}
                    style={on ? { background: "var(--ink)" } : undefined}
                  >
                    {c.label}
                    {c.key === "yearly" && (
                      <span className="text-[9px] px-1 py-0.5 rounded-full font-semibold" style={{ background: on ? "rgba(255,255,255,0.2)" : "#DCFCE7", color: on ? "#fff" : "#166534" }}>−20%</span>
                    )}
                  </button>
                );
              })}
            </div>
          </div>
          <div className="grid gap-3 sm:grid-cols-3">
            {PLANS.filter((p) => p.key !== "enterprise").map((p) => {
              const cycleMatters = p.key === "starter" || p.key === "professional";
              const isCurrent = p.key === plan && (!cycleMatters || cycle === planCycle);
              return (
                <div
                  key={p.key}
                  className="rounded-xl border p-4 flex flex-col"
                  style={{
                    borderColor: isCurrent ? "var(--brand)" : "var(--line)",
                    background: isCurrent ? "var(--brand-soft)" : "#fff",
                  }}
                >
                  <div className="flex items-center gap-2 mb-1">
                    <p className="font-semibold text-neutral-900">{p.name}</p>
                    {p.popular && !isCurrent && (
                      <span className="text-[10px] px-1.5 py-0.5 rounded-full brand-gradient text-white font-semibold">Popular</span>
                    )}
                  </div>
                  <p className="text-lg font-bold text-neutral-900 font-display leading-tight">{p.price}</p>
                  {p.cadence && <p className="text-xs text-neutral-500">{p.cadence}</p>}
                  {p.rm && <p className="text-[11px] text-neutral-400 mb-2">{p.rm} · in USD</p>}
                  {cycleMatters && cycle === "yearly" && (
                    <p className="text-[11px] font-medium mb-2" style={{ color: "#166534" }}>save 20% billed yearly</p>
                  )}
                  <p className="text-xs text-neutral-500 mb-3 mt-1">{p.blurb}</p>
                  <ul className="space-y-2 mb-4 flex-1">
                    {p.features.map((f) => (
                      <li key={f} className="flex items-start gap-2 text-xs text-neutral-600">
                        <span className="mt-0.5 shrink-0 inline-flex items-center justify-center w-3.5 h-3.5 rounded-full text-white brand-gradient">
                          <Icon name="check" className="w-2 h-2" />
                        </span>
                        <span className="leading-snug">{f}</span>
                      </li>
                    ))}
                  </ul>
                  <button
                    onClick={() => choosePlan(p)}
                    disabled={isCurrent}
                    className={`w-full rounded-xl text-xs font-medium py-2 transition-colors ${
                      isCurrent
                        ? "bg-neutral-100 text-neutral-400 cursor-default"
                        : p.key === "enterprise"
                          ? "border border-neutral-300 text-neutral-800 hover:bg-neutral-50"
                          : "brand-gradient text-white hover:opacity-90"
                    }`}
                  >
                    {isCurrent
                      ? "Current plan"
                      : p.key === "enterprise"
                        ? "Contact sales"
                        : p.key === plan && cycleMatters
                          ? (cycle === "yearly" ? "Switch to yearly" : "Switch to monthly")
                          : rank[p.key] < rank[plan]
                            ? "Downgrade"
                            : "Upgrade"}
                  </button>
                </div>
              );
            })}
          </div>

          {/* Enterprise — highlighted separately */}
          <div className="mt-3 rounded-xl border p-4 flex flex-col sm:flex-row sm:items-center gap-4" style={{ borderColor: "#E6D3FF", background: "var(--brand-soft)" }}>
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-2 mb-1">
                <span className="w-7 h-7 rounded-lg flex items-center justify-center shrink-0 brand-gradient text-white"><Icon name="shield" className="w-4 h-4" /></span>
                <p className="font-semibold text-neutral-900">Enterprise</p>
              </div>
              <p className="text-xs text-neutral-600 leading-relaxed">Everything in Premium, plus SSO &amp; audit logs, a dedicated success manager, and custom SLAs &amp; onboarding.</p>
            </div>
            <button
              onClick={() => choosePlan(PLANS.find((p) => p.key === "enterprise"))}
              className="shrink-0 rounded-xl text-xs font-semibold px-4 py-2 bg-white border border-neutral-300 text-neutral-800 hover:bg-neutral-50 transition-colors"
            >
              Contact sales
            </button>
          </div>
        </div>

        {/* Payment method */}
        <div className={`${cardClass} mb-4`}>
          <h2 className="text-sm font-medium text-neutral-600 uppercase tracking-wide mb-3">Payment method</h2>
          {paidSub ? (
            <div className="flex items-center justify-between gap-3">
              <div className="flex items-center gap-3 min-w-0">
                <span className="w-10 h-7 rounded-md flex items-center justify-center text-[10px] font-bold text-white shrink-0" style={{ background: "#1A1F71" }}>VISA</span>
                <div className="min-w-0">
                  <p className="text-sm font-medium text-neutral-900">Visa •••• 4242</p>
                  <p className="text-xs text-neutral-500">Expires 08 / 27 · shah@example.com</p>
                </div>
              </div>
              <button
                onClick={() => setMsg("Preview: card details are never entered here. In production this opens a secure hosted form (e.g. Stripe), so raw card numbers never touch the app.")}
                className="text-xs rounded-xl border px-3 py-1.5 shrink-0 hover:bg-neutral-50 transition-colors"
                style={{ borderColor: "var(--line)", color: "var(--ink-2)" }}
              >
                Update
              </button>
            </div>
          ) : (
            <p className="text-sm text-neutral-500">No payment method needed on your current plan.</p>
          )}
        </div>

        {/* Billing history */}
        <div className={cardClass}>
          <h2 className="text-sm font-medium text-neutral-600 uppercase tracking-wide mb-3">Billing history</h2>
          {invoices.length === 0 ? (
            <p className="text-sm text-neutral-500">No invoices yet.</p>
          ) : (
            <div className="divide-y" style={{ borderColor: "var(--line)" }}>
              {invoices.map((inv) => (
                <div key={inv.id} className="flex items-center justify-between gap-3 py-2.5">
                  <div className="min-w-0">
                    <p className="text-sm font-medium text-neutral-900 truncate">{inv.desc}</p>
                    <p className="text-xs text-neutral-500">{inv.date} · {inv.id}</p>
                  </div>
                  <div className="flex items-center gap-3 shrink-0">
                    <span className="text-sm tnum text-neutral-900">{inv.amount}</span>
                    <span className="text-[10px] px-2 py-0.5 rounded-full font-semibold" style={{ background: "#DCFCE7", color: "#166534" }}>{inv.status}</span>
                    <button
                      onClick={() => setMsg("Preview: this would download the tax invoice PDF for " + inv.id + ".")}
                      className="text-xs underline underline-offset-2 hover:text-neutral-800"
                      style={{ color: "var(--ink-2)" }}
                    >
                      Invoice
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
          <p className="text-xs text-neutral-400 mt-3">
            Amounts include applicable taxes. Tax invoices are issued to {company || "your workspace"} and can be downloaded above.
          </p>
        </div>
      </div>

      {/* Downgrade confirmation — shows exactly what gets paused/locked */}
      {showDowngrade && (
        <div className="fixed inset-0 z-50 flex items-center justify-center px-4 py-6 overflow-y-auto" style={{ background: "rgba(10,11,30,0.45)" }} onClick={() => setShowDowngrade(false)}>
          <div className="w-full max-w-md rounded-2xl bg-white p-6 act-shadow my-auto" onClick={(e) => e.stopPropagation()}>
            <h3 className="text-base font-bold font-display mb-1" style={{ color: "var(--ink)" }}>Downgrade to Free?</h3>
            <p className="text-sm mb-4" style={{ color: "var(--ink-2)" }}>
              Nothing is deleted — over-limit items are paused and come back if you upgrade again. Here's what changes on Free:
            </p>

            <div className="space-y-2.5 mb-4">
              <div className="rounded-xl border p-3" style={{ borderColor: "var(--line)" }}>
                <p className="text-sm font-medium text-neutral-900 mb-2">
                  {jobs.length} job posting{jobs.length === 1 ? "" : "s"} → keep 1 active
                </p>
                {otherJobs > 0 && (
                  <p className="text-xs mb-2" style={{ color: "var(--ink-3)" }}>
                    {otherJobs} other{otherJobs === 1 ? "" : "s"} will be paused (Apply page links stop taking new applicants).
                  </p>
                )}
                <div className="space-y-1">
                  {jobs.map((j) => (
                    <label key={j.id} className="flex items-center gap-2 text-sm cursor-pointer rounded-lg px-2 py-1.5" style={{ background: keepJob === j.id ? "var(--brand-soft)" : "transparent" }}>
                      <input type="radio" name="keepJob" checked={keepJob === j.id} onChange={() => setKeepJob(j.id)} />
                      <span className="truncate" style={{ color: "var(--ink)" }}>{j.title}</span>
                    </label>
                  ))}
                </div>
              </div>

              {activeTeammates > 0 && (
                <div className="rounded-xl border p-3 flex gap-2.5" style={{ borderColor: "var(--line)" }}>
                  <span className="shrink-0 mt-0.5" style={{ color: "var(--ink-3)" }}><Icon name="users" className="w-4 h-4" /></span>
                  <p className="text-xs" style={{ color: "var(--ink-2)" }}>
                    <span className="font-medium text-neutral-900">{activeTeammates} teammate{activeTeammates === 1 ? "" : "s"}</span> will lose access until you upgrade. Their notes and past interviews stay in the workspace.
                  </p>
                </div>
              )}

              <div className="rounded-xl border p-3 flex gap-2.5" style={{ borderColor: "var(--line)" }}>
                <span className="shrink-0 mt-0.5" style={{ color: "var(--ink-3)" }}><Icon name="lock" className="w-4 h-4" /></span>
                <p className="text-xs" style={{ color: "var(--ink-2)" }}>
                  You keep your full candidate list, but AI matching drops to 3 runs a month, shows only the top 3 fits, and hides the written reasoning.
                </p>
              </div>

              <div className="rounded-xl border p-3 flex gap-2.5" style={{ borderColor: "#BBF7D0", background: "#F0FDF4" }}>
                <span className="shrink-0 mt-0.5" style={{ color: "#16A34A" }}><Icon name="calendar" className="w-4 h-4" /></span>
                <p className="text-xs" style={{ color: "#166534" }}>
                  Interviews already booked will still happen — nothing on the calendar is cancelled.
                </p>
              </div>
            </div>

            <p className="text-xs mb-4" style={{ color: "var(--ink-3)" }}>
              In production this takes effect at the end of your current billing period.
            </p>

            <div className="flex justify-end gap-2">
              <button onClick={() => setShowDowngrade(false)} className="text-sm rounded-xl border px-4 py-2 hover:bg-neutral-50 transition-colors" style={{ borderColor: "var(--line)", color: "var(--ink-2)" }}>
                Keep Premium
              </button>
              <button onClick={confirmDowngrade} disabled={!keepJob} className="text-sm rounded-xl bg-neutral-900 hover:bg-neutral-800 disabled:opacity-40 text-white font-medium px-4 py-2 transition-colors">
                Downgrade to Free
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}


// The fixed set of automated emails, with the placeholders each supports.
// In production these live in an `email_templates` table (per org); here they're
// editable in-memory so the UX (edit + insert placeholder + live preview) is real.
const EMAIL_TEMPLATE_DEFS = [
  { key: "sourcing_invite", name: "Sourcing invite — reconnect", desc: "Sent when you invite someone from your database to apply for an open role.",
    tokens: ["candidate_name", "job_title", "apply_link"],
    subject: "A {{job_title}} role you might like",
    body: "Hi {{candidate_name}},\n\nIt has been a while since we last connected, but your background stood out to us and we are now hiring a {{job_title}}. If you are interested, tap the link below to see the role and apply with your latest resume. It only takes a minute.\n\n{{apply_link}}\n\nWe would love to reconnect." },
  { key: "offer", name: "Offer — you've been selected", desc: "Sent when you make an offer. Includes the accept / decline links.",
    tokens: ["candidate_name", "job_title", "company_name", "hr_contact"],
    subject: "You've been selected for the {{job_title}} role",
    body: "Hi {{candidate_name}},\n\nCongratulations! Following your interview, we're delighted to offer you the {{job_title}} role at {{company_name}}. Our HR team ({{hr_contact}}) will be in touch with the details.\n\nPlease confirm whether you'd like to accept using the buttons below.\n\nWarm regards,\nThe {{company_name}} Hiring Team" },
  { key: "rejection", name: "Rejection — application update", desc: "Sent when you reject a candidate with an email.",
    tokens: ["candidate_name", "job_title", "company_name"],
    subject: "Update on your application — {{job_title}}",
    body: "Hi {{candidate_name}},\n\nThank you for applying for the {{job_title}} role at {{company_name}} and for the time you invested.\n\nAfter careful consideration we've decided not to move forward at this time. We genuinely appreciate your interest and wish you all the best.\n\nWarm regards,\nThe {{company_name}} Hiring Team" },
  { key: "interview_invite", name: "Interview invite", desc: "Sent when you invite a candidate to pick an interview slot.",
    tokens: ["candidate_name", "job_title", "interviewer_name", "booking_link"],
    subject: "Interview invitation — {{job_title}}",
    body: "Hi {{candidate_name}},\n\nWe'd love to interview you for the {{job_title}} role. Your interviewer will be {{interviewer_name}}.\n\nPlease pick a time that works for you here: {{booking_link}}\n\nSee you soon,\nThe Hiring Team" },
  { key: "interview_confirmation", name: "Interview confirmation", desc: "Sent once the candidate picks a slot.",
    tokens: ["candidate_name", "job_title", "date_time", "meeting_link"],
    subject: "Your interview is confirmed — {{date_time}}",
    body: "Hi {{candidate_name}},\n\nYour interview for the {{job_title}} role is confirmed for {{date_time}}.\n\nJoin here: {{meeting_link}}\n\nLooking forward to speaking,\nThe Hiring Team" },
  { key: "application_received", name: "Application received", desc: "Auto-reply when someone applies via the public link.",
    tokens: ["candidate_name", "job_title", "company_name"],
    subject: "We've received your application — {{job_title}}",
    body: "Hi {{candidate_name}},\n\nThanks for applying for the {{job_title}} role at {{company_name}}. We've received your application and will be in touch if there's a fit.\n\nWarm regards,\nThe {{company_name}} Hiring Team" },
  { key: "welcome_hired", name: "Welcome — offer accepted", desc: "Sent after a candidate accepts their offer.",
    tokens: ["candidate_name", "job_title", "company_name"],
    subject: "Welcome to {{company_name}}, {{candidate_name}}!",
    body: "Hi {{candidate_name}},\n\nWe're thrilled you're joining {{company_name}} as our new {{job_title}}! Our HR team will reach out shortly with your onboarding details and start date.\n\nWelcome aboard,\nThe {{company_name}} Team" },
];

// Placeholders offered in every template's editor, on top of its own tokens.
const COMMON_TOKENS = ["company_name", "company_address", "interviewer_name", "logo"];
// Sample values used to render the live preview.
const TOKEN_SAMPLES = {
  candidate_name: "Amira Hassan", job_title: "Senior Frontend Engineer", company: "Oryx Studio",
  company_name: "Oryx Studio", company_address: "Level 12, Menara Aster, Jalan Ampang, 50450 Kuala Lumpur",
  hr_contact: "Farah (HR)", interviewer_name: "Jane Tan", booking_link: "aster.my/book/xxxx",
  date_time: "Tue 8 Jul, 2:00 PM", meeting_link: "meet.google.com/xxx-xxxx", apply_link: "aster.my/apply/xxxx",
};
const fillTokens = (text) => (text || "").replace(/\{\{(\w+)\}\}/g, (_, k) => TOKEN_SAMPLES[k] ?? `{{${k}}}`);

function EmailTemplatesScreen({ navigate, plan = "free", logoUrl, company }) {
  const [templates, setTemplates] = useState(() => Object.fromEntries(EMAIL_TEMPLATE_DEFS.map((t) => [t.key, { subject: t.subject, body: t.body }])));
  const [selected, setSelected] = useState(null); // template key or null (list view)
  const [subject, setSubject] = useState("");
  const [body, setBody] = useState("");
  const [savedMsg, setSavedMsg] = useState(null);
  const [showPreview, setShowPreview] = useState(false);

  const cardClass = "rounded-2xl bg-white act-shadow p-5 border border-[color:var(--line)]";
  const def = EMAIL_TEMPLATE_DEFS.find((t) => t.key === selected);

  const open = (key) => {
    const t = templates[key];
    setSelected(key); setSubject(t.subject); setBody(t.body); setSavedMsg(null); setShowPreview(false);
  };
  const dirty = def && (subject !== templates[selected].subject || body !== templates[selected].body);
  const save = () => {
    setTemplates((prev) => ({ ...prev, [selected]: { subject, body } }));
    setSavedMsg("Saved — future emails of this type will use this wording.");
  };
  // Insert a placeholder at the end of the body (real editor would insert at cursor).
  const insertToken = (tok) => { setBody((b) => `${b}{{${tok}}}`); setSavedMsg(null); };
  // Preview: fill text tokens, and render {{logo}} as the actual logo image.
  const renderPreviewBody = (text) => {
    const parts = fillTokens(text).split("{{logo}}"); // logo isn't in samples, so it survives fillTokens
    return parts.map((p, i) => (
      <Fragment key={i}>
        {p}
        {i < parts.length - 1 && (logoUrl
          ? <img src={logoUrl} alt={company || "logo"} style={{ height: 22, display: "inline-block", verticalAlign: "middle", margin: "0 3px" }} />
          : <span className="inline-flex items-center px-1.5 py-0.5 rounded text-[10px] align-middle" style={{ background: "var(--brand-soft)", color: "var(--brand)" }}>logo</span>)}
      </Fragment>
    ));
  };

  // ---- List view ----
  if (!selected) {
    return (
      <div className="px-4 sm:px-6 py-8 sm:py-10">
        <div className="max-w-2xl mx-auto pb-8">
          <BackLink onClick={() => navigate("settings")}>← Settings</BackLink>
          <h1 className="text-xl sm:text-2xl font-bold font-display mt-2 mb-1" style={{ color: "var(--ink)" }}>Email templates</h1>
          <p className="text-sm text-neutral-600 mb-5">Edit the wording behind each automated email. Placeholders like <span className="font-mono text-xs bg-neutral-100 px-1 py-0.5 rounded">{"{{candidate_name}}"}</span> are filled in automatically when each email is sent.</p>
          <div className="space-y-2">
            {EMAIL_TEMPLATE_DEFS.map((t) => (
              <button key={t.key} onClick={() => open(t.key)} className={`${cardClass} w-full text-left flex items-center gap-3 hover:bg-neutral-50 transition-colors`}>
                <span className="min-w-0 flex-1">
                  <span className="block text-sm font-semibold" style={{ color: "var(--ink)" }}>{t.name}</span>
                  <span className="block text-xs text-neutral-500 truncate">{t.desc}</span>
                </span>
                <Icon name="chevronRight" className="w-5 h-5 text-neutral-300 shrink-0" />
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  // ---- Editor view ----
  return (
    <div className="px-4 sm:px-6 py-8 sm:py-10">
      <div className="max-w-2xl mx-auto pb-8">
        <BackLink onClick={() => setSelected(null)}>← All templates</BackLink>
        <h1 className="text-xl sm:text-2xl font-bold font-display mt-2 mb-1" style={{ color: "var(--ink)" }}>{def.name}</h1>
        <p className="text-sm text-neutral-600 mb-5">{def.desc}</p>

        {savedMsg && (
          <div className="rounded-xl border p-3 mb-4 text-xs" style={{ borderColor: "#BBF7D0", background: "#F0FDF4", color: "#166534" }}>{savedMsg}</div>
        )}

        <div className={`${cardClass} mb-4`}>
          <label className="block text-xs text-neutral-500 mb-1">Subject</label>
          <input value={subject} onChange={(e) => { setSubject(e.target.value); setSavedMsg(null); }}
            className="w-full rounded-xl bg-neutral-100 border border-neutral-200 px-3 py-2 text-neutral-900 text-sm focus:outline-none focus:ring-2 focus:ring-neutral-400 mb-4" />

          <div className="flex items-center justify-between mb-1">
            <label className="block text-xs text-neutral-500">Body</label>
            <button onClick={() => setShowPreview((s) => !s)} className="text-xs font-medium" style={{ color: "var(--brand)" }}>{showPreview ? "Edit" : "Preview"}</button>
          </div>

          {showPreview ? (
            <div className="rounded-xl border p-4" style={{ borderColor: "var(--line)", background: "#fff" }}>
              <p className="text-xs text-neutral-400 mb-2">Preview with sample data</p>
              <p className="text-sm font-semibold text-neutral-900 mb-2">{fillTokens(subject)}</p>
              <div className="text-sm text-neutral-700 whitespace-pre-wrap leading-relaxed">{renderPreviewBody(body)}</div>
              {/* Auto letterhead — added under every email automatically from the
                  logo + company name set in Settings. Not part of the editable body. */}
              <div className="mt-5 pt-4" style={{ borderTop: "1px solid var(--line)" }}>
                {logoUrl ? (
                  <img src={logoUrl} alt={company || "Company"} style={{ height: 28, width: "auto", objectFit: "contain" }} />
                ) : (
                  <div className="w-24 h-7 rounded flex items-center justify-center text-[10px]" style={{ background: "var(--brand-soft)", color: "var(--brand)" }}>your logo</div>
                )}
                {company && <p className="text-xs font-medium mt-1.5" style={{ color: "var(--ink-2)" }}>{company}</p>}
              </div>
            </div>
          ) : (
            <>
              {/* In production this textarea is a rich-text editor (CKEditor/TipTap).
                  Placeholder chips insert tokens; preview shows the filled result. */}
              <textarea value={body} onChange={(e) => { setBody(e.target.value); setSavedMsg(null); }} rows={12}
                className="w-full rounded-xl bg-neutral-100 border border-neutral-200 px-3 py-2 text-neutral-900 text-sm focus:outline-none focus:ring-2 focus:ring-neutral-400 resize-y font-mono leading-relaxed" />
              <p className="text-[11px] mt-2 flex items-center gap-1.5" style={{ color: "var(--ink-3)" }}>
                <Icon name="check" className="w-3 h-3" /> Your logo{company ? ` and “${company}”` : ""} are added automatically under the signature — no need to include them here. Change them in Settings.
              </p>
              <div className="mt-3">
                <p className="text-[11px] text-neutral-500 mb-1.5">Insert a placeholder:</p>
                <div className="flex flex-wrap gap-1.5">
                  {[...new Set([...(def.tokens || []), ...COMMON_TOKENS])].map((tok) => (
                    <button key={tok} onClick={() => insertToken(tok)}
                      className="text-[11px] font-mono rounded-full px-2 py-0.5 border transition-colors hover:bg-neutral-50"
                      style={{ borderColor: "var(--line-strong)", color: "var(--brand)", background: "var(--brand-soft)" }}>
                      {`{{${tok}}}`}
                    </button>
                  ))}
                </div>
              </div>
            </>
          )}
        </div>

        <div className="flex items-center gap-2">
          <button onClick={save} disabled={!dirty} className="text-sm rounded-xl brand-gradient disabled:opacity-40 text-white font-medium px-4 py-2 transition-opacity hover:opacity-90">Save template</button>
          {dirty && <button onClick={() => open(selected)} className="text-sm rounded-xl border px-4 py-2 transition-colors hover:bg-neutral-50" style={{ borderColor: "var(--line-strong)", color: "var(--ink-2)" }}>Reset</button>}
        </div>
      </div>
    </div>
  );
}

function ProfileScreen({ navigate, avatarUrl, setAvatarUrl, logoUrl, setLogoUrl, profile, setProfile, company, setCompany }) {
  const [email] = useState("shah@example.com");
  const [newEmail, setNewEmail] = useState("");
  const [emailMsg, setEmailMsg] = useState(null);

  // Staged (draft) edits — nothing is committed until Save. Cancel reverts.
  const [dLogo, setDLogo] = useState(logoUrl);
  const [dCompany, setDCompany] = useState(company || "");
  const [dAvatar, setDAvatar] = useState(avatarUrl);
  const [dFirst, setDFirst] = useState(profile?.firstName || "");
  const [dLast, setDLast] = useState(profile?.lastName || "");
  const [dRole, setDRole] = useState(profile?.role || "");
  const [saving, setSaving] = useState(false);
  const [savedMsg, setSavedMsg] = useState(null);

  // Password / sign-in
  const [curPw, setCurPw] = useState("");
  const [newPw, setNewPw] = useState("");
  const [confPw, setConfPw] = useState("");
  const [showPw, setShowPw] = useState(false);
  const [pwMsg, setPwMsg] = useState(null);

  const inputClass = "w-full rounded-xl bg-neutral-100 border border-neutral-200 px-3 py-2 text-neutral-900 text-sm focus:outline-none focus:ring-2 focus:ring-neutral-400";
  const cardClass = "rounded-2xl bg-white act-shadow p-5 border border-[color:var(--line)]";

  const dirty =
    dLogo !== logoUrl ||
    dCompany !== (company || "") ||
    dAvatar !== avatarUrl ||
    dFirst !== (profile?.firstName || "") ||
    dLast !== (profile?.lastName || "") ||
    dRole !== (profile?.role || "");

  const handleLogoChange = (e) => { const f = e.target.files?.[0]; if (!f) return; const r = new FileReader(); r.onload = () => { setDLogo(r.result); setSavedMsg(null); }; r.readAsDataURL(f); };
  const handleAvatarChange = (e) => { const f = e.target.files?.[0]; if (!f) return; const r = new FileReader(); r.onload = () => { setDAvatar(r.result); setSavedMsg(null); }; r.readAsDataURL(f); };

  const handleSave = () => {
    setSaving(true);
    setTimeout(() => {
      setLogoUrl(dLogo);
      setCompany(dCompany.trim());
      setAvatarUrl(dAvatar);
      setProfile({ firstName: dFirst.trim(), lastName: dLast.trim(), role: dRole.trim() });
      setSaving(false);
      setSavedMsg("All changes saved.");
    }, 800);
  };
  const handleCancel = () => {
    setDLogo(logoUrl); setDCompany(company || ""); setDAvatar(avatarUrl);
    setDFirst(profile?.firstName || ""); setDLast(profile?.lastName || ""); setDRole(profile?.role || "");
    setSavedMsg(null);
  };

  const handleEmailSubmit = () => {
    if (!newEmail) return;
    setEmailMsg(`Confirmation sent to ${newEmail}. Your email won't change until you click the link in that message.`);
    setNewEmail("");
  };

  const handleChangePassword = () => {
    setPwMsg(null);
    if (!curPw || !newPw || !confPw) { setPwMsg({ type: "err", text: "Fill in all three password fields." }); return; }
    const problem = passwordProblem(newPw);
    if (problem) { setPwMsg({ type: "err", text: problem }); return; }
    if (newPw !== confPw) { setPwMsg({ type: "err", text: "New passwords don't match." }); return; }
    setPwMsg({ type: "ok", text: "Password updated." });
    setCurPw(""); setNewPw(""); setConfPw("");
  };

  const avatarInitial = (dFirst?.[0] || "S").toUpperCase();

  return (
    <div className="px-4 sm:px-6 py-8 sm:py-10">
      <div className="max-w-2xl mx-auto pb-8">
        <BackLink onClick={() => navigate("dashboard")}>← Dashboard</BackLink>
        <h1 className="text-xl sm:text-2xl font-bold font-display mt-2 mb-1" style={{ color: "var(--ink)" }}>Profile</h1>
        <p className="text-sm text-neutral-500 mb-6">Your company branding, personal details, and sign-in.</p>

        {/* Company details */}
        <div className={`${cardClass} mb-4`}>
          <h2 className="text-sm font-medium text-neutral-600 uppercase tracking-wide mb-3">Company details</h2>
          <div className="flex items-center gap-4">
            <div className="h-14 w-40 rounded-xl border flex items-center justify-center overflow-hidden bg-white shrink-0" style={{ borderColor: "var(--line)" }}>
              <img src={dLogo || ACTIVYS_LOGO} alt={dCompany || "Company logo"} className="h-11 w-auto object-contain" />
            </div>
            <div className="flex flex-wrap gap-2">
              <label className="text-sm rounded-xl bg-neutral-900 hover:bg-neutral-800 text-white px-4 py-2 cursor-pointer transition-colors inline-block">
                {dLogo ? "Replace logo" : "Upload logo"}
                <input type="file" accept="image/*" onChange={handleLogoChange} className="hidden" />
              </label>
              {dLogo && (
                <button onClick={() => { setDLogo(null); setSavedMsg(null); }} className="text-sm rounded-xl border px-4 py-2 transition-colors hover:bg-neutral-50" style={{ borderColor: "var(--line)", color: "var(--ink-2)" }}>Remove</button>
              )}
            </div>
          </div>
          <p className="text-xs text-neutral-500 mt-2">Shows in the sidebar, on the login screen, and in the mobile header. Wide (landscape) logos work best.</p>
          <div className="mt-4">
            <label className="block text-xs mb-1" style={{ color: "var(--ink-2)" }}>Company name</label>
            <input value={dCompany} onChange={(e) => { setDCompany(e.target.value); setSavedMsg(null); }} placeholder="Your company" className={inputClass} />
            <p className="text-xs text-neutral-500 mt-1">Collected at sign-up and shown across your workspace.</p>
          </div>
        </div>

        {/* Personal details */}
        <div className={`${cardClass} mb-4`}>
          <h2 className="text-sm font-medium text-neutral-600 uppercase tracking-wide mb-3">Personal details</h2>
          <div className="flex items-center gap-4 mb-4">
            {dAvatar ? (
              <img src={dAvatar} alt="Your photo" className="w-16 h-16 rounded-full object-cover border border-neutral-200" />
            ) : (
              <div className="w-16 h-16 rounded-full bg-violet-100 border border-neutral-200 flex items-center justify-center text-neutral-700 font-medium text-lg">{avatarInitial}</div>
            )}
            <div className="flex flex-wrap gap-2">
              <label className="text-sm rounded-xl bg-neutral-900 hover:bg-neutral-800 text-white px-4 py-2 cursor-pointer transition-colors">
                Change photo
                <input type="file" accept="image/*" onChange={handleAvatarChange} className="hidden" />
              </label>
              {dAvatar && (
                <button onClick={() => { setDAvatar(null); setSavedMsg(null); }} className="text-sm rounded-xl border px-4 py-2 transition-colors hover:bg-neutral-50" style={{ borderColor: "var(--line)", color: "var(--ink-2)" }}>Remove</button>
              )}
            </div>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <div>
              <label className="block text-xs mb-1" style={{ color: "var(--ink-2)" }}>First name</label>
              <input value={dFirst} onChange={(e) => { setDFirst(e.target.value); setSavedMsg(null); }} placeholder="Shah" className={inputClass} />
            </div>
            <div>
              <label className="block text-xs mb-1" style={{ color: "var(--ink-2)" }}>Last name</label>
              <input value={dLast} onChange={(e) => { setDLast(e.target.value); setSavedMsg(null); }} placeholder="Ramly" className={inputClass} />
            </div>
            <div className="sm:col-span-2">
              <label className="block text-xs mb-1" style={{ color: "var(--ink-2)" }}>Role</label>
              <input value={dRole} onChange={(e) => { setDRole(e.target.value); setSavedMsg(null); }} placeholder="Hiring Manager" className={inputClass} />
            </div>
          </div>
          <p className="text-xs text-neutral-500 mt-2">Your first name shows in the dashboard greeting; full name and role show in the sidebar.</p>
        </div>

        {/* ===== Sign-in ===== */}
        <p className="text-xs font-semibold uppercase mb-3 mt-6" style={{ color: "var(--brand)", letterSpacing: "0.07em" }}>Sign-in</p>

        {/* Email address */}
        <div className={`${cardClass} mb-4`}>
          <h2 className="text-sm font-medium text-neutral-600 uppercase tracking-wide mb-3">Email address</h2>
          <p className="text-sm text-neutral-600 mb-3">Current: <span className="text-neutral-900">{email}</span></p>
          <div className="space-y-3">
            <input type="email" value={newEmail} onChange={(e) => setNewEmail(e.target.value)} placeholder="new-email@example.com" autoComplete="email" className={inputClass} />
            <p className="text-xs text-neutral-500">We'll email a confirmation link to the new address. Your login email stays the same until you click it.</p>
            {emailMsg && <p className="text-sm text-emerald-600">{emailMsg}</p>}
            <button onClick={handleEmailSubmit} className="rounded-xl bg-neutral-900 hover:bg-neutral-800 text-white text-sm font-medium px-4 py-2 transition-colors">Send confirmation</button>
          </div>
        </div>

        {/* Password */}
        <div className={cardClass}>
          <h2 className="text-sm font-medium text-neutral-600 uppercase tracking-wide mb-3">Password</h2>
          <div className="space-y-3">
            <input type={showPw ? "text" : "password"} value={curPw} onChange={(e) => { setCurPw(e.target.value); setPwMsg(null); }} placeholder="Current password" autoComplete="current-password" className={inputClass} />
            <input type={showPw ? "text" : "password"} value={newPw} onChange={(e) => { setNewPw(e.target.value); setPwMsg(null); }} placeholder="New password" autoComplete="new-password" className={inputClass} />
            <input type={showPw ? "text" : "password"} value={confPw} onChange={(e) => { setConfPw(e.target.value); setPwMsg(null); }} placeholder="Confirm new password" autoComplete="new-password" className={inputClass} />
            <label className="flex items-center gap-2 text-xs cursor-pointer" style={{ color: "var(--ink-2)" }}>
              <input type="checkbox" checked={showPw} onChange={(e) => setShowPw(e.target.checked)} /> Show passwords
            </label>
            <p className="text-xs text-neutral-500">At least 8 characters, with a letter and a number.</p>
            {pwMsg && <p className="text-sm" style={{ color: pwMsg.type === "ok" ? "#166534" : "#DC2626" }}>{pwMsg.text}</p>}
            <div className="flex items-center gap-4 flex-wrap">
              <button onClick={handleChangePassword} className="rounded-xl bg-neutral-900 hover:bg-neutral-800 text-white text-sm font-medium px-4 py-2 transition-colors">Update password</button>
              <button onClick={() => navigate("forgotPassword")} className="text-sm font-medium hover:opacity-70 transition-opacity" style={{ color: "var(--brand)" }}>Forgot your password?</button>
            </div>
          </div>
        </div>

        {/* Save / Cancel bar */}
        <div className="sticky bottom-4 z-20 mt-6 rounded-2xl border bg-white/95 backdrop-blur px-4 py-3 act-shadow" style={{ borderColor: "var(--line)" }}>
          <div className="flex items-center justify-between gap-3">
            <p className="text-xs sm:text-sm min-w-0 truncate" style={{ color: savedMsg ? "#166534" : "var(--ink-2)" }}>
              {saving ? "Saving…" : savedMsg ? savedMsg : dirty ? "You have unsaved changes." : "Everything is up to date."}
            </p>
            <div className="flex items-center gap-2 shrink-0">
              <button onClick={handleCancel} disabled={!dirty || saving} className="text-sm rounded-xl border px-4 py-2 transition-colors hover:bg-neutral-50 disabled:opacity-40 disabled:cursor-not-allowed" style={{ borderColor: "var(--line)", color: "var(--ink-2)" }}>Cancel</button>
              <button onClick={handleSave} disabled={!dirty || saving} className="text-sm rounded-xl brand-gradient hover:opacity-90 text-white font-medium px-5 py-2 transition-opacity disabled:opacity-40 disabled:cursor-not-allowed">{saving ? "Saving…" : "Save changes"}</button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function SettingsScreen({ navigate, provider, setProvider, calendarConnected, setCalendarConnected, bookings = {}, plan = "free" }) {
  // Staged (draft) edits for the calendar provider — Save/Cancel form.
  const [dProvider, setDProvider] = useState(provider);
  const [dCalConnected, setDCalConnected] = useState(calendarConnected);
  const [connectingCal, setConnectingCal] = useState(false);
  const [saving, setSaving] = useState(false);
  const [savedMsg, setSavedMsg] = useState(null);

  // WhatsApp Business — BSP-assisted connection. Included on Professional & up
  // (not Starter). Self-contained (connecting an integration is an immediate
  // action, separate from the Save/Cancel form).
  const hasWhatsApp = planLimits(plan).whatsapp;
  const [waStatus, setWaStatus] = useState("disconnected"); // disconnected | connecting | pending | connected
  const [waTemplates, setWaTemplates] = useState({ confirmed: true, received: true, reminder: false });
  const [waTested, setWaTested] = useState(false);
  const connectWhatsApp = () => { setWaStatus("connecting"); setTimeout(() => setWaStatus("pending"), 1400); };

  const calSystem = dProvider === "microsoft" ? "Microsoft 365" : "Google Workspace";
  const meetName = dProvider === "microsoft" ? "Teams" : "Google Meet";
  const savedMeetName = provider === "microsoft" ? "Teams" : "Google Meet";

  // Upcoming interviews already booked on the CURRENTLY SAVED provider. These
  // keep their existing links if the user switches — used to warn on switch.
  const upcomingOnSaved = Object.values(bookings).filter(
    (b) => b && b.status === "scheduled" && b.confirmedSlot?.start && (b.provider || "google") === provider
  ).length;
  const providerChanged = dProvider !== provider;

  const cardClass = "rounded-2xl bg-white act-shadow p-5 border border-[color:var(--line)]";

  const dirty = dProvider !== provider || dCalConnected !== calendarConnected;

  const handleConnectCalendar = () => {
    setConnectingCal(true);
    setTimeout(() => { setDCalConnected(true); setConnectingCal(false); }, 1500);
  };

  const handleSave = () => {
    setSaving(true);
    setTimeout(() => {
      setProvider(dProvider);
      setCalendarConnected(dCalConnected);
      setSaving(false);
      setSavedMsg("All changes saved.");
    }, 800);
  };

  const handleCancel = () => {
    setDProvider(provider);
    setDCalConnected(calendarConnected);
    setSavedMsg(null);
  };

  return (
    <div className="px-4 sm:px-6 py-8 sm:py-10">
      <div className="max-w-2xl mx-auto pb-8">
        <BackLink onClick={() => navigate("dashboard")}>← Dashboard</BackLink>
        <h1 className="text-xl sm:text-2xl font-bold font-display mt-2 mb-1" style={{ color: "var(--ink)" }}>Settings</h1>
        <p className="text-sm text-neutral-500 mb-6">Email templates, calendar, messaging, and usage for your workspace.</p>

        {/* Email templates — the wording behind every automated email */}
        <button onClick={() => navigate("emailTemplates")} className={`${cardClass} mb-4 w-full text-left flex items-center gap-3 hover:bg-neutral-50 transition-colors`}>
          <span className="w-10 h-10 rounded-xl flex items-center justify-center shrink-0" style={{ background: "var(--brand-soft)", color: "var(--brand)" }}>
            <Icon name="doc" className="w-5 h-5" />
          </span>
          <span className="min-w-0 flex-1">
            <span className="block text-sm font-semibold" style={{ color: "var(--ink)" }}>Email templates</span>
            <span className="block text-xs text-neutral-500">Edit the offer, rejection, interview &amp; other automated emails</span>
          </span>
          <Icon name="chevronRight" className="w-5 h-5 text-neutral-300 shrink-0" />
        </button>

        {/* 4 — Meeting & calendar */}
        <div className={`${cardClass} mb-4`}>
          <h2 className="text-sm font-medium text-neutral-600 uppercase tracking-wide mb-1">Meeting &amp; calendar</h2>
          <p className="text-sm text-neutral-600 mb-3">
            Used for every interview across the workspace. Connect once here — all interviewers are covered, no per-person setup.
          </p>
          <div className="grid grid-cols-2 gap-3 mb-4">
            {["google", "microsoft"].map((p) => (
              <button
                key={p}
                onClick={() => {
                  if (p !== dProvider) {
                    setDProvider(p);
                    setDCalConnected(false); // switching platform drops the old connection
                    setSavedMsg(null);
                  }
                }}
                className={`rounded-xl border px-4 py-3 text-sm text-left transition-colors ${
                  dProvider === p ? "border-neutral-900 bg-neutral-50" : "border-neutral-200 bg-white hover:border-neutral-300"
                }`}
              >
                <p className="font-medium text-neutral-900">{p === "google" ? "Google Meet" : "Microsoft Teams"}</p>
                <p className="text-xs text-neutral-500">{p === "google" ? "Google Calendar" : "Outlook Calendar"}</p>
              </button>
            ))}
          </div>

          {providerChanged && upcomingOnSaved > 0 && (
            <div className="rounded-xl border p-3 mb-4 flex gap-2.5" style={{ borderColor: "#FCD34D", background: "#FFFBEB" }}>
              <span className="shrink-0 mt-0.5" style={{ color: "#B45309" }}>
                <Icon name="bell" className="w-4 h-4" />
              </span>
              <p className="text-xs leading-relaxed" style={{ color: "#92400E" }}>
                You have {upcomingOnSaved} upcoming interview{upcomingOnSaved === 1 ? "" : "s"} on {savedMeetName}. Switching won't change {upcomingOnSaved === 1 ? "it" : "them"} — {upcomingOnSaved === 1 ? "that interview keeps its" : "those interviews keep their"} existing {savedMeetName} link{upcomingOnSaved === 1 ? "" : "s"}. Only new interviews will use {meetName}.
              </p>
            </div>
          )}

          <div className="rounded-xl border p-3 flex items-center justify-between gap-3" style={{ borderColor: "var(--line)", background: dCalConnected ? "#F0FDF4" : "var(--bg)" }}>
            <div className="min-w-0">
              <p className="text-sm font-medium" style={{ color: "var(--ink)" }}>{calSystem} calendar</p>
              <p className="text-xs" style={{ color: "var(--ink-2)" }}>
                {dCalConnected
                  ? `Connected — interviews auto-create ${meetName} links and check everyone's availability.`
                  : `Connect to check availability and auto-create ${meetName} links.`}
              </p>
            </div>
            {dCalConnected ? (
              <span className="text-xs px-2.5 py-1 rounded-full shrink-0 flex items-center gap-1.5" style={{ background: "#DCFCE7", color: "#166534" }}>
                <span className="w-1.5 h-1.5 rounded-full" style={{ background: "#22C55E" }} /> Connected
              </span>
            ) : (
              <button
                onClick={handleConnectCalendar}
                disabled={connectingCal}
                className="text-xs rounded-xl bg-neutral-900 hover:bg-neutral-800 disabled:opacity-50 text-white px-3 py-1.5 shrink-0 transition-colors"
              >
                {connectingCal ? "Connecting…" : `Connect ${calSystem}`}
              </button>
            )}
          </div>
        </div>

        {/* 5 — WhatsApp Business (Pro, BSP-assisted, bring-your-own-number) */}
        <div className={cardClass}>
          <div className="flex items-center gap-2 mb-1">
            <h2 className="text-sm font-medium text-neutral-600 uppercase tracking-wide">WhatsApp Business</h2>
            {!hasWhatsApp && <LockBadge label="Pro" />}
          </div>
          <p className="text-sm text-neutral-600 mb-4">
            Send interview confirmations and reminders over WhatsApp using your own WhatsApp Business number. Messages are billed to your Meta account, not Aster.
          </p>

          {!hasWhatsApp ? (
            <div className="rounded-xl border p-4 flex items-center justify-between gap-3" style={{ borderColor: "var(--line)", background: "var(--brand-soft)" }}>
              <p className="text-sm" style={{ color: "var(--ink-2)" }}>
                WhatsApp automations are on <span className="font-semibold">Premium</span> and up.
              </p>
              <button onClick={() => navigate("billing")} className="text-xs brand-gradient text-white font-medium px-3 py-1.5 rounded-lg shrink-0 hover:opacity-90 transition-opacity">Upgrade</button>
            </div>
          ) : waStatus === "connected" ? (
            <div className="space-y-3">
              <div className="rounded-xl border p-3 flex items-center justify-between gap-3" style={{ borderColor: "#BBF7D0", background: "#F0FDF4" }}>
                <div className="min-w-0">
                  <p className="text-sm font-medium" style={{ color: "#166534" }}>Connected as +60 12-••• ••89</p>
                  <p className="text-xs" style={{ color: "#166534" }}>Business verified ✓ · via messaging partner</p>
                </div>
                <button onClick={() => { setWaStatus("disconnected"); setWaTested(false); }} className="text-xs text-neutral-500 hover:text-red-600 shrink-0 transition-colors">Disconnect</button>
              </div>

              <div>
                <p className="text-xs font-medium text-neutral-600 mb-2">Message templates</p>
                <div className="space-y-1.5">
                  {[
                    ["confirmed", "Interview confirmed", "Sent when a candidate books a time"],
                    ["received", "Application received", "Sent when someone applies"],
                    ["reminder", "Interview reminder — 24h before", "Auto-reminder the day before"],
                  ].map(([key, name, desc]) => (
                    <label key={key} className="flex items-center gap-3 rounded-xl border px-3 py-2.5 cursor-pointer" style={{ borderColor: "var(--line)" }}>
                      <input type="checkbox" checked={waTemplates[key]} onChange={(e) => setWaTemplates((t) => ({ ...t, [key]: e.target.checked }))} />
                      <div className="min-w-0 flex-1">
                        <p className="text-sm text-neutral-900">{name}</p>
                        <p className="text-xs text-neutral-500">{desc}</p>
                      </div>
                      <span className="text-[10px] px-1.5 py-0.5 rounded-full shrink-0" style={{ background: "#DCFCE7", color: "#166534" }}>Approved</span>
                    </label>
                  ))}
                </div>
              </div>

              <div className="flex items-center gap-3">
                <button onClick={() => setWaTested(true)} className="text-xs rounded-xl border px-3 py-1.5 hover:bg-neutral-50 transition-colors" style={{ borderColor: "var(--line-strong)", color: "var(--ink)" }}>
                  Send test message
                </button>
                {waTested && <span className="text-xs" style={{ color: "#166534" }}>Test message sent to your number ✓</span>}
              </div>
              <p className="text-xs text-neutral-400">Each message is billed to your Meta/WhatsApp account by our messaging partner — Aster doesn't charge per message.</p>
            </div>
          ) : waStatus === "pending" ? (
            <div className="rounded-xl border p-4" style={{ borderColor: "#FCD34D", background: "#FFFBEB" }}>
              <p className="text-sm font-medium mb-1" style={{ color: "#92400E" }}>Verification pending</p>
              <p className="text-xs mb-3" style={{ color: "#92400E" }}>
                Your number is registered with our messaging partner. Meta is verifying your business — this usually takes a few hours. We'll email you when it's live.
              </p>
              <button onClick={() => setWaStatus("connected")} className="text-xs rounded-lg bg-neutral-900 hover:bg-neutral-800 text-white px-3 py-1.5 transition-colors">
                Simulate approval (preview)
              </button>
            </div>
          ) : (
            <div>
              <div className="rounded-xl border p-3 mb-3" style={{ borderColor: "var(--line)", background: "var(--bg)" }}>
                <p className="text-xs font-medium text-neutral-700 mb-1.5">Before you connect, you'll need:</p>
                <ul className="space-y-1">
                  <li className="text-xs flex gap-2" style={{ color: "var(--ink-2)" }}><span style={{ color: "var(--brand)" }}>•</span> A Meta Business account</li>
                  <li className="text-xs flex gap-2" style={{ color: "var(--ink-2)" }}><span style={{ color: "var(--brand)" }}>•</span> A phone number <span className="font-medium">not</span> currently on the WhatsApp app</li>
                </ul>
              </div>
              <button
                onClick={connectWhatsApp}
                disabled={waStatus === "connecting"}
                className="text-sm rounded-xl bg-neutral-900 hover:bg-neutral-800 disabled:opacity-50 text-white px-4 py-2 transition-colors"
              >
                {waStatus === "connecting" ? "Connecting…" : "Connect WhatsApp Business"}
              </button>
              <p className="text-xs text-neutral-400 mt-2">We set you up through our WhatsApp messaging partner — no Meta dashboard wrangling. Messages are billed to your own Meta account.</p>
            </div>
          )}
        </div>

        {/* Save / Cancel bar — sticky within the content column, so it never
            underlaps the sidebar or its Log out button on any screen size. */}
        <div className="sticky bottom-4 z-20 mt-6 rounded-2xl border bg-white/95 backdrop-blur px-4 py-3 act-shadow" style={{ borderColor: "var(--line)" }}>
          <div className="flex items-center justify-between gap-3">
            <p className="text-xs sm:text-sm min-w-0 truncate" style={{ color: savedMsg ? "#166534" : "var(--ink-2)" }}>
              {saving ? "Saving…" : savedMsg ? savedMsg : dirty ? "You have unsaved changes." : "Everything is up to date."}
            </p>
            <div className="flex items-center gap-2 shrink-0">
              <button
                onClick={handleCancel}
                disabled={!dirty || saving}
                className="text-sm rounded-xl border px-4 py-2 transition-colors hover:bg-neutral-50 disabled:opacity-40 disabled:cursor-not-allowed"
                style={{ borderColor: "var(--line)", color: "var(--ink-2)" }}
              >
                Cancel
              </button>
              <button
                onClick={handleSave}
                disabled={!dirty || saving}
                className="text-sm rounded-xl brand-gradient hover:opacity-90 text-white font-medium px-5 py-2 transition-opacity disabled:opacity-40 disabled:cursor-not-allowed"
              >
                {saving ? "Saving…" : "Save changes"}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function StatRow({ label, value }) {
  return (
    <div className="min-w-0">
      <p className="text-neutral-500 text-xs">{label}</p>
      <p className="text-neutral-900 truncate">{value}</p>
    </div>
  );
}

function fmtYears(years) {
  if (years == null) return "—";
  return `${years} ${years <= 1 ? "year" : "years"}`;
}
// Prefer years; only fall back to months for sub-year durations (e.g. short gaps).
function fmtMonths(months) {
  if (months == null) return "—";
  if (months >= 12) return fmtYears(Math.round((months / 12) * 10) / 10);
  return `${months} ${months === 1 ? "month" : "months"}`;
}

// A single metric tile: small label with a bold value (and optional sub-line).
function InsightTile({ label, value, sub, accent }) {
  return (
    <div className="rounded-xl px-3.5 py-2.5" style={{ background: accent ? "var(--brand-soft)" : "#F7F7FA", border: "1px solid var(--line)" }}>
      <p className="text-[11px] font-medium truncate" style={{ color: "var(--ink-3)" }}>{label}</p>
      <p className="text-lg font-bold font-display leading-tight mt-0.5" style={{ color: accent ? "var(--brand)" : "var(--ink)" }}>{value}</p>
      {sub && <p className="text-[11px] mt-0.5 truncate" style={{ color: "var(--ink-3)" }}>{sub}</p>}
    </div>
  );
}
// A yes/no signal rendered as a compact pill with an icon.
function InsightFlag({ label, yes }) {
  return (
    <div className="rounded-xl px-3.5 py-2.5 flex items-center justify-between gap-2" style={{ background: "#F7F7FA", border: "1px solid var(--line)" }}>
      <span className="text-[11px] font-medium min-w-0 truncate" style={{ color: "var(--ink-3)" }}>{label}</span>
      <span className="text-xs font-semibold inline-flex items-center gap-1 shrink-0" style={{ color: yes ? "#16A34A" : "var(--ink-3)" }}>
        <Icon name={yes ? "check" : "close"} className="w-3.5 h-3.5" /> {yes ? "Yes" : "No"}
      </span>
    </div>
  );
}
function InsightsDisplay({ insights }) {
  const ei = insights.experience_insights;
  const ea = insights.employment_analysis;
  const heading = (t) => <h3 className="text-[11px] font-semibold uppercase tracking-wide mb-2.5" style={{ color: "var(--ink-3)", letterSpacing: "0.06em" }}>{t}</h3>;

  return (
    <div className="space-y-4">
      <div>
        {heading("Experience insights")}
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-2.5">
          <InsightTile label="Total experience" value={fmtYears(ei.total_experience_years)} accent />
          <InsightTile label="Leadership" value={fmtYears(ei.leadership_experience_years)} />
          {ei.domain_experience.map((d) => (
            <InsightTile key={d.domain} label={`${d.domain}`} value={fmtYears(d.years)} />
          ))}
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-2.5 mt-2.5">
          <InsightFlag label="Startup" yes={ei.startup_experience} />
          <InsightFlag label="Enterprise" yes={ei.enterprise_experience} />
          <InsightFlag label="Remote work" yes={ei.remote_work_mentioned} />
        </div>
      </div>

      <div className="pt-4" style={{ borderTop: "1px solid var(--line)" }}>
        {heading("Employment analysis")}
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-2.5">
          <InsightTile label="Employers" value={String(ea.number_of_employers)} />
          <InsightTile label="Average tenure" value={fmtMonths(ea.average_tenure_months)} />
          {ea.longest_tenure && (
            <InsightTile label="Longest tenure" value={fmtMonths(ea.longest_tenure.months)} sub={ea.longest_tenure.company} />
          )}
        </div>
        {ea.career_progression && (
          <div className="mt-3 rounded-xl px-3.5 py-3 flex items-start gap-2.5" style={{ background: "rgba(151,59,247,0.05)", border: "1px solid rgba(151,59,247,0.13)" }}>
            <span className="shrink-0 mt-0.5" style={{ color: "var(--brand)" }}><Icon name="matching" className="w-4 h-4" /></span>
            <p className="text-sm leading-relaxed" style={{ color: "var(--ink-2)" }}>{ea.career_progression}</p>
          </div>
        )}
        {ea.employment_gaps.length > 0 ? (
          <div className="mt-3 rounded-xl px-3.5 py-3" style={{ background: "#FFFBEB", border: "1px solid #FDE68A" }}>
            <p className="text-xs font-semibold mb-1" style={{ color: "#92400E" }}>Employment gaps</p>
            <ul className="text-sm space-y-0.5" style={{ color: "#92400E" }}>
              {ea.employment_gaps.map((gap, i) => (
                <li key={i}>{gap.start} to {gap.end} <span className="opacity-70">({fmtMonths(gap.duration_months)})</span></li>
              ))}
            </ul>
          </div>
        ) : (
          <p className="text-xs mt-3 flex items-center gap-1.5" style={{ color: "#16A34A" }}>
            <Icon name="check" className="w-3.5 h-3.5" /> No employment gaps of 3+ months detected.
          </p>
        )}
      </div>
    </div>
  );
}

// Mock insights per candidate — stands in for the real Claude analysis
const MOCK_INSIGHTS = {
  c1: {
    generated_at: new Date().toISOString(),
    experience_insights: {
      total_experience_years: 6.5,
      leadership_experience_years: 2,
      domain_experience: [
        { domain: "Fintech", years: 3 },
        { domain: "E-commerce", years: 2.5 },
      ],
      startup_experience: false,
      enterprise_experience: true,
      remote_work_mentioned: true,
    },
    employment_analysis: {
      number_of_employers: 2,
      average_tenure_months: 39,
      longest_tenure: { company: "Grabtech", months: 48 },
      career_progression: "Progressed from Frontend Developer to Senior Frontend Engineer with growing ownership of design system architecture over 6 years.",
      employment_gaps: [],
    },
  },
  c3: {
    generated_at: new Date().toISOString(),
    experience_insights: {
      total_experience_years: 3.2,
      leadership_experience_years: 0,
      domain_experience: [{ domain: "Creative / Agency", years: 3.2 }],
      startup_experience: true,
      enterprise_experience: false,
      remote_work_mentioned: false,
    },
    employment_analysis: {
      number_of_employers: 2,
      average_tenure_months: 19,
      longest_tenure: { company: "Studio Kite", months: 24 },
      career_progression: "Moved from an internship at MDEC into a full creative engineering role at Studio Kite within a year.",
      employment_gaps: [{ start: "Jun 2022", end: "Sep 2022", duration_months: 3 }],
    },
  },
};

// --- Derived AI Experience Insights ---------------------------------------
// When there's no curated MOCK_INSIGHTS for a candidate, compute solid, real
// insights from the parsed resume so every profile shows substantive analysis
// rather than a thin placeholder. This stands in for the real model output.
const LEADERSHIP_RE = /\b(senior|lead|principal|staff|head|director|manager|chief|vp|vice president|founder|co-?founder|president|partner)\b/i;
const DOMAIN_SHORT = {
  "Finance & Fintech": "Fintech", "E-commerce & Retail": "E-commerce", "Media & Creative": "Media",
  "Logistics & Operations": "Logistics", "Travel & Aviation": "Travel", "Professional Services": "Consulting",
  Technology: "Tech", Healthcare: "Healthcare",
};
const ENTERPRISE_COMPANIES = new Set(["MDEC", "iPay88", "Maybank", "Shopee", "Pos Malaysia", "Naga DDB", "Leo Burnett", "AirAsia", "Gleneagles Hospital", "KPMG"]);
const STARTUP_COMPANIES = new Set(["Grabtech", "Grab", "Setel", "StoreHub", "Piktochart", "Oryx Studio", "MoneyLion", "StashAway", "Fave", "Carsome", "FashionValet", "iflix", "Studio Kite"]);
function parseDuration(duration) {
  const nowY = new Date().getFullYear();
  const s = String(duration || "");
  const present = /present|current|now/i.test(s);
  const yrs = (s.match(/\b(?:19|20)\d{2}\b/g) || []).map(Number);
  if (!yrs.length) return null;
  const start = yrs[0];
  const end = present ? nowY : (yrs[1] ?? yrs[0]);
  return { start, end: Math.max(end, start) };
}
function roleMonths(duration) {
  const p = parseDuration(duration);
  if (!p) return 12;
  return Math.max(12, (p.end - p.start) * 12);
}
function deriveInsights(candidate) {
  const p = candidate?.parsed || {};
  const exp = (p.experience || []).filter(Boolean);
  const raw = exp.map((e) => ({ e, months: roleMonths(e.duration) }));
  const rawTotal = raw.reduce((s, r) => s + r.months, 0);
  const totalYears = p.years_of_experience != null ? p.years_of_experience : Math.max(1, Math.round((rawTotal / 12) * 10) / 10);
  // Scale role durations so domain / tenure figures sum to the stated total.
  const scale = (p.years_of_experience != null && rawTotal > 0) ? (p.years_of_experience * 12) / rawTotal : 1;
  const sm = (r) => r.months * scale;
  const yrs = (m) => Math.round((m / 12) * 10) / 10;

  const leadershipMonths = raw.filter((r) => LEADERSHIP_RE.test(r.e.title || "")).reduce((s, r) => s + sm(r), 0);

  const domainMonths = {};
  raw.forEach((r) => { const ind = COMPANY_INDUSTRY[r.e.company]; if (ind) domainMonths[ind] = (domainMonths[ind] || 0) + sm(r); });
  const domain_experience = Object.entries(domainMonths)
    .map(([d, m]) => ({ domain: DOMAIN_SHORT[d] || d, years: yrs(m) }))
    .filter((x) => x.years > 0).sort((a, b) => b.years - a.years).slice(0, 3);

  const companies = raw.map((r) => r.e.company).filter(Boolean);
  const enterprise = companies.some((c) => ENTERPRISE_COMPANIES.has(c));
  const startup = companies.some((c) => STARTUP_COMPANIES.has(c));
  const hay = `${p.summary || ""} ${exp.map((e) => e.summary || "").join(" ")} ${p.location || ""}`.toLowerCase();
  const remote = /\bremote\b|work from home|distributed team|hybrid/.test(hay);

  const distinct = [...new Set(companies)];
  const tenures = raw.map((r) => ({ company: r.e.company, months: Math.round(sm(r)) }));
  const avg = tenures.length ? Math.round(tenures.reduce((s, t) => s + t.months, 0) / tenures.length) : null;
  const longest = tenures.length ? tenures.reduce((a, b) => (b.months > a.months ? b : a)) : null;

  const rt = Math.round(totalYears);
  let progression;
  if (exp.length >= 2) {
    const first = exp[exp.length - 1], last = exp[0];
    progression = `Progressed from ${first.title} at ${first.company} to ${last.title} at ${last.company} across ${rt} year${rt === 1 ? "" : "s"}${yrs(leadershipMonths) >= 1 ? ", stepping into leadership along the way" : ""}.`;
  } else if (exp.length === 1) {
    const e0 = exp[0];
    const focus = (p.skills || []).slice(0, 2).join(" and ");
    progression = `${rt} year${rt === 1 ? "" : "s"} at ${e0.company} as ${e0.title}${focus ? `, with deep hands-on work in ${focus}` : ""}.`;
  } else {
    progression = "The resume lists no dated roles, so a progression can't be inferred.";
  }

  const ranges = raw.map((r) => parseDuration(r.e.duration)).filter(Boolean).sort((a, b) => a.start - b.start);
  const gaps = [];
  for (let i = 1; i < ranges.length; i++) {
    const g = ranges[i].start - ranges[i - 1].end;
    if (g >= 1) gaps.push({ start: String(ranges[i - 1].end), end: String(ranges[i].start), duration_months: g * 12 });
  }

  return {
    generated_at: new Date().toISOString(),
    experience_insights: {
      total_experience_years: totalYears,
      leadership_experience_years: yrs(leadershipMonths),
      domain_experience,
      startup_experience: startup,
      enterprise_experience: enterprise,
      remote_work_mentioned: remote,
    },
    employment_analysis: {
      number_of_employers: distinct.length,
      average_tenure_months: avg,
      longest_tenure: longest ? { company: longest.company, months: longest.months } : null,
      career_progression: progression,
      employment_gaps: gaps,
    },
  };
}

function ScorecardPanel({ scorecards = [], onSubmit, plan = "free", navigate, authorName }) {
  const isPaid = plan !== "free";
  const [open, setOpen] = useState(false);
  const [ratings, setRatings] = useState({ technical: 0, communication: 0, cultureFit: 0, experience: 0 });
  const [rec, setRec] = useState("");
  const [notes, setNotes] = useState("");
  const [privateNote, setPrivateNote] = useState("");
  const [savedNote, setSavedNote] = useState(false);

  const recOf = (key) => RECOMMENDATIONS.find((r) => r.key === key) || RECOMMENDATIONS[1];
  const avgOf = (r) => { const v = Object.values(r); return v.reduce((a, b) => a + b, 0) / v.length; };
  const teamAvg = scorecards.length ? scorecards.reduce((s, c) => s + avgOf(c.ratings), 0) / scorecards.length : 0;
  const canSubmit = rec && Object.values(ratings).every((v) => v > 0);

  const submit = () => {
    if (!canSubmit) return;
    onSubmit({ id: "sc" + Date.now(), interviewer: authorName || "You", ratings, recommendation: rec, notes: notes.trim(), submittedAt: "just now" });
    setRatings({ technical: 0, communication: 0, cultureFit: 0, experience: 0 });
    setRec("");
    setNotes("");
    setOpen(false);
  };

  return (
    <div className="mb-6 rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]">
      <div className="flex items-center justify-between gap-2 mb-3">
        <div className="flex items-center gap-2">
          <h2 className="text-sm font-medium text-neutral-600 uppercase tracking-wide">Team scorecards</h2>
          <InfoHint dir="down" hint="Each interviewer rates the candidate from 1 to 4 after the interview, and Aster averages them into one team score." />
          {!isPaid && <LockBadge />}
        </div>
        {isPaid && scorecards.length > 0 && (
          <span className="text-xs text-neutral-500">Team avg <span className="font-semibold text-neutral-800 tnum">{teamAvg.toFixed(1)}</span>/4 · {scorecards.length} submitted</span>
        )}
      </div>

      {!isPaid ? (
        <div>
          <div className="rounded-xl border p-3 mb-3 flex items-center justify-between gap-3" style={{ borderColor: "var(--line)", background: "var(--brand-soft)" }}>
            <p className="text-xs" style={{ color: "var(--ink-2)" }}>
              Structured scorecards from every interviewer are a <span className="font-semibold">Pro</span> feature. On Free you can keep one private note.
            </p>
            <button onClick={() => navigate("billing")} className="text-xs brand-gradient text-white font-medium px-3 py-1.5 rounded-lg shrink-0 hover:opacity-90 transition-opacity">Upgrade</button>
          </div>
          <textarea
            rows={3}
            value={privateNote}
            onChange={(e) => { setPrivateNote(e.target.value); setSavedNote(false); }}
            placeholder="Private note (only you can see this)…"
            className="w-full rounded-xl bg-neutral-100 border border-neutral-200 px-3 py-2 text-neutral-900 text-sm focus:outline-none focus:ring-2 focus:ring-neutral-400"
          />
          <div className="flex items-center gap-3 mt-2">
            <button onClick={() => setSavedNote(true)} disabled={!privateNote.trim()} className="text-xs rounded-lg bg-neutral-900 hover:bg-neutral-800 disabled:opacity-40 text-white px-3 py-1.5 transition-colors">Save note</button>
            {savedNote && <span className="text-xs" style={{ color: "#166534" }}>Saved ✓</span>}
          </div>
        </div>
      ) : (
        <div className="space-y-3">
          {scorecards.length === 0 && !open && (
            <p className="text-sm text-neutral-500">No scorecards yet. Add yours after the interview, and your teammates' will collect here.</p>
          )}

          {scorecards.map((sc) => {
            const r = recOf(sc.recommendation);
            return (
              <div key={sc.id} className="rounded-xl border p-3" style={{ borderColor: "var(--line)" }}>
                <div className="flex items-center justify-between gap-2 mb-2">
                  <p className="text-sm font-medium text-neutral-900">{sc.interviewer} <span className="text-xs text-neutral-400 font-normal">· {sc.submittedAt}</span></p>
                  <span className="text-[10px] px-2 py-0.5 rounded-full font-semibold shrink-0" style={{ background: r.bg, color: r.color }}>{r.label}</span>
                </div>
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mb-2">
                  {SCORE_CRITERIA.map((c) => (
                    <div key={c.key} className="rounded-lg bg-neutral-50 px-2 py-1.5">
                      <p className="text-[11px] text-neutral-500 leading-tight">{c.label}</p>
                      <p className="text-sm font-semibold text-neutral-900 tnum">{sc.ratings[c.key]}<span className="text-[10px] text-neutral-400">/4</span></p>
                    </div>
                  ))}
                </div>
                {sc.notes && <p className="text-sm text-neutral-600">{sc.notes}</p>}
              </div>
            );
          })}

          {open ? (
            <div className="rounded-xl border p-3 space-y-3" style={{ borderColor: "var(--brand)", background: "var(--brand-soft)" }}>
              <p className="text-sm font-semibold text-neutral-900">Your scorecard</p>
              {SCORE_CRITERIA.map((c) => (
                <div key={c.key} className="flex items-center justify-between gap-2">
                  <span className="text-sm text-neutral-700">{c.label}</span>
                  <div className="flex gap-1">
                    {[1, 2, 3, 4].map((n) => (
                      <button
                        key={n}
                        onClick={() => setRatings((rr) => ({ ...rr, [c.key]: n }))}
                        className="w-8 h-8 rounded-lg text-sm font-medium transition-colors"
                        style={ratings[c.key] === n ? { background: "var(--brand)", color: "#fff" } : { background: "#fff", color: "var(--ink-2)", border: "1px solid var(--line-strong)" }}
                      >
                        {n}
                      </button>
                    ))}
                  </div>
                </div>
              ))}
              <div>
                <p className="text-sm text-neutral-700 mb-1.5">Recommendation</p>
                <div className="flex flex-wrap gap-1.5">
                  {RECOMMENDATIONS.map((r) => (
                    <button
                      key={r.key}
                      onClick={() => setRec(r.key)}
                      className="text-xs px-2.5 py-1.5 rounded-lg font-medium transition-colors"
                      style={rec === r.key ? { background: r.color, color: "#fff" } : { background: "#fff", color: "var(--ink-2)", border: "1px solid var(--line-strong)" }}
                    >
                      {r.label}
                    </button>
                  ))}
                </div>
              </div>
              <textarea
                rows={2}
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
                placeholder="Notes for the team…"
                className="w-full rounded-xl bg-white border border-neutral-200 px-3 py-2 text-neutral-900 text-sm focus:outline-none focus:ring-2 focus:ring-neutral-400"
              />
              <div className="flex items-center gap-2">
                <button onClick={submit} disabled={!canSubmit} className="text-sm rounded-xl brand-gradient disabled:opacity-40 text-white font-medium px-4 py-2 transition-opacity hover:opacity-90">Submit scorecard</button>
                <button onClick={() => setOpen(false)} className="text-sm rounded-xl border px-4 py-2 transition-colors hover:bg-white" style={{ borderColor: "var(--line-strong)", color: "var(--ink-2)" }}>Cancel</button>
              </div>
            </div>
          ) : (
            <button onClick={() => setOpen(true)} className="text-sm rounded-xl bg-neutral-900 hover:bg-neutral-800 text-white px-4 py-2 transition-colors">
              + Add your scorecard
            </button>
          )}
        </div>
      )}
    </div>
  );
}

function CandidateProfileScreen({ navigate, candidate, jobs, interviewers, onPreviewBooking, contextJobId, initialStage, booking, onInviteSent, provider = "google", calendarConnected = false, plan = "free", scorecards = [], onSubmitScorecard, stage = "applied", onSetStage, offer, onSendOffer, onRespondOffer, hiredIds = new Set(), profile, avatarUrl = null, activities = [], onOpenNotifications, aiInsightsUsed = 0, setAiInsightsUsed, insightsCache = {}, setInsightsCache }) {
  // Insights are never generated automatically. Once a user runs them they're
  // saved in a session cache keyed by candidate id, so returning to the profile
  // shows the saved result without spending another credit.
  const insights = candidate ? (insightsCache[candidate.id] ?? null) : null;
  const [generating, setGenerating] = useState(false);
  const [showPdf, setShowPdf] = useState(false);
  // AI Experience Insights are metered per plan, like AI match runs.
  const insightsLimit = planLimits(plan).aiInsightsPerMonth;
  const insightsUnlimited = insightsLimit === Infinity;
  const insightsLeft = Math.max(0, insightsLimit - aiInsightsUsed);
  const outOfInsights = !insightsUnlimited && insightsLeft <= 0;
  const [showOffer, setShowOffer] = useState(false);
  // Database-view invite: pick an open role, draft a re-engagement email, and
  // send it to the candidate's profile email. If they apply, they drop their
  // latest resume and move into the hiring workflow.
  const [inviteJobId, setInviteJobId] = useState("");
  const [inviteSent, setInviteSent] = useState(false);
  const [inviteMsg, setInviteMsg] = useState(null);
  // Questions unlock once the interview is actually booked: either the shared
  // booking shows the candidate confirmed a time, or the application is already
  // at the interviewing/offer/hired stage.
  // Interview questions are only available once an interview is actually
  // scheduled — not merely because the candidate sits at a later stage.
  const isBooked = booking?.status === "scheduled";
  const questionsUnlocked = isBooked;
  // Detect whether the scheduled interview has already happened (its slot is in
  // the past). Scorecards + the decision step only make sense post-interview.
  const interviewStart = booking?.confirmedSlot?.start ? new Date(booking.confirmedSlot.start) : null;
  const interviewPast = isBooked && interviewStart && interviewStart.getTime() < Date.now();
  const interviewWhen = interviewStart
    ? interviewStart.toLocaleDateString(undefined, { day: "numeric", month: "short" }) + ", " + interviewStart.toLocaleTimeString(undefined, { hour: "numeric", minute: "2-digit" })
    : null;
  const stageRank = { applied: 0, shortlisted: 1, interviewing: 2, offer: 3, hired: 4, rejected: 5 };
  const decided = stage === "hired" || stage === "rejected";
  // A hired (or rejected) candidate is closed out — no more scheduling or offers.
  const isHired = hiredIds.has(candidate?.id) || stage === "hired";
  const isClosed = isHired || stage === "rejected";
  // Offer response state: 'sent' (awaiting candidate) | 'accepted' | 'declined'.
  const offerStatus = offer?.status || (isHired ? "accepted" : stage === "offer" ? "sent" : null);
  const hasEmail = !!candidate?.parsed?.email;
  const firstName = candidate?.parsed?.name ? candidate.parsed.name.split(" ")[0] : "the candidate";

  if (!candidate) {
    return (
      <div className="px-4 sm:px-6 py-8 sm:py-10">
        <div className="max-w-2xl mx-auto">
          <BackLink onClick={() => navigate("dashboard")}>← Back</BackLink>
          <p className="text-sm text-neutral-500 mt-4">Candidate not found.</p>
        </div>
      </div>
    );
  }

  const parsed = candidate.parsed;

  const handleGenerate = () => {
    if (!candidate) return;
    // Gate on the plan's monthly allowance; a fresh (not cached) run consumes one.
    if (outOfInsights && !insights) { navigate("billing"); return; }
    if (!insightsUnlimited && setAiInsightsUsed) setAiInsightsUsed((n) => n + 1);
    setGenerating(true);
    setTimeout(() => {
      const result = MOCK_INSIGHTS[candidate.id] ?? deriveInsights(candidate);
      if (setInsightsCache) setInsightsCache((prev) => ({ ...prev, [candidate.id]: result })); // save & keep
      setGenerating(false);
    }, 1600);
  };

  const openJobsForInvite = (jobs || []).filter((j) => j.status === "open");
  const candidateEmail = candidate?.parsed?.email || "";
  const pickInviteJob = (id) => { setInviteJobId(id); setInviteSent(false); setInviteMsg(null); };
  const sendInviteEmail = () => {
    const job = jobs.find((j) => j.id === inviteJobId);
    if (!job || !candidateEmail) return;
    setInviteSent(true);
    setInviteMsg(`Invite sent to ${candidateEmail} using the Sourcing invite template. When ${firstName} applies through the link, AI refreshes the profile with their latest resume and moves them into your hiring workflow.`);
  };

  // Reworked AI Experience Insights card — plan-metered (meter lives in sidebar).
  const aiInsightsCard = (
    <div className="rounded-2xl p-5 relative" style={{ background: "linear-gradient(135deg, rgba(214,91,255,0.07), rgba(90,120,248,0.06))", border: "1px solid var(--line)" }}>
      <div className="flex items-start justify-between gap-3 mb-2.5">
        <div className="flex items-center gap-2 min-w-0">
          <span className="w-8 h-8 rounded-xl brand-gradient flex items-center justify-center text-white shrink-0 shadow-[0_8px_20px_-8px_rgba(151,59,247,0.7)]"><Icon name="matching" className="w-4 h-4" /></span>
          <h2 className="text-sm font-semibold font-display" style={{ color: "var(--ink)" }}>AI Experience Insights</h2>
          <InfoHint dir="down" hint="An optional AI read of the resume that estimates total and leadership experience, time at each employer, and any gaps. Each run uses one of your monthly AI insight credits." />
        </div>
        {insights && <span className="text-[11px] shrink-0 mt-1.5" style={{ color: "var(--ink-3)" }}>Generated {new Date(insights.generated_at).toLocaleDateString()}</span>}
      </div>

      {!insights ? (
        outOfInsights ? (
          <div className="rounded-xl bg-white border p-4 flex items-start gap-3" style={{ borderColor: "var(--line)" }}>
            <span className="w-8 h-8 rounded-lg flex items-center justify-center shrink-0" style={{ background: "var(--brand-soft)", color: "var(--brand)" }}><Icon name="lock" className="w-4 h-4" /></span>
            <div className="min-w-0">
              <p className="text-sm font-semibold" style={{ color: "var(--ink)" }}>You're out of AI insights</p>
              <p className="text-xs mt-0.5 mb-2.5" style={{ color: "var(--ink-3)" }}>You've used all {insightsLimit} AI insight runs on your plan this month. Upgrade for more, or they reset on the 1st.</p>
              <button onClick={() => navigate("billing")} className="rounded-xl brand-gradient hover:opacity-95 text-white text-xs font-semibold px-3.5 py-2 inline-flex items-center gap-1.5 transition-all hover:-translate-y-0.5 shadow-[0_10px_24px_-12px_rgba(151,59,247,0.8)]"><Icon name="arrowUpRight" className="w-3.5 h-3.5" /> Upgrade for more</button>
            </div>
          </div>
        ) : (
          <>
            <p className="text-sm mb-3" style={{ color: "var(--ink-2)" }}>Run a deeper AI read of this resume: total and leadership experience, domain exposure, employer tenure, and any employment gaps.</p>
            <button onClick={handleGenerate} disabled={generating} className="rounded-xl brand-gradient hover:opacity-95 disabled:opacity-50 text-white text-sm font-semibold px-4 py-2.5 inline-flex items-center gap-2 transition-all enabled:hover:-translate-y-0.5 shadow-[0_12px_30px_-12px_rgba(151,59,247,0.8)]">
              <Icon name="matching" className="w-4 h-4" /> {generating ? "Analyzing…" : "Generate AI insights"}
            </button>
          </>
        )
      ) : (
        <div className="rounded-xl bg-white border p-4" style={{ borderColor: "var(--line)" }}>
          <InsightsDisplay insights={insights} />
          <button onClick={handleGenerate} disabled={generating || outOfInsights} className="mt-3 text-xs font-medium disabled:opacity-50 hover:opacity-70 transition-opacity" style={{ color: "var(--brand)" }}>
            {generating ? "Re-analyzing…" : outOfInsights ? "No AI insight runs left this month" : "Regenerate"}
          </button>
        </div>
      )}

    </div>
  );

  // Sidebar "at a glance" card — scannable summary that fills the second column.
  const topRole = parsed.experience?.[0];
  const quickFacts = (
    <div className="rounded-2xl bg-white border p-5" style={{ borderColor: "var(--line)" }}>
      <h2 className="text-[11px] font-semibold uppercase tracking-wide mb-3" style={{ color: "var(--ink-2)", letterSpacing: "0.06em" }}>At a glance</h2>
      <div className="space-y-3">
        {contextJobId && (
          <div className="flex items-center justify-between gap-2">
            <span className="text-xs" style={{ color: "var(--ink-3)" }}>Pipeline stage</span>
            <StageBadge stage={stage} />
          </div>
        )}
        {parsed.years_of_experience != null && (
          <div className="flex items-center justify-between gap-2">
            <span className="text-xs" style={{ color: "var(--ink-3)" }}>Experience</span>
            <span className="text-sm font-medium" style={{ color: "var(--ink)" }}>{parsed.years_of_experience} yrs</span>
          </div>
        )}
        {topRole && (
          <div className="flex items-start justify-between gap-2">
            <span className="text-xs shrink-0" style={{ color: "var(--ink-3)" }}>Current role</span>
            <span className="text-sm font-medium text-right min-w-0" style={{ color: "var(--ink)" }}>{topRole.title}<span className="block text-xs font-normal" style={{ color: "var(--ink-3)" }}>{topRole.company}</span></span>
          </div>
        )}
        {parsed.location && (
          <div className="flex items-center justify-between gap-2">
            <span className="text-xs" style={{ color: "var(--ink-3)" }}>Location</span>
            <span className="text-sm font-medium text-right" style={{ color: "var(--ink)" }}>{parsed.location}</span>
          </div>
        )}
      </div>
      {parsed.skills?.length > 0 && (
        <div className="mt-4 pt-3.5" style={{ borderTop: "1px solid var(--line)" }}>
          <p className="text-[11px] font-medium mb-2" style={{ color: "var(--ink-3)" }}>Top skills</p>
          <div className="flex flex-wrap gap-1.5">
            {parsed.skills.slice(0, 6).map((s) => <span key={s} className="text-[11px] rounded-full px-2 py-0.5 font-medium" style={{ background: "var(--brand-soft)", color: "var(--brand)" }}>{s}</span>)}
          </div>
        </div>
      )}
      {parsed.industries?.length > 0 && (
        <div className="mt-4 pt-3.5" style={{ borderTop: "1px solid var(--line)" }}>
          <p className="text-[11px] font-medium mb-2" style={{ color: "var(--ink-3)" }}>Industry experience</p>
          <div className="flex flex-wrap gap-1.5">
            {parsed.industries.map((ind) => <span key={ind} className="text-[11px] rounded-full px-2 py-0.5 font-medium" style={{ background: "var(--line)", color: "var(--ink-2)" }}>{ind}</span>)}
          </div>
        </div>
      )}
    </div>
  );

  return (
    <div className="px-4 sm:px-6 py-6 sm:py-8">
      <div className="max-w-[1400px] mx-auto">
        <BackLink onClick={() => navigate(-1)}>← Back</BackLink>

        {/* Standard app header */}
        <div className="mt-2">
          <TopBar
            title="Candidate Profile"
            subtitle={contextJobId
              ? `In the ${(jobs.find((j) => j.id === contextJobId) || {}).title || "role"} pipeline`
              : "From your candidate database"}
            activities={activities}
            onOpenNotifications={onOpenNotifications}
            avatarUrl={avatarUrl}
            profile={profile}
            navigate={navigate}
          />
        </div>

        {/* Identity banner (full width) */}
        <div className="rounded-2xl bg-white border p-5 sm:p-6 flex flex-col sm:flex-row sm:items-center gap-4" style={{ borderColor: "var(--line)" }}>
          <CandidateAvatar name={parsed.name} hasPhoto={candidate.hasPhoto} src={candidate.avatarUrl} size={64} />
          <div className="min-w-0 flex-1">
            <div className="flex items-center gap-2 flex-wrap">
              <h2 className="text-xl sm:text-2xl font-bold font-display" style={{ color: "var(--ink)" }}>{parsed.name}</h2>
              {contextJobId && <StageBadge stage={stage} />}
            </div>
            <div className="flex flex-wrap items-center gap-x-3 gap-y-1 mt-1.5 text-sm" style={{ color: "var(--ink-3)" }}>
              {parsed.email && <span>{parsed.email}</span>}
              {parsed.phone && <span>{parsed.phone}</span>}
              {parsed.location && <span>{parsed.location}</span>}
              {parsed.years_of_experience != null && <span>{parsed.years_of_experience} yrs experience</span>}
            </div>
            {(parsed.linkedin_url || parsed.portfolio_url) && (
              <div className="flex items-center gap-3 mt-2">
                {parsed.linkedin_url && <span className="text-xs" style={{ color: "var(--brand)" }}>LinkedIn ↗</span>}
                {parsed.portfolio_url && <span className="text-xs" style={{ color: "var(--brand)" }}>Portfolio ↗</span>}
              </div>
            )}
          </div>
          <div className="flex items-center gap-2 shrink-0 self-start sm:self-center">
            {planLimits(plan).storeOriginal ? (
              <button onClick={() => setShowPdf(true)} className="rounded-xl bg-neutral-100 hover:bg-neutral-200 text-sm text-neutral-800 px-3 py-1.5 transition-colors inline-flex items-center gap-1.5">
                <Icon name="doc" className="w-4 h-4" /> View original PDF
              </button>
            ) : (
              <button onClick={() => navigate("billing")} className="rounded-xl text-xs px-3 py-1.5 inline-flex items-center gap-1.5 transition-colors hover:opacity-80" style={{ background: "var(--brand-soft)", color: "var(--brand)" }} title="On Free, the original file isn't stored">
                <Icon name="lock" className="w-3.5 h-3.5" /> Original not stored · Pro
              </button>
            )}
          </div>
        </div>

        {/* Two columns: resume + workflow in main, insights + summary in the sidebar */}
        <div className="grid lg:grid-cols-3 gap-5 mt-5 items-start">
          <div className="lg:col-span-2 space-y-5">
            {aiInsightsCard}

        {parsed.summary && (
          <div className="mb-6 rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]">
            <h2 className="text-sm font-medium text-neutral-600 mb-3 uppercase tracking-wide">Summary</h2>
            <p className="text-sm text-neutral-700">{parsed.summary}</p>
          </div>
        )}

        <div className="mb-6 rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]">
          <h2 className="text-sm font-medium text-neutral-600 mb-3 uppercase tracking-wide">Skills</h2>
          <div className="flex flex-wrap gap-2">
            {parsed.skills?.length ? parsed.skills.map((skill) => (
              <span key={skill} className="text-xs rounded-full bg-neutral-100 border border-neutral-200 px-3 py-1 text-neutral-700">
                {skill}
              </span>
            )) : (
              <p className="text-sm text-neutral-400">No skills detected in this resume.</p>
            )}
          </div>
        </div>

        <div className="mb-6 rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]">
          <h2 className="text-sm font-medium text-neutral-600 mb-3 uppercase tracking-wide">Experience</h2>
          <div className="space-y-4">
            {parsed.experience?.length ? parsed.experience.map((exp, i) => (
              <div key={i}>
                <div className="flex flex-col sm:flex-row sm:items-baseline sm:justify-between gap-x-2">
                  <p className="text-neutral-900 text-sm font-medium">
                    {exp.title} · {exp.company}
                    {exp.industry && !/^unknown$/i.test(exp.industry) && (
                      <span className="ml-2 align-middle text-[10px] rounded-full px-1.5 py-0.5 font-medium" style={{ background: "var(--line)", color: "var(--ink-3)" }}>{exp.industry}</span>
                    )}
                  </p>
                  <span className="text-xs text-neutral-500 shrink-0">{exp.duration}</span>
                </div>
                <p className="text-sm text-neutral-600 mt-1">{exp.summary}</p>
              </div>
            )) : (
              <p className="text-sm text-neutral-400">No work experience detected in this resume.</p>
            )}
          </div>
        </div>

        <div className="mb-6 rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]">
          <h2 className="text-sm font-medium text-neutral-600 mb-3 uppercase tracking-wide">Education</h2>
          <div className="space-y-2">
            {parsed.education?.length ? parsed.education.map((ed, i) => (
              <div key={i} className="flex flex-col sm:flex-row sm:items-baseline sm:justify-between gap-x-2">
                <p className="text-neutral-900 text-sm">{ed.degree} · {ed.institution}</p>
                <span className="text-xs text-neutral-500 shrink-0">{ed.year}</span>
              </div>
            )) : (
              <p className="text-sm text-neutral-400">No education detected in this resume.</p>
            )}
          </div>
        </div>

        {parsed.certifications && parsed.certifications.length > 0 && (
          <div className="mb-6 rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]">
            <h2 className="text-sm font-medium text-neutral-600 mb-3 uppercase tracking-wide">Certifications</h2>
            <ul className="text-sm text-neutral-700 space-y-1 list-disc list-inside">
              {parsed.certifications.map((cert) => (
                <li key={cert}>{cert}</li>
              ))}
            </ul>
          </div>
        )}

        {parsed.languages && parsed.languages.length > 0 && (
          <div className="mb-6 rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]">
            <h2 className="text-sm font-medium text-neutral-600 mb-3 uppercase tracking-wide">Languages</h2>
            <div className="flex flex-wrap gap-2">
              {parsed.languages.map((lang) => (
                <span key={lang} className="text-xs rounded-full bg-neutral-100 border border-neutral-200 px-3 py-1 text-neutral-700">
                  {lang}
                </span>
              ))}
            </div>
          </div>
        )}

        <div className="mb-6 rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]">
          <h2 className="text-sm font-medium text-neutral-600 mb-3 uppercase tracking-wide">Salary Expectation</h2>
          {parsed.salary_expectation ? (
            <p className="text-sm text-neutral-900">{parsed.salary_expectation}</p>
          ) : (
            <div className="flex items-start gap-2">
              <span className="text-amber-600 text-sm shrink-0">⚠</span>
              <p className="text-sm text-amber-700">
                Not stated in resume. AI could not find a salary expectation — please confirm
                directly with the candidate.
              </p>
            </div>
          )}
        </div>

        {/* Database view — this candidate isn't in a pipeline for a job you're
            viewing, so interview / scorecard / decision tools are hidden. Show
            their profile and a way to invite them to apply, even if it's an old
            profile. Those tools appear once they actually apply to a role. */}
        {!contextJobId && (
          <div className="mt-2 mb-6 rounded-2xl p-5 relative" style={{ background: "linear-gradient(135deg, rgba(214,91,255,0.06), rgba(90,120,248,0.05))", border: "1px solid var(--line)" }}>
            <div className="flex items-start gap-3">
              <span className="w-9 h-9 rounded-xl brand-gradient flex items-center justify-center text-white shrink-0 shadow-[0_8px_20px_-8px_rgba(151,59,247,0.7)]">
                <Icon name="briefcase" className="w-4 h-4" />
              </span>
              <div className="min-w-0 flex-1">
                <h2 className="text-sm font-semibold font-display" style={{ color: "var(--ink)" }}>{isHired ? `${firstName} is already hired` : `Invite ${firstName} to apply`}</h2>
                <p className="text-xs mt-0.5" style={{ color: "var(--ink-3)" }}>
                  {isHired
                    ? "This person is already on the team, so there's nothing to invite them to."
                    : "They're in your database from an earlier point, not yet in a pipeline. Email them about an open role. If they're still keen, they apply with their latest resume and move into your hiring workflow."}
                </p>
                {!isHired && (openJobsForInvite.length === 0 ? (
                  <p className="text-xs mt-3" style={{ color: "var(--ink-3)" }}>No open roles yet. Create one under Job Postings.</p>
                ) : (
                  <div className="mt-3">
                    <FieldLabel hint="Pick an open role. Aster emails the candidate the Sourcing invite template with a link to apply.">Open role</FieldLabel>
                    <JobSelect jobs={openJobsForInvite} value={inviteJobId} onChange={pickInviteJob} placeholder="Select an open role…" />
                    <p className="text-xs mt-2.5 flex items-start gap-1.5" style={{ color: "var(--ink-3)" }}>
                      <Icon name="chat" className="w-3.5 h-3.5 shrink-0 mt-0.5" style={{ color: "var(--brand)" }} />
                      <span>Emails {candidateEmail || "this candidate"} using the <span className="font-medium" style={{ color: "var(--ink-2)" }}>Sourcing invite</span> template, with the apply link added automatically. <button onClick={() => navigate("emailTemplates")} className="font-medium hover:opacity-70 transition-opacity" style={{ color: "var(--brand)" }}>Edit template</button></span>
                    </p>
                    <button onClick={sendInviteEmail} disabled={!inviteJobId || !candidateEmail || inviteSent}
                      className="mt-3 w-full sm:w-auto rounded-xl brand-gradient hover:opacity-95 disabled:opacity-40 disabled:cursor-not-allowed text-white text-sm font-semibold px-5 py-2.5 inline-flex items-center justify-center gap-2 transition-all enabled:hover:-translate-y-0.5 shadow-[0_12px_30px_-12px_rgba(151,59,247,0.8)]">
                      <Icon name={inviteSent ? "check" : "chat"} className="w-4 h-4" /> {inviteSent ? "Invite sent" : "Send invite"}
                    </button>
                  </div>
                ))}
                {inviteMsg && (
                  <div className="mt-3 rounded-xl px-3.5 py-2.5 flex items-start gap-2" style={{ background: "rgba(16,185,129,0.08)", border: "1px solid rgba(16,185,129,0.25)" }}>
                    <span className="shrink-0 mt-0.5" style={{ color: "#059669" }}><Icon name="check" className="w-4 h-4" /></span>
                    <p className="text-xs" style={{ color: "#047857" }}>{inviteMsg}</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {contextJobId && (<>
        {isClosed && (
          <div className="mt-2 mb-6 rounded-2xl border p-5" style={{ borderColor: isHired ? "#BBF7D0" : "var(--line)", background: isHired ? "#F0FDF4" : "var(--bg)" }}>
            {isHired ? (
              <>
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-lg">🎉</span>
                  <h2 className="text-sm font-semibold" style={{ color: "#166534" }}>Hired</h2>
                </div>
                <p className="text-sm" style={{ color: "#166534" }}>
                  {parsed.name.split(" ")[0]} has been hired and is no longer part of active interviewing. Their record stays here, but they won't appear in matching or be schedulable.
                </p>
              </>
            ) : (
              <>
                <h2 className="text-sm font-semibold mb-1" style={{ color: "var(--ink)" }}>Not proceeding</h2>
                <p className="text-sm mb-3" style={{ color: "var(--ink-2)" }}>
                  This candidate was rejected, so interview scheduling is closed.
                </p>
                <button onClick={() => onSetStage && onSetStage("interviewing")} className="text-xs rounded-xl border font-medium px-3 py-1.5 transition-colors hover:bg-neutral-50" style={{ borderColor: "var(--line-strong)", color: "var(--ink-2)" }}>
                  Reopen candidate
                </button>
              </>
            )}
          </div>
        )}

        {!isClosed && (<>
        <ScheduleInterviewPanel
          candidate={candidate}
          jobs={jobs}
          interviewers={interviewers}
          onPreviewBooking={onPreviewBooking}
          contextJobId={contextJobId}
          booking={booking}
          onInviteSent={onInviteSent}
          provider={provider}
          calendarConnected={calendarConnected}
        />

        <InterviewQuestionsPanel
          candidate={candidate}
          jobs={jobs}
          contextJobId={contextJobId}
          isScheduled={questionsUnlocked}
        />

        {/* After the interview — unlocks once the scheduled slot is in the past.
            This closes the gap between "interview scheduled" and a hire/reject
            decision: collect team scorecards, then move the candidate forward. */}
        {isBooked && !interviewPast && (
          <div className="mt-6 rounded-2xl border border-dashed p-4 flex items-start gap-3" style={{ borderColor: "var(--line-strong)", background: "var(--bg)" }}>
            <Icon name="lock" className="w-4 h-4 mt-0.5 shrink-0" style={{ color: "var(--ink-3)" }} />
            <p className="text-xs leading-relaxed" style={{ color: "var(--ink-2)" }}>
              Interview set for <span className="font-semibold">{interviewWhen}</span>. Once it's done, team scorecards and the hire / reject decision will unlock here.
            </p>
          </div>
        )}

        {interviewPast && (
          <div className="mt-6">
            <div className="flex items-center gap-2 mb-3">
              <span className="text-xs font-semibold uppercase tracking-wide" style={{ color: "var(--ink-3)", letterSpacing: "0.06em" }}>After the interview</span>
              <span className="text-[11px] px-2 py-0.5 rounded-full font-medium" style={{ background: "#DCFCE7", color: "#166534" }}>Interview done · {interviewWhen}</span>
            </div>

            <ScorecardPanel
              scorecards={scorecards}
              onSubmit={onSubmitScorecard}
              plan={plan}
              navigate={navigate}
              authorName={`${profile?.firstName || "You"} ${profile?.lastName || ""}`.trim()}
            />

            {/* Decision / next step */}
            <div className="mt-4 rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]">
              <h2 className="text-sm font-medium text-neutral-600 mb-1 uppercase tracking-wide">Decision</h2>

              {stage === "hired" ? (
                <div className="mt-2">
                  <div className="flex items-center gap-2">
                    <span className="text-sm font-semibold" style={{ color: "#166534" }}>✓ Hired</span>
                    <span className="text-xs text-neutral-500">{firstName} accepted the offer.</span>
                  </div>
                </div>
              ) : stage === "rejected" ? (
                <div className="flex items-center justify-between gap-3 mt-2">
                  <span className="text-sm text-neutral-500">Not proceeding with this candidate.</span>
                  <button onClick={() => onSetStage && onSetStage("interviewing")} className="text-xs text-neutral-500 underline underline-offset-2 hover:text-neutral-800 shrink-0">Undo</button>
                </div>
              ) : offerStatus === "declined" ? (
                <div className="mt-2">
                  <div className="rounded-xl border p-3 mb-3" style={{ borderColor: "#FECDD3", background: "#FFF1F2" }}>
                    <p className="text-sm font-medium" style={{ color: "#9F1239" }}>{firstName} declined the offer.</p>
                    <p className="text-xs mt-0.5" style={{ color: "#9F1239" }}>They let you know they won't be proceeding.</p>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    <button onClick={() => setShowOffer(true)} className="text-sm rounded-xl border font-medium px-4 py-2 transition-colors hover:bg-neutral-50" style={{ borderColor: "var(--line-strong)", color: "var(--ink-2)" }}>
                      Re-send offer
                    </button>
                    <button onClick={() => onSetStage && onSetStage("rejected")} className="text-sm rounded-xl border font-medium px-4 py-2 transition-colors hover:bg-neutral-50" style={{ borderColor: "var(--line-strong)", color: "var(--ink-2)" }}>
                      Close as rejected
                    </button>
                  </div>
                </div>
              ) : offerStatus === "sent" ? (
                <div className="mt-2">
                  <div className="rounded-xl border p-3 mb-3" style={{ borderColor: "#BFDBFE", background: "#EFF6FF" }}>
                    <p className="text-sm font-medium" style={{ color: "#1E40AF" }}>Offer sent — awaiting {firstName}'s response</p>
                    <p className="text-xs mt-0.5" style={{ color: "#1E40AF" }}>
                      {offer?.emailSent === false
                        ? "Recorded internally (no email on file). Update the stage once they confirm."
                        : `${firstName} was emailed that they've been selected and asked to accept or decline. The HR team will follow up with details.`}
                    </p>
                  </div>
                  <p className="text-[11px] mb-2" style={{ color: "var(--ink-3)" }}>Preview — simulate the candidate's reply:</p>
                  <div className="flex flex-wrap gap-2">
                    <button onClick={() => onRespondOffer && onRespondOffer(true)} className="text-sm rounded-xl brand-gradient text-white font-medium px-4 py-2 hover:opacity-90 transition-opacity">
                      Candidate accepts ✓
                    </button>
                    <button onClick={() => onRespondOffer && onRespondOffer(false)} className="text-sm rounded-xl border font-medium px-4 py-2 transition-colors hover:bg-neutral-50" style={{ borderColor: "var(--line-strong)", color: "var(--ink-2)" }}>
                      Candidate declines
                    </button>
                  </div>
                </div>
              ) : (
                <>
                  <p className="text-sm text-neutral-600 mb-3">
                    Once your team has scored the interview, move {firstName} to the next step.
                  </p>
                  <div className="flex flex-wrap gap-2">
                    <button onClick={() => setShowOffer(true)} className="text-sm rounded-xl brand-gradient text-white font-medium px-4 py-2 hover:opacity-90 transition-opacity">
                      Make an offer →
                    </button>
                    <button onClick={() => onSetStage && onSetStage("rejected")} className="text-sm rounded-xl border font-medium px-4 py-2 transition-colors hover:bg-neutral-50" style={{ borderColor: "var(--line-strong)", color: "var(--ink-2)" }}>
                      Reject
                    </button>
                  </div>
                  <p className="text-[11px] mt-3" style={{ color: "var(--ink-3)" }}>
                    Current stage: <span className="font-medium">{stage.charAt(0).toUpperCase() + stage.slice(1)}</span>
                  </p>
                </>
              )}
            </div>
          </div>
        )}
        </>)}

        {showOffer && (
          <OfferModal
            candidateName={parsed.name}
            jobTitle={(jobs.find((j) => j.id === contextJobId) || {}).title || "the role"}
            hasEmail={hasEmail}
            onClose={() => setShowOffer(false)}
            onSend={(emailSent) => { setShowOffer(false); onSendOffer && onSendOffer(emailSent); }}
          />
        )}
        </>)}
          </div>{/* main column */}
          <aside className="space-y-5 lg:sticky lg:top-4 lg:self-start">
            {quickFacts}
            {!insightsUnlimited && (
              <UsageMeter
                title="AI insights this month"
                hint="Each AI Experience Insights run uses one credit. Your plan includes a set number each month."
                used={aiInsightsUsed} limit={insightsLimit} unit="used"
                note={outOfInsights
                  ? `You've used all ${insightsLimit} AI insight runs. Resets on the 1st.`
                  : `${insightsLeft} insight run${insightsLeft === 1 ? "" : "s"} left this month.`}
                onManage={() => navigate("billing")} onUpgrade={() => navigate("billing")} upgradeLabel="Upgrade for more"
              />
            )}
          </aside>
        </div>{/* two-column grid */}
      </div>
      {showPdf && <ResumePdfModal candidate={candidate} onClose={() => setShowPdf(false)} />}
    </div>
  );
}

// The stored original resume, shown in a lightweight PDF-style viewer. The
// preview has no binary file, so it renders the parsed resume as a clean
// document and exports the same content on download.
function ResumePdfModal({ candidate, onClose }) {
  const p = candidate.parsed;
  const realPdf = candidate.resumeUrl || null; // signed URL to the stored original
  const fileName = realPdf ? (candidate.fileName || "resume.pdf") : `${(p.name || "candidate").replace(/\s+/g, "_")}_Resume.pdf`;
  const download = () => {
    const out = [];
    out.push(p.name || "");
    out.push([p.email, p.phone, p.location].filter(Boolean).join("  |  "));
    if (p.summary) out.push("\nSUMMARY\n" + p.summary);
    if (p.skills?.length) out.push("\nSKILLS\n" + p.skills.join(", "));
    if (p.experience?.length) { out.push("\nEXPERIENCE"); p.experience.forEach((e) => out.push(`${e.title} · ${e.company}  (${e.duration})\n${e.summary || ""}`)); }
    if (p.education?.length) { out.push("\nEDUCATION"); p.education.forEach((e) => out.push(`${e.degree} · ${e.institution}  (${e.year})`)); }
    if (p.certifications?.length) out.push("\nCERTIFICATIONS\n" + p.certifications.join("\n"));
    if (p.languages?.length) out.push("\nLANGUAGES\n" + p.languages.join(", "));
    try {
      const blob = new Blob([out.join("\n")], { type: "text/plain" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a"); a.href = url; a.download = fileName.replace(/\.pdf$/i, ".txt");
      document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
    } catch { /* no-op */ }
  };
  useEffect(() => {
    const onKey = (e) => { if (e.key === "Escape") onClose(); };
    document.addEventListener("keydown", onKey);
    return () => document.removeEventListener("keydown", onKey);
  }, [onClose]);
  const contact = [p.email, p.phone, p.location].filter(Boolean);
  const Section = ({ title, children }) => (
    <div className="mt-5">
      <h3 className="text-[11px] font-semibold uppercase tracking-[0.12em] pb-1 mb-2.5" style={{ color: "#6b7280", borderBottom: "1px solid #e5e7eb" }}>{title}</h3>
      {children}
    </div>
  );
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-3 sm:p-6">
      <div className="absolute inset-0 bg-black/60" onClick={onClose} />
      <div className="relative w-full max-w-2xl max-h-[92vh] flex flex-col rounded-2xl overflow-hidden shadow-2xl" style={{ background: "#20233A" }}>
        {/* Viewer toolbar */}
        <div className="flex items-center gap-3 px-4 py-3 shrink-0" style={{ background: "#2A2E48" }}>
          <Icon name="doc" className="w-4 h-4 shrink-0" style={{ color: "rgba(255,255,255,0.8)" }} />
          <span className="text-sm font-medium truncate" style={{ color: "rgba(255,255,255,0.92)" }}>{fileName}</span>
          <div className="ml-auto flex items-center gap-1.5 shrink-0">
            {realPdf ? (
              <a href={realPdf} target="_blank" rel="noopener noreferrer" className="text-xs font-medium rounded-lg px-3 py-1.5 inline-flex items-center gap-1.5 transition-colors hover:bg-white/10" style={{ color: "rgba(255,255,255,0.9)" }}>
                <Icon name="download" className="w-3.5 h-3.5" /> Open in new tab
              </a>
            ) : (
              <button onClick={download} className="text-xs font-medium rounded-lg px-3 py-1.5 inline-flex items-center gap-1.5 transition-colors hover:bg-white/10" style={{ color: "rgba(255,255,255,0.9)" }}>
                <Icon name="download" className="w-3.5 h-3.5" /> Download
              </button>
            )}
            <button onClick={onClose} aria-label="Close" className="rounded-lg p-1.5 transition-colors hover:bg-white/10" style={{ color: "rgba(255,255,255,0.75)" }}>
              <Icon name="close" className="w-4 h-4" />
            </button>
          </div>
        </div>
        {/* Document page: the real uploaded PDF when we have it, else a clean
            reconstruction from the parsed fields. */}
        {realPdf ? (
          <iframe title={fileName} src={realPdf} className="flex-1 w-full" style={{ border: 0, background: "#3A3F5C", minHeight: "60vh" }} />
        ) : (
        <div className="flex-1 overflow-y-auto p-4 sm:p-6" style={{ background: "#3A3F5C" }}>
          <div className="mx-auto bg-white shadow-xl px-8 sm:px-10 py-9 max-w-[620px]" style={{ color: "#1f2937" }}>
            <h1 className="text-2xl font-bold tracking-tight" style={{ color: "#111827" }}>{p.name}</h1>
            {contact.length > 0 && <p className="text-xs mt-1.5" style={{ color: "#6b7280" }}>{contact.join("   ·   ")}</p>}
            {(p.linkedin_url || p.portfolio_url) && (
              <p className="text-xs mt-1" style={{ color: "#4f46e5" }}>{[p.linkedin_url && "LinkedIn", p.portfolio_url && "Portfolio"].filter(Boolean).join("   ·   ")}</p>
            )}
            {p.summary && <Section title="Summary"><p className="text-sm leading-relaxed" style={{ color: "#374151" }}>{p.summary}</p></Section>}
            {p.experience?.length > 0 && (
              <Section title="Experience">
                <div className="space-y-3.5">
                  {p.experience.map((e, i) => (
                    <div key={i}>
                      <div className="flex items-baseline justify-between gap-3">
                        <p className="text-sm font-semibold" style={{ color: "#111827" }}>{e.title}<span style={{ color: "#6b7280", fontWeight: 400 }}> · {e.company}</span></p>
                        <span className="text-xs shrink-0" style={{ color: "#9ca3af" }}>{e.duration}</span>
                      </div>
                      {e.summary && <p className="text-sm mt-0.5 leading-relaxed" style={{ color: "#4b5563" }}>{e.summary}</p>}
                    </div>
                  ))}
                </div>
              </Section>
            )}
            {p.education?.length > 0 && (
              <Section title="Education">
                <div className="space-y-1.5">
                  {p.education.map((e, i) => (
                    <div key={i} className="flex items-baseline justify-between gap-3">
                      <p className="text-sm" style={{ color: "#111827" }}>{e.degree} · {e.institution}</p>
                      <span className="text-xs shrink-0" style={{ color: "#9ca3af" }}>{e.year}</span>
                    </div>
                  ))}
                </div>
              </Section>
            )}
            {p.skills?.length > 0 && (
              <Section title="Skills"><p className="text-sm leading-relaxed" style={{ color: "#374151" }}>{p.skills.join(", ")}</p></Section>
            )}
            {p.certifications?.length > 0 && (
              <Section title="Certifications"><ul className="text-sm space-y-1 list-disc list-inside" style={{ color: "#374151" }}>{p.certifications.map((c) => <li key={c}>{c}</li>)}</ul></Section>
            )}
            {p.languages?.length > 0 && (
              <Section title="Languages"><p className="text-sm" style={{ color: "#374151" }}>{p.languages.join(", ")}</p></Section>
            )}
          </div>
        </div>
        )}
      </div>
    </div>
  );
}
const STAGE_ORDER = ["applied", "shortlisted", "interviewing", "offer", "hired", "rejected"];
const STAGE_LABELS = {
  applied: "Applied",
  shortlisted: "Shortlisted",
  interviewing: "Interviewing",
  offer: "Offer",
  hired: "Hired",
  rejected: "Rejected",
};
const STAGE_STYLES = {
  applied: "bg-neutral-100 text-neutral-600 border border-neutral-200",
  shortlisted: "bg-indigo-50 text-indigo-600 border border-indigo-200",
  interviewing: "bg-blue-50 text-blue-600 border border-blue-200",
  offer: "bg-violet-50 text-violet-600 border border-violet-200",
  hired: "bg-emerald-50 text-emerald-600 border border-emerald-200",
  rejected: "bg-rose-50 text-rose-600 border border-rose-200",
};

function StageBadge({ stage }) {
  return <span className={`text-xs px-2 py-0.5 rounded-full ${STAGE_STYLES[stage]}`}>{STAGE_LABELS[stage]}</span>;
}

// The standard warm-decline template, matching the agreed rejection copy.
function buildRejectionDraft(name, jobTitle) {
  const first = (name || "there").split(" ")[0];
  return {
    subject: `Update on your application — ${jobTitle}`,
    body: `Hi ${first},\n\nThank you for taking the time to apply for the ${jobTitle} role and for sharing your background with us.\n\nAfter careful consideration, we've decided not to move forward with your application at this time. This was a competitive process and the decision wasn't easy.\n\nWe genuinely appreciate your interest, and we'd welcome you to apply for future roles that match your experience. We wish you all the best in your search.\n\nWarm regards,\nThe Hiring Team`,
  };
}

function buildOfferDraft(name, jobTitle) {
  const first = (name || "there").split(" ")[0];
  return {
    subject: `You've been selected for the ${jobTitle} role`,
    body: `Hi ${first},\n\nCongratulations! Following your interview, we're delighted to let you know that you've been selected for the ${jobTitle} role.\n\nOur HR team will be in touch shortly with the full details — compensation, start date, and everything you'll need for the next steps.\n\nBefore we proceed, please let us know whether you'd like to accept this offer using the Accept or Decline buttons below. We can't move forward until we hear from you.\n\nWe're excited about the possibility of you joining the team and look forward to your response.\n\nWarm regards,\nThe Hiring Team`,
  };
}

function OfferModal({ candidateName, jobTitle, hasEmail = true, onClose, onSend }) {
  const initial = buildOfferDraft(candidateName, jobTitle);
  const [subject, setSubject] = useState(initial.subject);
  const [body, setBody] = useState(initial.body);
  const [sending, setSending] = useState(false);

  const inputClass = "w-full rounded-lg bg-neutral-100 border border-neutral-200 px-3 py-2 text-neutral-900 text-sm focus:outline-none focus:ring-2 focus:ring-neutral-400";

  const handleSend = () => {
    setSending(true);
    setTimeout(() => onSend(true), 900); // simulate send
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/50" onClick={onClose} />
      <div className="relative w-full max-w-lg rounded-2xl border border-neutral-200 bg-white shadow-xl p-6 max-h-[90vh] overflow-y-auto">
        <h2 className="text-lg font-bold font-display mb-1" style={{ color: "var(--ink)" }}>Send offer to {candidateName}</h2>
        <p className="text-sm text-neutral-500 mb-4">
          This emails the candidate to say they've been selected and asks them to <span className="font-medium">accept or decline</span>. They stay in the Offer stage until they respond.
        </p>

        {!hasEmail && (
          <div className="mb-4 rounded-lg border border-amber-200 bg-amber-50 px-3 py-2">
            <p className="text-xs text-amber-700">
              This candidate has no email on file, so the offer email can't be sent. You can still record the offer internally.
            </p>
          </div>
        )}

        <label className="block text-xs text-neutral-500 mb-1">Subject</label>
        <input value={subject} onChange={(e) => setSubject(e.target.value)} className={`${inputClass} mb-3`} disabled={!hasEmail} />

        <label className="block text-xs text-neutral-500 mb-1">Message</label>
        <textarea value={body} onChange={(e) => setBody(e.target.value)} rows={12} className={`${inputClass} mb-4 resize-y`} disabled={!hasEmail} />

        <div className="flex flex-wrap items-center justify-end gap-2">
          <button onClick={onClose} className="text-sm rounded-lg px-4 py-2 text-neutral-600 hover:bg-neutral-100 transition-colors">
            Cancel
          </button>
          {!hasEmail && (
            <button onClick={() => onSend(false)} className="text-sm rounded-lg px-4 py-2 border border-neutral-200 text-neutral-700 hover:bg-neutral-100 transition-colors">
              Record offer without email
            </button>
          )}
          {hasEmail && (
            <button onClick={handleSend} disabled={sending} className="text-sm rounded-lg px-4 py-2 brand-gradient hover:opacity-90 disabled:opacity-50 text-white font-medium transition-opacity">
              {sending ? "Sending…" : "Send offer"}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

function RejectionModal({ candidateName, jobTitle, hasEmail = true, onClose, onReject }) {
  const initial = buildRejectionDraft(candidateName, jobTitle);
  const [subject, setSubject] = useState(initial.subject);
  const [body, setBody] = useState(initial.body);
  const [sending, setSending] = useState(false);

  const inputClass = "w-full rounded-lg bg-neutral-100 border border-neutral-200 px-3 py-2 text-neutral-900 text-sm focus:outline-none focus:ring-2 focus:ring-neutral-400";

  const handleSend = () => {
    setSending(true);
    setTimeout(() => onReject(true), 900); // simulate send
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/50" onClick={onClose} />
      <div className="relative w-full max-w-lg rounded-2xl border border-neutral-200 bg-white shadow-xl p-6 max-h-[90vh] overflow-y-auto">
        <h2 className="text-lg font-bold font-display mb-1" style={{ color: "var(--ink)" }}>Reject {candidateName}</h2>
        <p className="text-sm text-neutral-500 mb-4">
          Review the email before it's sent. You can edit it, send it, or reject without emailing.
        </p>

        {!hasEmail && (
          <div className="mb-4 rounded-lg border border-amber-200 bg-amber-50 px-3 py-2">
            <p className="text-xs text-amber-700">
              This candidate has no email on file, so an email can't be sent. You can still reject internally.
            </p>
          </div>
        )}

        <label className="block text-xs text-neutral-500 mb-1">Subject</label>
        <input value={subject} onChange={(e) => setSubject(e.target.value)} className={`${inputClass} mb-3`} disabled={!hasEmail} />

        <label className="block text-xs text-neutral-500 mb-1">Message</label>
        <textarea value={body} onChange={(e) => setBody(e.target.value)} rows={12} className={`${inputClass} mb-4 resize-y`} disabled={!hasEmail} />

        <div className="flex flex-wrap items-center justify-end gap-2">
          <button onClick={onClose} className="text-sm rounded-lg px-4 py-2 text-neutral-600 hover:bg-neutral-100 transition-colors">
            Cancel
          </button>
          <button onClick={() => onReject(false)} className="text-sm rounded-lg px-4 py-2 border border-neutral-200 text-neutral-700 hover:bg-neutral-100 transition-colors">
            Reject without email
          </button>
          {hasEmail && (
            <button onClick={handleSend} disabled={sending} className="text-sm rounded-lg px-4 py-2 bg-rose-600 hover:bg-rose-500 disabled:opacity-50 text-white font-medium transition-colors">
              {sending ? "Sending…" : "Send & reject"}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

function StageControl({ stage, rejectionEmailSent, candidateName, jobTitle, hasEmail, onStageChange }) {
  const [open, setOpen] = useState(false);
  const [showReject, setShowReject] = useState(false);

  // Offer & Hired are NOT manually selectable here — they only happen through
  // the offer → accept flow on the candidate's profile, so HR can't skip the
  // funnel or fake a hire the candidate never confirmed. Reject is always
  // available (except on someone already hired). A hired candidate is final.
  const isPickable = (s) => {
    if (s === stage) return false;
    if (s === "offer" || s === "hired") return false;   // via profile offer flow only
    if (stage === "hired") return false;                // hired is final
    if (s === "rejected") return true;                  // can reject anytime otherwise
    return true;                                        // applied / shortlisted / interviewing
  };

  const choose = (next) => {
    if (!isPickable(next)) return;
    setOpen(false);
    if (next === "rejected") {
      setShowReject(true);
      return;
    }
    onStageChange(next);
  };

  return (
    <div className="relative">
      <button
        onClick={() => setOpen((o) => !o)}
        className={`flex items-center gap-1.5 rounded-full px-2.5 py-1 border transition-colors hover:brightness-95 ${STAGE_STYLES[stage]}`}
      >
        <span className="text-xs font-medium">{STAGE_LABELS[stage]}</span>
        <Icon name="chevronDown" className={`w-3.5 h-3.5 transition-transform ${open ? "rotate-180" : ""}`} />
      </button>

      {stage === "rejected" && (
        <p className="text-[11px] text-neutral-400 mt-1 text-right">
          {rejectionEmailSent ? "Email sent" : "No email sent"}
        </p>
      )}

      {open && (
        <>
          <div className="fixed inset-0 z-30" onClick={() => setOpen(false)} />
          <div className="absolute z-40 right-0 mt-1 w-52 rounded-xl border border-neutral-200 bg-white shadow-lg py-1">
            <p className="px-3 pt-1 pb-1.5 text-[10px] uppercase tracking-wide text-neutral-400">Move to stage</p>
            {STAGE_ORDER.map((s) => {
              const current = s === stage;
              const gated = s === "offer" || s === "hired";
              const disabled = !current && !isPickable(s);
              return (
                <button
                  key={s}
                  onClick={() => choose(s)}
                  disabled={disabled}
                  title={gated ? "Set from the candidate's profile via the offer flow" : undefined}
                  className={`w-full flex items-center justify-between px-3 py-1.5 text-sm transition-colors ${
                    current
                      ? "text-neutral-900 bg-neutral-100 font-medium"
                      : disabled
                        ? "text-neutral-300 cursor-not-allowed"
                        : s === "rejected"
                          ? "text-rose-600 hover:bg-rose-50"
                          : "text-neutral-700 hover:bg-neutral-50"
                  }`}
                >
                  <span className="flex items-center gap-1.5">
                    {gated && <Icon name="lock" className="w-3 h-3" />}
                    {STAGE_LABELS[s]}{s === "rejected" ? "…" : ""}
                  </span>
                  {current && <span className="text-neutral-400">✓</span>}
                </button>
              );
            })}
            <p className="px-3 pt-1.5 pb-1 text-[10px] text-neutral-400 border-t border-neutral-100 mt-1">
              Offers &amp; hires happen on the candidate's profile, after the interview.
            </p>
          </div>
        </>
      )}

      {showReject && (
        <RejectionModal
          candidateName={candidateName}
          jobTitle={jobTitle}
          hasEmail={hasEmail}
          onClose={() => setShowReject(false)}
          onReject={(emailSent) => { setShowReject(false); onStageChange("rejected", emailSent); }}
        />
      )}
    </div>
  );
}

function ApplicantsScreen({ navigate, jobs, activeJobId, onViewCandidate, stageOverrides = {}, onStageChange, plan = "free", matchRunsUsed = 0, setMatchRunsUsed, bookings = {}, hiredIds = new Set() }) {
  // Real activity signal per applicant — an event worth noticing, not presence.
  const activityFor = (a) => {
    if (bookings?.[a.candidateId]?.status === "scheduled") return { label: "Interview scheduled", color: "#4F46E5", bg: "#EEF0FF" };
    const t = (a.appliedAt || "").toLowerCase();
    if (t.includes("today") || /^\s*1\s*d/.test(t)) return { label: "New", color: "#166534", bg: "#DCFCE7" };
    return null;
  };
  const limits = planLimits(plan);
  const aiMatchLimit = limits.aiMatches;
  const runLimit = limits.aiRunsPerMonth;
  const runsLeft = Math.max(0, runLimit - matchRunsUsed);
  const outOfRuns = limits.aiRunsPerMonth !== Infinity && runsLeft <= 0;
  const job = jobs.find((j) => j.id === activeJobId);
  const jobTitle = job?.title ?? "the role";
  // Shared source of truth (also drives the count on the Jobs card).
  const baseApplicants = APPLICANTS_BY_JOB[activeJobId] || [];
  const [localRejectEmail, setLocalRejectEmail] = useState({}); // candidateId -> emailSent

  const applicants = baseApplicants.map((a) => ({
    ...a,
    stage: stageOverrides[a.candidateId] ?? a.baseStage,
    rejectionEmailSent: localRejectEmail[a.candidateId] ?? a.rejectionEmailSent,
  }));

  const [stageFilter, setStageFilter] = useState("all");
  const [filterOpen, setFilterOpen] = useState(false);
  // Inline AI matching — ranks these applicants against the job.
  const [matching, setMatching] = useState(false);
  const [matchResults, setMatchResults] = useState(null); // null until run: { [candidateId]: {score, rationale} }

  const runMatching = () => {
    if (outOfRuns) { navigate("billing"); return; }
    setMatching(true);
    setTimeout(() => {
      const list = MOCK_MATCHES[activeJobId] || [];
      const map = {};
      list.forEach((m) => { map[m.candidateId] = { score: m.score, rationale: m.rationale }; });
      setMatchResults(map);
      setMatching(false);
      if (limits.aiRunsPerMonth !== Infinity && setMatchRunsUsed) setMatchRunsUsed((n) => n + 1);
    }, 1400);
  };

  const setStage = (candidateId, stage, emailSent) => {
    if (stage === "rejected") {
      setLocalRejectEmail((prev) => ({ ...prev, [candidateId]: Boolean(emailSent) }));
    }
    if (onStageChange) onStageChange(candidateId, stage);
  };

  // Only applicants whose candidate exists and is parsed are shown
  const visible = applicants.filter((a) => {
    const c = MOCK_CANDIDATES.find((cand) => cand.id === a.candidateId);
    return c && c.parsed;
  });

  const countFor = (key) => (key === "all" ? visible.length : visible.filter((a) => a.stage === key).length);
  let filtered = stageFilter === "all" ? visible : visible.filter((a) => a.stage === stageFilter);
  // Recency rank: lower = newer ("today" newest, "6d ago" older).
  const recencyRank = (a) => {
    const t = (a.appliedAt || "").toLowerCase();
    if (t.includes("today")) return 0;
    const m = t.match(/(\d+)\s*d/);
    return m ? Number(m[1]) : 999;
  };
  if (matchResults) {
    // Once matched, rank by score (highest first); unscored fall to the bottom.
    filtered = [...filtered].sort((a, b) => (matchResults[b.candidateId]?.score ?? -1) - (matchResults[a.candidateId]?.score ?? -1));
  } else {
    // Newest applicants first for everyone (Free can see its whole pipeline).
    filtered = [...filtered].sort((a, b) => recencyRank(a) - recencyRank(b));
  }

  const filterOptions = ["all", ...STAGE_ORDER];
  const filterLabel = (key) => (key === "all" ? "All stages" : STAGE_LABELS[key]);

  // Free can view every applicant now; only AI-match depth is gated.
  const shownApps = filtered;

  return (
    <div className="px-4 sm:px-6 py-8 sm:py-10">
      <div className="max-w-2xl mx-auto">
        <BackLink onClick={() => navigate("jobs")}>← Jobs</BackLink>
        <h1 className="text-xl sm:text-2xl font-bold font-display mt-2 mb-1" style={{ color: "var(--ink)" }}>
          Applicants{job ? ` — ${job.title}` : ""}
        </h1>
        <p className="text-sm text-neutral-600 mb-4">
          Candidates who applied directly through the public job link. Tap the stage pill to move them through the pipeline or reject with a reviewed email.
        </p>

        <div className="rounded-2xl border border-[color:var(--line)] bg-white p-4 mb-5 flex items-center justify-between gap-3">
          <div className="min-w-0">
            <p className="text-sm font-semibold font-display flex items-center gap-1.5" style={{ color: "var(--ink)" }}>
              Rank these applicants with AI
              <InfoHint dir="down" hint="AI scores each applicant against this role from 0 to 100 percent, and on paid plans explains the reasoning behind each score." />
            </p>
            <p className="text-xs mt-0.5" style={{ color: "var(--ink-3)" }}>
              {visible.length === 0
                ? "No applicants yet — matching becomes available once someone applies."
                : matchResults
                  ? "Ranked by fit against this role. Best matches shown first."
                  : "Score every candidate against this role and see who fits best."}
            </p>
          </div>
          <button
            onClick={runMatching}
            disabled={matching || visible.length === 0}
            className="shrink-0 rounded-xl brand-gradient hover:opacity-90 disabled:opacity-40 disabled:cursor-not-allowed text-white text-sm font-medium px-4 py-2 flex items-center gap-2 transition-opacity"
          >
            <Icon name={outOfRuns ? "lock" : "target"} className="w-4 h-4" />
            {matching
              ? "Matching…"
              : outOfRuns
                ? "Upgrade for more runs"
                : matchResults
                  ? "Re-run matching"
                  : "Run AI Matching"}
          </button>
        </div>
        {limits.aiRunsPerMonth !== Infinity && (
          <p className="text-xs mb-4" style={{ color: "var(--ink-3)" }}>
            {outOfRuns
              ? `You've used all ${limits.aiRunsPerMonth} match runs this month. Upgrade for unlimited runs, the full ranking, and the AI's reasoning.`
              : `Your plan includes ${limits.aiRunsPerMonth} match runs a month (${runsLeft} left) — you'll see the top ${limits.aiMatches} fits with scores. Upgrade for unlimited runs and the reasoning.`}
          </p>
        )}

        {/* Stage filter */}
        <div className="flex items-center justify-between gap-3 mb-4">
          <p className="text-sm text-neutral-500">
            {filtered.length} {filtered.length === 1 ? "candidate" : "candidates"}
            {stageFilter !== "all" ? ` · ${STAGE_LABELS[stageFilter]}` : ""}
          </p>
          <div className="relative">
            <button
              onClick={() => setFilterOpen((o) => !o)}
              className="flex items-center gap-2 rounded-xl bg-white border border-neutral-200 px-3 py-2 text-sm text-neutral-700 hover:border-neutral-300 transition-colors"
            >
              <span className="text-neutral-400">Filter:</span>
              <span className="font-medium">{filterLabel(stageFilter)}</span>
              <Icon name="chevronDown" className={`w-4 h-4 text-neutral-400 transition-transform ${filterOpen ? "rotate-180" : ""}`} />
            </button>
            {filterOpen && (
              <>
                <div className="fixed inset-0 z-30" onClick={() => setFilterOpen(false)} />
                <div className="absolute z-40 right-0 mt-1 w-48 rounded-xl border border-neutral-200 bg-white shadow-lg py-1">
                  {filterOptions.map((key) => (
                    <button
                      key={key}
                      onClick={() => { setStageFilter(key); setFilterOpen(false); }}
                      className={`w-full flex items-center justify-between px-3 py-1.5 text-sm transition-colors ${
                        stageFilter === key ? "text-neutral-900 bg-neutral-100 font-medium" : "text-neutral-700 hover:bg-neutral-50"
                      }`}
                    >
                      <span>{filterLabel(key)}</span>
                      <span className="text-xs text-neutral-400">{countFor(key)}</span>
                    </button>
                  ))}
                </div>
              </>
            )}
          </div>
        </div>

        {filtered.length === 0 ? (
          <p className="text-sm text-neutral-500">No candidates in this stage.</p>
        ) : (
          <div className="space-y-2">
            {shownApps.map((a, idx) => {
              const c = MOCK_CANDIDATES.find((cand) => cand.id === a.candidateId);
              if (!c || !c.parsed) return null;
              const role = c.parsed.experience?.[0]?.title ?? "Applicant";
              const match = matchResults?.[a.candidateId];
              const scoreVisible = idx < aiMatchLimit;
              const isTop = !!matchResults && idx === 0 && !!match && scoreVisible;
              return (
                <div
                  key={a.candidateId}
                  className="rounded-2xl bg-white act-shadow px-5 py-4 border border-[color:var(--line)]"
                >
                  <div className="flex items-center gap-3">
                    <button onClick={() => onViewCandidate(a.candidateId, activeJobId, a.stage)} className="shrink-0">
                      {match && scoreVisible
                        ? <ScoreRingLight value={Math.round(match.score * 100)} size={52} />
                        : <CandidateAvatar name={c.parsed.name} hasPhoto={c.hasPhoto} src={c.avatarUrl} />}
                    </button>
                    <div className="min-w-0 flex-1">
                      <div className="flex items-center gap-2">
                        <button onClick={() => onViewCandidate(a.candidateId, activeJobId, a.stage)} className="block text-left min-w-0 flex-1">
                          <p className="text-neutral-900 font-medium truncate hover:underline">{c.parsed.name}</p>
                        </button>
                        {isTop && <span className="shrink-0 text-[10px] px-2 py-0.5 rounded-full brand-gradient text-white font-semibold">Top match</span>}
                        {match && !scoreVisible && (
                          <button onClick={() => navigate("billing")} className="shrink-0" aria-label="Upgrade to see match score">
                            <span className="inline-flex items-center gap-1 text-[10px] font-semibold px-1.5 py-0.5 rounded-full" style={{ background: "var(--brand-soft)", color: "var(--brand)" }}>
                              <Icon name="lock" className="w-3 h-3" /> score
                            </span>
                          </button>
                        )}
                      </div>
                      <div className="flex items-center gap-2 mt-0.5 min-w-0">
                        {(() => {
                          const act = activityFor(a);
                          return act ? (
                            <span className="shrink-0 inline-flex items-center gap-1 text-[10px] font-medium px-1.5 py-0.5 rounded-full" style={{ background: act.bg, color: act.color }} title={act.label}>
                              <span className="w-1.5 h-1.5 rounded-full" style={{ background: act.color }} /> {act.label}
                            </span>
                          ) : null;
                        })()}
                        <p className="text-xs text-neutral-500 truncate">{role} · applied {a.appliedAt}</p>
                      </div>
                    </div>
                  </div>

                  {match && scoreVisible && (
                    limits.showRationale ? (
                      <p className="text-xs mt-2.5" style={{ color: "var(--ink-2)" }}>{match.rationale}</p>
                    ) : (
                      <button onClick={() => navigate("billing")} className="text-xs mt-2.5 inline-flex items-center gap-1 hover:opacity-80" style={{ color: "var(--brand)" }}>
                        <Icon name="lock" className="w-3 h-3" /> See why — upgrade for the AI's reasoning
                      </button>
                    )
                  )}

                  <div className="flex justify-end mt-3">
                    {hiredIds.has(a.candidateId) ? (
                      <span className="inline-flex items-center gap-1 text-xs font-semibold px-2.5 py-1.5 rounded-full" style={{ background: "#DCFCE7", color: "#166534" }}>
                        <Icon name="check" className="w-3.5 h-3.5" /> Hired
                      </span>
                    ) : (
                      <StageControl
                        stage={a.stage}
                        rejectionEmailSent={a.rejectionEmailSent}
                        candidateName={c.parsed.name}
                        jobTitle={jobTitle}
                        hasEmail={Boolean(c.parsed.email)}
                        onStageChange={(stage, emailSent) => setStage(a.candidateId, stage, emailSent)}
                      />
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

function CandidateListScreen({ navigate, candidates, filter, onViewCandidate, plan = "free", hiredIds = new Set(), hiredDates = {} }) {
  const [query, setQuery] = useState("");
  const [hiredMonth, setHiredMonth] = useState("all"); // "all" | "YYYY-MM"
  const limit = planLimits(plan).visibleCandidates;

  const isHiredView = !!(filter && filter.hired);
  let title = "Candidates";
  // Only parsed candidates are shown — unparsed ones have no name/role to display yet.
  let base = candidates.filter((c) => c.status === "parsed");

  if (filter) {
    if (filter.hired) {
      title = "Hired";
      base = candidates.filter((c) => hiredIds.has(c.id));
    } else if (filter.status === "parsed") {
      title = "Parsed candidates";
    } else if (filter.status === "pending" || filter.status === "failed") {
      // These statuses aren't parsed, so there's nothing to list here.
      title = filter.status === "pending" ? "Parsing pending" : "Parse failed";
      base = [];
    } else if (filter.source === "public_application") {
      title = "Applications";
      base = base.filter((c) => ["c1", "c3"].includes(c.id));
    } else if (filter.interview) {
      title = "Candidates in interview";
      base = base.filter((c) => c.id === "c1");
    }
  }

  // Month options for the Hired view, derived from when each hire happened.
  const monthLabel = (ym) => {
    const [y, m] = ym.split("-");
    return new Date(Number(y), Number(m) - 1, 1).toLocaleDateString(undefined, { month: "long", year: "numeric" });
  };
  const hiredMonths = isHiredView
    ? Array.from(new Set(base.map((c) => (hiredDates[c.id] || "").slice(0, 7)).filter(Boolean))).sort().reverse()
    : [];
  if (isHiredView && hiredMonth !== "all") {
    base = base.filter((c) => (hiredDates[c.id] || "").slice(0, 7) === hiredMonth);
  }

  const q = query.trim().toLowerCase();
  const filtered = q ? base.filter((c) => (c.parsed?.name ?? "").toLowerCase().includes(q)) : base;
  const visible = filtered.slice(0, limit);
  const locked = filtered.slice(limit);

  const currentRole = (c) => {
    const job = c.parsed?.experience?.[0];
    if (!job) return null;
    return job.company ? `${job.title} · ${job.company}` : job.title;
  };

  return (
    <div className="px-4 sm:px-6 py-8 sm:py-10">
      <div className="max-w-2xl mx-auto">
        <BackLink onClick={() => navigate("dashboard")}>← Dashboard</BackLink>
        <div className="flex items-start justify-between gap-3 mt-2 mb-1">
          <h1 className="text-xl sm:text-2xl font-bold font-display" style={{ color: "var(--ink)" }}>{title}</h1>
          {isHiredView && hiredMonths.length > 0 && (
            <select
              value={hiredMonth}
              onChange={(e) => setHiredMonth(e.target.value)}
              className="shrink-0 rounded-xl bg-white border border-neutral-200 text-sm text-neutral-800 px-3 py-2 focus:outline-none focus:ring-2 focus:ring-neutral-400"
            >
              <option value="all">All months</option>
              {hiredMonths.map((ym) => (
                <option key={ym} value={ym}>{monthLabel(ym)}</option>
              ))}
            </select>
          )}
        </div>
        <p className="text-sm text-neutral-600 mb-4">
          {filtered.length} {isHiredView ? "hire" : "candidate"}{filtered.length === 1 ? "" : "s"}{isHiredView && hiredMonth !== "all" ? ` in ${monthLabel(hiredMonth)}` : ""}
        </p>

        {/* Search by name */}
        <div className="relative mb-5">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-400">
            <Icon name="search" className="w-4 h-4" />
          </span>
          <input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search candidates by name…"
            className="w-full rounded-xl bg-white border border-neutral-200 pl-9 pr-3 py-2.5 text-sm text-neutral-900 focus:outline-none focus:ring-2 focus:ring-neutral-400"
          />
        </div>

        {filtered.length === 0 ? (
          <p className="text-sm text-neutral-500">
            {q ? `No candidates matching “${query}”.` : "No parsed candidates to show."}
          </p>
        ) : (
          <div className="space-y-2">
            {visible.map((c) => (
              <button
                key={c.id}
                onClick={() => onViewCandidate(c.id)}
                className="flex items-center gap-4 w-full text-left rounded-2xl bg-white act-shadow card-hover px-5 py-4 border border-[color:var(--line)]"
              >
                <CandidateAvatar name={c.parsed?.name} hasPhoto={c.hasPhoto} src={c.avatarUrl} size={48} />
                <div className="min-w-0 flex-1">
                  <div className="flex items-center gap-2">
                    <p className="text-lg font-semibold text-neutral-900 truncate">
                      {c.parsed?.name ?? c.fileName}
                    </p>
                    {hiredIds.has(c.id) && (
                      <span className="inline-flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-full font-semibold shrink-0" style={{ background: "#DCFCE7", color: "#166534" }}>
                        <Icon name="check" className="w-3 h-3" /> Hired
                      </span>
                    )}
                  </div>
                  {currentRole(c) && (
                    <p className="text-sm text-neutral-500 truncate">
                      {hiredIds.has(c.id)
                        ? (hiredDates[c.id] ? `Hired ${new Date(hiredDates[c.id]).toLocaleDateString(undefined, { day: "numeric", month: "short", year: "numeric" })}` : "Hired — no longer available")
                        : currentRole(c)}
                    </p>
                  )}
                </div>
                <Icon name="chevronRight" className="w-5 h-5 text-neutral-300 shrink-0" />
              </button>
            ))}

          </div>
        )}
      </div>
    </div>
  );
}

// ---------- Root ----------

// Each screen gets a dedicated URL. Detail screens that depend on transient
// state (a picked candidate/job) share or fall back to a safe list URL, so a
// cold refresh never lands on a broken screen.
const SCREEN_TO_PATH = {
  landing: "/",
  login: "/login",
  forgotPassword: "/forgot-password",
  signup: "/signup",
  dashboard: "/dashboard",
  candidates: "/candidates",
  candidateProfile: "/candidates",
  applicants: "/applicants",
  interviews: "/interviews",
  interviewers: "/interviewers",
  jobs: "/jobs",
  search: "/search",
  upload: "/upload",
  emailTemplates: "/email-templates",
  billing: "/billing",
  profile: "/profile",
  settings: "/settings",
  schedulePicker: "/schedule",
  apply: "/apply",
  product: "/product",
  solutions: "/solutions",
  blog: "/blog",
  glossary: "/resources/glossary",
  compare: "/compare",
};
const PATH_TO_SCREEN = {
  "/": "landing",
  "/product": "product",
  "/solutions": "solutions",
  "/blog": "blog",
  "/resources/glossary": "glossary",
  "/compare": "compare",
  "/login": "login",
  "/forgot-password": "forgotPassword",
  "/signup": "signup",
  "/dashboard": "dashboard",
  "/candidates": "candidates",
  "/applicants": "applicants",
  "/interviews": "interviews",
  "/interviewers": "interviewers",
  "/jobs": "jobs",
  "/search": "search",
  "/upload": "upload",
  "/email-templates": "emailTemplates",
  "/billing": "billing",
  "/profile": "profile",
  "/settings": "settings",
  "/schedule": "dashboard", // needs a picked booking -> fall back on refresh
  "/apply": "dashboard",     // needs a picked job -> fall back on refresh
};
const AUTH_SCREENS = new Set(["landing", "login", "signup", "forgotPassword"]);

// Each candidate profile has its own deep-linkable URL, /candidates/<id>.
function candidateIdFromPath(pathname) {
  const m = (pathname || "").match(/^\/candidates\/([^/]+)$/);
  return m ? decodeURIComponent(m[1]) : null;
}
// Product marketing pages: /product (overview) and /product/<slug>.
function productSlugFromPath(pathname) {
  if (pathname === "/product") return "";
  const m = (pathname || "").match(/^\/product\/([^/]+)$/);
  return m ? m[1] : null; // null → not a product path
}
// Solutions pages: /solutions (hub) and /solutions/<slug>, where <slug> may be
// nested (e.g. industries/technology). The whole sub-path is the slug.
function solutionSlugFromPath(pathname) {
  if (pathname === "/solutions") return "";
  const m = (pathname || "").match(/^\/solutions\/(.+)$/);
  return m ? m[1] : null; // null → not a solutions path
}
// Blog: /blog (index), /blog/category/<slug>, /blog/<slug> (post).
function blogInfoFromPath(pathname) {
  if (pathname === "/blog") return { kind: "index", slug: "" };
  let m = (pathname || "").match(/^\/blog\/category\/([^/]+)$/);
  if (m) return { kind: "category", slug: m[1] };
  m = (pathname || "").match(/^\/blog\/([^/]+)$/);
  if (m) return { kind: "post", slug: m[1] };
  return null;
}
// Glossary: /resources/glossary (index) and /resources/glossary/<slug> (term).
function glossaryInfoFromPath(pathname) {
  if (pathname === "/resources/glossary") return { kind: "index", slug: "" };
  const m = (pathname || "").match(/^\/resources\/glossary\/([^/]+)$/);
  return m ? { kind: "term", slug: m[1] } : null;
}
// Compare: /compare (hub) and /compare/<slug> (a competitor or "alternatives").
function compareInfoFromPath(pathname) {
  if (pathname === "/compare") return { kind: "index", slug: "" };
  const m = (pathname || "").match(/^\/compare\/([^/]+)$/);
  return m ? { kind: "page", slug: m[1] } : null;
}
// Applicants: /applicants (first job) and /applicants/<jobId> so a specific
// job's applicant list is refreshable and shareable.
function applicantsJobFromPath(pathname) {
  const m = (pathname || "").match(/^\/applicants\/([^/]+)$/);
  return m ? decodeURIComponent(m[1]) : null;
}
function screenFromPath(pathname) {
  if (candidateIdFromPath(pathname)) return "candidateProfile";
  if (applicantsJobFromPath(pathname)) return "applicants";
  if (productSlugFromPath(pathname) != null) return "product";
  if (solutionSlugFromPath(pathname) != null) return "solutions";
  if (blogInfoFromPath(pathname)) return "blog";
  if (glossaryInfoFromPath(pathname)) return "glossary";
  if (compareInfoFromPath(pathname)) return "compare";
  return PATH_TO_SCREEN[pathname] || "landing";
}

